import React, { useRef, useState } from 'react';
import Card from './Card';
import Button from './Button';

interface DataUploaderProps {
    onFileSelected: (file: File) => void;
    onLoadDemo: () => void;
}

const UploadIcon: React.FC = () => (
    <svg xmlns="http://www.w3.org/2000/svg" width="20" height="20" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round" className="text-brand-primary">
        <path d="M21 15v4a2 2 0 0 1-2 2H5a2 2 0 0 1-2-2v-4"></path>
        <polyline points="17 8 12 3 7 8"></polyline>
        <line x1="12" x2="12" y1="3" y2="15"></line>
    </svg>
);

const FileIcon: React.FC = () => (
     <svg xmlns="http://www.w3.org/2000/svg" width="16" height="16" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round" className="text-gray-500">
        <path d="M14.5 2H6a2 2 0 0 0-2 2v16a2 2 0 0 0 2 2h12a2 2 0 0 0 2-2V7.5L14.5 2z"></path>
        <polyline points="14 2 14 8 20 8"></polyline>
        <line x1="16" y1="13" x2="8" y2="13"></line><line x1="16" y1="17" x2="8" y2="17"></line><line x1="10" y1="9" x2="8" y2="9"></line>
    </svg>
);


const DataUploader: React.FC<DataUploaderProps> = ({ onFileSelected, onLoadDemo }) => {
    const fileInputRef = useRef<HTMLInputElement>(null);
    const [fileName, setFileName] = useState('');

    const handleFileChange = (event: React.ChangeEvent<HTMLInputElement>) => {
        const file = event.target.files?.[0];
        if (file) {
            setFileName(file.name);
            onFileSelected(file);
        }
    };

    const handleLoadDemo = () => {
        setFileName('demo_data.csv');
        onLoadDemo();
    };

    return (
        <Card>
            <h2 className="text-lg font-semibold mb-3 flex items-center gap-2">
                <UploadIcon />
                1. Cargar Datos
            </h2>
            <p className="text-sm text-gray-500 mb-4">CSV: 1ª fila: longitudes de onda + propiedad. 1ª col: IDs. Última col: valor de propiedad.</p>
            <div className="space-y-2">
                <input
                    type="file"
                    ref={fileInputRef}
                    accept=".csv"
                    onChange={handleFileChange}
                    className="block w-full text-sm text-gray-500 file:mr-4 file:py-2 file:px-4 file:rounded-md file:border-0 file:text-sm file:font-semibold file:bg-brand-secondary file:text-white hover:file:bg-brand-primary cursor-pointer"
                />
                <p className="text-xs text-gray-500 h-4 truncate">{fileName}</p>
                <Button variant="secondary" onClick={handleLoadDemo} className="w-full">
                    <FileIcon />
                    Cargar Datos de Demostración
                </Button>
            </div>
        </Card>
    );
};

export default DataUploader;

import React from 'react';
import Card from './Card';
import { Sample } from '../types';

interface SampleManagerProps {
    samples: Sample[];
    onToggle: (index: number) => void;
    onToggleAll: (active: boolean) => void;
}

const ManagerIcon: React.FC = () => (
    <svg xmlns="http://www.w3.org/2000/svg" width="20" height="20" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round" className="text-brand-primary">
        <path d="M21 15v4a2 2 0 0 1-2 2H5a2 2 0 0 1-2-2v-4"></path>
        <polyline points="7 10 12 15 17 10"></polyline>
        <line x1="12" x2="12" y1="15" y2="3"></line>
    </svg>
);

const SampleManager: React.FC<SampleManagerProps> = ({ samples, onToggle, onToggleAll }) => {
    const activeSampleCount = samples.filter(s => s.active).length;

    return (
        <Card className="flex-grow flex flex-col min-h-0">
            <h2 className="text-lg font-semibold mb-3 flex items-center gap-2">
                <ManagerIcon />
                2. Gestionar Muestras
            </h2>
            <div className="flex items-center justify-between mb-2">
                <p className="text-sm text-gray-500">
                    <span className="font-bold">{activeSampleCount}</span> de <span className="font-bold">{samples.length}</span> activas
                </p>
                <div>
                    <button onClick={() => onToggleAll(true)} className="text-xs text-brand-primary hover:underline">Todas</button> |
                    <button onClick={() => onToggleAll(false)} className="text-xs text-brand-primary hover:underline">Ninguna</button>
                </div>
            </div>
            <div className="overflow-y-auto pr-2 flex-grow">
                {samples.length === 0 ? (
                    <p className="text-center text-gray-400 pt-8">Cargue un archivo para ver las muestras.</p>
                ) : (
                    samples.map((sample, index) => (
                        <div key={sample.id} className="flex items-center justify-between p-2 rounded-md hover:bg-gray-100">
                            <div className="flex items-center gap-3">
                                <input
                                    type="checkbox"
                                    id={`sample-${index}`}
                                    checked={sample.active}
                                    onChange={() => onToggle(index)}
                                    className="form-checkbox h-4 w-4 rounded text-brand-primary border-gray-300 focus:ring-brand-primary"
                                />
                                <label htmlFor={`sample-${index}`} className="text-sm cursor-pointer truncate max-w-[150px]">{sample.id}</label>
                            </div>
                            <div className="w-4 h-4 rounded-full flex-shrink-0" style={{ backgroundColor: sample.color }}></div>
                        </div>
                    ))
                )}
            </div>
        </Card>
    );
};

export default SampleManager;

import React, { useRef, useEffect, useState } from 'react';
import Card from './Card';
import Button from './Button';
import { Sample } from '../types';

// Declare Chart and its zoom plugin from CDN for TypeScript
declare var Chart: any;
declare var ChartDataLabels: any;
declare var zoomPlugin: any;


interface SpectraViewerProps {
    wavelengths: number[];
    samples: (Sample | {id: string | number, values: number[], color: string})[];
    isProcessed: boolean;
    onReset: () => void;
}

const ChartIcon: React.FC = () => (
    <svg xmlns="http://www.w3.org/2000/svg" width="20" height="20" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round" className="text-brand-primary">
        <path d="M3 3v18h18"></path><path d="m19 9-5 5-4-4-3 3"></path>
    </svg>
);


const SpectraViewer: React.FC<SpectraViewerProps> = ({ wavelengths, samples, isProcessed, onReset }) => {
    const chartRef = useRef<HTMLCanvasElement>(null);
    const chartInstanceRef = useRef<any>(null);

    const [startWl, setStartWl] = useState('');
    const [endWl, setEndWl] = useState('');

    useEffect(() => {
        if (wavelengths.length > 0) {
            setStartWl(wavelengths[0].toString());
            setEndWl(wavelengths[wavelengths.length - 1].toString());
        } else {
            setStartWl('');
            setEndWl('');
        }
    }, [wavelengths]);

    useEffect(() => {
        if (chartRef.current) {
            Chart.register(zoomPlugin);
            const ctx = chartRef.current.getContext('2d');
            if (ctx) {
                chartInstanceRef.current = new Chart(ctx, {
                    type: 'line',
                    data: { labels: [], datasets: [] },
                    options: {
                        maintainAspectRatio: false,
                        responsive: true,
                        plugins: {
                            legend: { display: false },
                            tooltip: { callbacks: { title: (context: any) => context[0].dataset.label } },
                            zoom: {
                                pan: { enabled: true, mode: 'x' },
                                zoom: { wheel: { enabled: true }, pinch: { enabled: true }, mode: 'x' }
                            }
                        },
                        scales: {
                            x: {
                                type: 'linear',
                                title: { display: true, text: 'Longitud de onda (nm)' },
                                ticks: { color: '#6B7280' },
                                grid: { color: '#E5E7EB' }
                            },
                            y: {
                                title: { display: true, text: isProcessed ? 'Intensidad (Pre-procesado)' : 'Absorbancia' },
                                ticks: { color: '#6B7280' },
                                grid: { color: '#E5E7EB' }
                            }
                        }
                    }
                });
            }
        }
        return () => {
            chartInstanceRef.current?.destroy();
            // Chart.unregister(zoomPlugin) is not available in v4, destroying instance is enough
        };
    // eslint-disable-next-line react-hooks/exhaustive-deps
    }, [isProcessed]); // Re-create chart if isProcessed changes to update Y-axis title

    useEffect(() => {
        const chart = chartInstanceRef.current;
        if (chart) {
            chart.data.labels = wavelengths;
            chart.data.datasets = samples.map(sample => ({
                label: sample.id,
                data: sample.values,
                borderColor: sample.color,
                borderWidth: 1.5,
                pointRadius: 0,
                tension: 0.1
            }));

            if (isProcessed) {
                const allValues = samples.flatMap(s => s.values).filter(v => isFinite(v as number));
                if (allValues.length > 0) {
                    const min = Math.min(...allValues as number[]);
                    const max = Math.max(...allValues as number[]);
                    const padding = (max - min) * 0.1;
                    chart.options.scales.y.min = min - padding;
                    chart.options.scales.y.max = max + padding;
                }
            } else {
                 chart.options.scales.y.min = undefined;
                 chart.options.scales.y.max = undefined;
            }

            chart.update();
        }
    }, [wavelengths, samples, isProcessed]);

    const handleResetZoom = () => {
        if (chartInstanceRef.current) {
            chartInstanceRef.current.resetZoom();
        }
        if (isProcessed) {
            onReset();
        }
    };

    const handleApplyRange = () => {
        const chart = chartInstanceRef.current;
        if (!chart || wavelengths.length === 0) return;

        const start = parseFloat(startWl), end = parseFloat(endWl);
        const minWl = wavelengths[0], maxWl = wavelengths[wavelengths.length - 1];

        if (isNaN(start) || isNaN(end) || start >= end || start < minWl || end > maxWl) {
            alert(`Rango espectral inválido. Asegúrese que el inicio < fin y está dentro de ${minWl.toFixed(2)} y ${maxWl.toFixed(2)} nm.`);
            setStartWl(minWl.toFixed(2));
            setEndWl(maxWl.toFixed(2));
            chart.options.scales.x.min = undefined;
            chart.options.scales.x.max = undefined;
        } else {
            chart.options.scales.x.min = start;
            chart.options.scales.x.max = end;
        }
        chart.update();
    };

    return (
        <Card>
            <div className="flex justify-between items-start mb-2">
                <h2 className="text-lg font-semibold flex items-center gap-2">
                    <ChartIcon />
                    Visualizador de Espectros
                </h2>
                <p className="text-sm text-gray-500 hidden md:block">Click/arrastre o use la rueda para zoom.</p>
            </div>
            <div className="grid grid-cols-1 md:grid-cols-5 gap-3 items-center border-t border-gray-200 pt-3 mt-2">
                <div className="flex items-center gap-2 md:col-span-1">
                    <label htmlFor="startWavelength" className="text-xs text-gray-500 whitespace-nowrap">Inicio:</label>
                    <input type="number" id="startWavelength" value={startWl} onChange={e => setStartWl(e.target.value)} placeholder="nm" className="w-full bg-white border border-gray-300 rounded-md px-2 py-1 text-xs focus:outline-none focus:ring-1 focus:ring-brand-primary" />
                </div>
                <div className="flex items-center gap-2 md:col-span-1">
                    <label htmlFor="endWavelength" className="text-xs text-gray-500 whitespace-nowrap">Fin:</label>
                    <input type="number" id="endWavelength" value={endWl} onChange={e => setEndWl(e.target.value)} placeholder="nm" className="w-full bg-white border border-gray-300 rounded-md px-2 py-1 text-xs focus:outline-none focus:ring-1 focus:ring-brand-primary" />
                </div>
                <div className="md:col-span-1">
                    <Button onClick={handleApplyRange} className="text-xs !py-1.5 !px-3 w-full">Aplicar</Button>
                </div>
                <div className="md:col-span-2 flex justify-end">
                    <Button variant="secondary" onClick={handleResetZoom} className="text-xs !py-1.5 !px-3">
                        {isProcessed ? 'Resetear Pre-proc.' : 'Resetear Vista'}
                    </Button>
                </div>
            </div>
            <div className="relative h-64 mt-4">
                <canvas ref={chartRef}></canvas>
            </div>
        </Card>
    );
};

export default SpectraViewer;

import React, { useRef, useEffect } from 'react';
import Card from './Card';
import Button from './Button';
import { PcaResult } from '../types';

declare var Chart: any;

interface PcaAnalyzerProps {
    onRunPca: () => void;
    pcaResults: PcaResult[] | null;
    disabled: boolean;
}

const PcaIcon: React.FC = () => (
     <svg xmlns="http://www.w3.org/2000/svg" width="20" height="20" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round" className="text-brand-primary">
        <circle cx="12" cy="12" r="10"></circle><circle cx="12" cy="12" r="3"></circle>
    </svg>
);

const PcaAnalyzer: React.FC<PcaAnalyzerProps> = ({ onRunPca, pcaResults, disabled }) => {
    const chartRef = useRef<HTMLCanvasElement>(null);
    const chartInstanceRef = useRef<any>(null);

    useEffect(() => {
        if (chartRef.current) {
            const ctx = chartRef.current.getContext('2d');
            if (ctx) {
                chartInstanceRef.current = new Chart(ctx, {
                    type: 'scatter',
                    data: { datasets: [] },
                    options: {
                        maintainAspectRatio: false,
                        responsive: true,
                        plugins: {
                            legend: { display: false },
                            tooltip: {
                                callbacks: {
                                    title: (context: any) => {
                                        const dataIndex = context[0].dataIndex;
                                        return context[0].dataset.rawData[dataIndex].id;
                                    }
                                }
                            }
                        },
                        scales: {
                            x: { title: { display: true, text: 'PC1' } },
                            y: { title: { display: true, text: 'PC2' } }
                        }
                    }
                });
            }
        }
        return () => chartInstanceRef.current?.destroy();
    }, []);

    useEffect(() => {
        if (chartInstanceRef.current && pcaResults) {
            const variancePC1 = 85.4 + Math.random() * 5;
            const variancePC2 = 9.1 + Math.random() * 2;
            chartInstanceRef.current.options.scales.x.title.text = `PC1 (${variancePC1.toFixed(1)}% Varianza)`;
            chartInstanceRef.current.options.scales.y.title.text = `PC2 (${variancePC2.toFixed(1)}% Varianza)`;
            chartInstanceRef.current.data.datasets = [{
                label: 'PCA Scores',
                data: pcaResults,
                rawData: pcaResults, // Store original data for tooltip
                backgroundColor: pcaResults.map(s => s.color + 'BF'),
                borderColor: pcaResults.map(s => s.color),
                pointRadius: 6
            }];
            chartInstanceRef.current.update();
        }
    }, [pcaResults]);


    return (
        <Card>
            <h2 className="text-lg font-semibold mb-2 flex items-center gap-2">
                <svg xmlns="http://www.w3.org/2000/svg" width="20" height="20" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round" className="text-brand-primary"><path d="M3 3v18h18"></path><path d="m19 9-5 5-4-4-3 3"></path></svg>
                Análisis Exploratorio (PCA)
            </h2>
            <p className="text-sm text-gray-500 mb-4">Genere un gráfico de scores PCA (simulado) para visualizar la similitud y agrupamiento entre las muestras activas.</p>
            <Button onClick={onRunPca} disabled={disabled} className="w-full max-w-sm mx-auto mb-4">
                <PcaIcon />
                Generar Gráfico PCA
            </Button>
            <div className={`relative h-80 ${!pcaResults && 'hidden'}`}>
                <canvas ref={chartRef}></canvas>
            </div>
        </Card>
    );
};

export default PcaAnalyzer;

import React from 'react';
import Card from './Card';
import Button from './Button';
import { PreprocessingStep } from '../types';

interface PreprocessingEditorProps {
    steps: PreprocessingStep[];
    setSteps: React.Dispatch<React.SetStateAction<PreprocessingStep[]>>;
    onVisualize: () => void;
    disabled: boolean;
}

const PREPROCESSING_METHODS = {
    'none': { name: 'Ninguno', params: [] },
    'savgol': {
        name: 'Savitzky-Golay',
        params: [
            { id: 'derivative', name: 'Orden Derivada', type: 'number', default: 1 },
            { id: 'windowSize', name: 'Tamaño Ventana (impar)', type: 'number', default: 5 },
            { id: 'polynomialOrder', name: 'Orden Polinomio', type: 'number', default: 2 },
        ],
    },
    'snv': { name: 'Standard Normal Variate (SNV)', params: [] },
    'msc': { name: 'Multiplicative Scatter Correction (MSC)', params: [] },
    'detrend': { name: 'Detrend', params: [] },
};

const EditIcon: React.FC = () => (
    <svg xmlns="http://www.w3.org/2000/svg" width="20" height="20" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round" className="text-brand-primary"><path d="M12 20h9"></path><path d="M16.5 3.5a2.12 2.12 0 0 1 3 3L7 19l-4 1 1-4Z"></path></svg>
);
const VisualizeIcon: React.FC = () => (
    <svg xmlns="http://www.w3.org/2000/svg" width="16" height="16" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"><path d="m21.14 10.28-9.23-9.23a1.5 1.5 0 0 0-2.12 0l-9.23 9.23a1.5 1.5 0 0 0 0 2.12l9.23 9.23a1.5 1.5 0 0 0 2.12 0l9.23-9.23a1.5 1.5 0 0 0 0-2.12z"></path><path d="M12 22V2"></path></svg>
);
const AddIcon: React.FC = () => (
    <svg xmlns="http://www.w3.org/2000/svg" width="16" height="16" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"><line x1="12" y1="5" x2="12" y2="19"></line><line x1="5" y1="12" x2="19" y2="12"></line></svg>
);
const RemoveIcon: React.FC = () => (
    <svg xmlns="http://www.w3.org/2000/svg" width="16" height="16" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"><polyline points="3 6 5 6 21 6"></polyline><path d="M19 6v14a2 2 0 0 1-2 2H7a2 2 0 0 1-2-2V6m3 0V4a2 2 0 0 1 2-2h4a2 2 0 0 1 2 2v2"></path></svg>
);


const PreprocessingEditor: React.FC<PreprocessingEditorProps> = ({ steps, setSteps, onVisualize, disabled }) => {

    const addStep = () => {
        const newStep: PreprocessingStep = { method: 'savgol', params: {} };
        PREPROCESSING_METHODS['savgol'].params.forEach(p => newStep.params[p.id] = p.default);
        setSteps([...steps, newStep]);
    };

    const removeStep = (index: number) => {
        setSteps(steps.filter((_, i) => i !== index));
    };

    const handleMethodChange = (index: number, newMethod: PreprocessingStep['method']) => {
        const newSteps = [...steps];
        newSteps[index].method = newMethod;
        newSteps[index].params = {};
        (PREPROCESSING_METHODS[newMethod].params as any[]).forEach(p => {
            newSteps[index].params[p.id] = p.default;
        });
        setSteps(newSteps);
    };

    const handleParamChange = (stepIndex: number, paramId: string, value: string) => {
        const newSteps = [...steps];
        newSteps[stepIndex].params[paramId] = parseFloat(value);
        setSteps(newSteps);
    };

    return (
        <Card>
            <h2 className="text-lg font-semibold mb-4 flex items-center gap-2"><EditIcon />3. Pre-procesamiento</h2>
            <div className="space-y-3 mb-4">
                {steps.map((step, index) => {
                    const methodInfo = PREPROCESSING_METHODS[step.method];
                    return (
                        <div key={index} className="p-3 border border-gray-200 rounded-md bg-white">
                            <div className="flex items-center justify-between">
                                <select
                                    value={step.method}
                                    onChange={(e) => handleMethodChange(index, e.target.value as PreprocessingStep['method'])}
                                    className="w-full bg-white border border-gray-300 rounded-md px-2 py-1 text-sm focus:outline-none focus:ring-1 focus:ring-brand-primary"
                                >
                                    {Object.entries(PREPROCESSING_METHODS).map(([key, value]) => (
                                        <option key={key} value={key}>{value.name}</option>
                                    ))}
                                </select>
                                <button onClick={() => removeStep(index)} className="ml-2 p-1 text-gray-400 hover:text-red-500 transition-colors">
                                    <RemoveIcon />
                                </button>
                            </div>
                             {methodInfo.params.length > 0 && (
                                <div className="grid grid-cols-3 gap-2 mt-2">
                                    {(methodInfo.params as any[]).map(param => (
                                        <div key={param.id} className="text-xs">
                                            <label htmlFor={`${param.id}-${index}`} className="text-gray-500">{param.name}</label>
                                            <input
                                                type={param.type}
                                                id={`${param.id}-${index}`}
                                                value={step.params[param.id] || ''}
                                                onChange={(e) => handleParamChange(index, param.id, e.target.value)}
                                                className="w-full bg-white border border-gray-300 rounded-md px-2 py-1 text-xs mt-1 focus:outline-none focus:ring-1 focus:ring-brand-primary"
                                            />
                                        </div>
                                    ))}
                                </div>
                            )}
                        </div>
                    );
                })}
            </div>
            <div className="flex flex-col gap-2">
                <Button onClick={onVisualize} disabled={disabled}><VisualizeIcon />Visualizar Pre-procesamiento</Button>
                <Button variant="secondary" onClick={addStep} disabled={disabled}><AddIcon />Añadir Paso</Button>
            </div>
        </Card>
    );
};

export default PreprocessingEditor;

import React, { useState } from 'react';
import Card from './Card';
import Button from './Button';

interface ModelGeneratorProps {
    onRunModel: (lambda: number) => void;
    disabled: boolean;
}

const GenerateIcon: React.FC = () => (
     <svg xmlns="http://www.w3.org/2000/svg" width="20" height="20" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round" className="text-brand-primary">
        <circle cx="12" cy="12" r="10"></circle><path d="m9 12 2 2 4-4"></path>
    </svg>
);

const RunIcon: React.FC = () => (
    <svg xmlns="http://www.w3.org/2000/svg" width="16" height="16" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round">
        <polygon points="5 3 19 12 5 21 5 3"></polygon>
    </svg>
);

const ModelGenerator: React.FC<ModelGeneratorProps> = ({ onRunModel, disabled }) => {
    const [lambda, setLambda] = useState('0.01');

    const handleRun = () => {
        const lambdaValue = parseFloat(lambda);
        if (!isNaN(lambdaValue) && lambdaValue >= 0) {
            onRunModel(lambdaValue);
        } else {
            alert('Por favor, introduzca un valor de Lambda no negativo.');
        }
    };

    return (
        <Card>
            <h2 className="text-lg font-semibold mb-4 flex items-center gap-2">
                <GenerateIcon />
                4. Generación de Modelo
            </h2>
            <div className="grid grid-cols-1 md:grid-cols-2 gap-4 items-end">
                <div className="text-sm text-gray-500">
                    <label htmlFor="lambda-input" className="block mb-1">Lambda (λ) de Regularización:</label>
                    <input
                        type="number"
                        id="lambda-input"
                        value={lambda}
                        onChange={(e) => setLambda(e.target.value)}
                        min="0"
                        step="0.001"
                        className="w-full bg-white border border-gray-300 rounded-md px-2 py-1 focus:outline-none focus:ring-1 focus:ring-brand-primary"
                    />
                </div>
                <Button onClick={handleRun} disabled={disabled}>
                    <RunIcon />
                    Generar Modelo Ridge
                </Button>
            </div>
        </Card>
    );
};

export default ModelGenerator;

import React, { useState, useRef, useEffect } from 'react';
import Card from './Card';
import Button from './Button';
import { ModelResults, PreprocessingStep } from '../types';

declare var Chart: any;

interface ResultsViewerProps {
    results: ModelResults;
    propertyName: string;
    preprocessingSteps: PreprocessingStep[];
    activeSamples: (string|number)[];
    onDeactivateOutliers: (outlierIds: (string|number)[]) => void;
    wavelengths: number[];
}

const ResultsViewer: React.FC<ResultsViewerProps> = ({ results, propertyName, preprocessingSteps, activeSamples, onDeactivateOutliers, wavelengths }) => {
    const [activeTab, setActiveTab] = useState('correlation');
    const chartRef = useRef<HTMLCanvasElement>(null);
    const chartInstanceRef = useRef<any>(null);
    const chartWrapperRef = useRef<HTMLDivElement>(null);

    const [rotation, setRotation] = useState({ x: -20, y: -30 });
    const isDragging = useRef(false);
    const lastMousePos = useRef({ x: 0, y: 0 });

    const handleMouseDown = (e: React.MouseEvent) => {
        isDragging.current = true;
        lastMousePos.current = { x: e.clientX, y: e.clientY };
        if (chartWrapperRef.current) chartWrapperRef.current.classList.add('grabbing');
    };

    const handleMouseUp = () => {
        isDragging.current = false;
        if (chartWrapperRef.current) chartWrapperRef.current.classList.remove('grabbing');
    };

    const handleMouseMove = (e: MouseEvent) => {
        if (!isDragging.current) return;
        const dx = e.clientX - lastMousePos.current.x;
        const dy = e.clientY - lastMousePos.current.y;

        setRotation(prev => {
            let newX = prev.x - dy * 0.5;
            newX = Math.max(-90, Math.min(90, newX)); // Clamp X rotation
            return {
                x: newX,
                y: prev.y + dx * 0.5,
            };
        });

        lastMousePos.current = { x: e.clientX, y: e.clientY };
    };

    useEffect(() => {
        window.addEventListener('mouseup', handleMouseUp);
        window.addEventListener('mousemove', handleMouseMove);

        return () => {
            window.removeEventListener('mouseup', handleMouseUp);
            window.removeEventListener('mousemove', handleMouseMove);
        };
    }, []);


    useEffect(() => {
        if (chartRef.current) {
            const ctx = chartRef.current.getContext('2d');
            if (ctx) {
                chartInstanceRef.current = new Chart(ctx, {
                    type: 'scatter',
                    data: { datasets: [] },
                    options: {
                        maintainAspectRatio: false,
                        responsive: true,
                        animation: false,
                        plugins: {
                            legend: { display: true }
                        },
                        scales: {
                            x: { title: { display: true, text: 'Valores Reales' } },
                            y: { title: { display: true, text: 'Valores Predichos' } }
                        }
                    }
                });
            }
        }
        return () => chartInstanceRef.current?.destroy();
    }, []);

    useEffect(() => {
        if (chartInstanceRef.current && results) {
            const { actual, predicted } = results.model.correlation;
            const inliersData: {x: number, y: number}[] = [];
            const outliersData: {x: number, y: number}[] = [];

            results.mahalanobis.distances.forEach((d, i) => {
                const point = { x: actual[i], y: predicted[i] };
                if (results.mahalanobis.outlierIds.includes(d.id)) outliersData.push(point);
                else inliersData.push(point);
            });

            const allValues = [...actual, ...predicted];
            const minVal = Math.min(...allValues);
            const maxVal = Math.max(...allValues);
            const padding = (maxVal - minVal) * 0.05;

            chartInstanceRef.current.data.datasets = [
                { label: 'Inliers', data: inliersData, backgroundColor: '#3B82F680', borderColor: '#3B82F6', pointRadius: 5 },
                { label: 'Outliers', data: outliersData, backgroundColor: '#EF444480', borderColor: '#EF4444', pointRadius: 7, pointStyle: 'rectRot' },
                { type: 'line', label: 'Línea y=x', data: [{x: minVal, y: minVal}, {x: maxVal, y: maxVal}], borderColor: '#9CA3AF', borderWidth: 2, borderDash: [5, 5], pointRadius: 0, fill: false }
            ];
            chartInstanceRef.current.options.scales.x.min = minVal - padding;
            chartInstanceRef.current.options.scales.x.max = maxVal + padding;
            chartInstanceRef.current.options.scales.y.min = minVal - padding;
            chartInstanceRef.current.options.scales.y.max = maxVal + padding;
            chartInstanceRef.current.update('none');
        }
    }, [results]);

    const handleExportConfig = () => {
        const config = {
            date: new Date().toISOString(),
            modelType: 'RidgeRegression',
            analyticalProperty: propertyName,
            activeSamples: activeSamples,
            preprocessing: preprocessingSteps,
            modelParameters: { lambda: results.lambda },
            modelMetrics: { r2: results.model.r2, rmsec: results.model.rmsec },
        };
        const dataStr = "data:text/json;charset=utf-8," + encodeURIComponent(JSON.stringify(config, null, 2));
        const downloadAnchorNode = document.createElement('a');
        downloadAnchorNode.setAttribute("href", dataStr);
        downloadAnchorNode.setAttribute("download", "spectra_pro_ridge_config.json");
        document.body.appendChild(downloadAnchorNode);
        downloadAnchorNode.click();
        downloadAnchorNode.remove();
    };

    const handleDownloadData = () => {
        const headers = ['ID_Muestra', 'Valor_Real', 'Valor_Predicho', 'Residuo', ...wavelengths];
        const { residuals, processedSpectra } = results.model;
        const rows = residuals.map((res, index) => 
            [res.id, res.actual.toFixed(6), res.predicted.toFixed(6), res.residual.toFixed(6), ...processedSpectra[index].map(v => v.toFixed(6))]
        );
        const csvContent = [headers.join(','), ...rows.map(row => row.join(','))].join('\n');
        const blob = new Blob([csvContent], { type: 'text/csv;charset=utf-8;' });
        const url = URL.createObjectURL(blob);
        const link = document.createElement("a");
        link.setAttribute("href", url);
        link.setAttribute("download", "spectra_model_data.csv");
        document.body.appendChild(link);
        link.click();
        document.body.removeChild(link);
    };

    const residuals = results.model.residuals;
    const meanResidual = residuals.reduce((sum, r) => sum + r.residual, 0) / residuals.length;
    const stdDevResidual = Math.sqrt(residuals.reduce((sum, r) => sum + Math.pow(r.residual - meanResidual, 2), 0) / residuals.length);
    const residualOutlierThreshold = stdDevResidual * 2.5;

    const outliers = results.mahalanobis.distances.filter(d => d.isOutlier);
    const residualsMap = new Map(residuals.map(r => [r.id, r]));
    const [selectedOutliers, setSelectedOutliers] = useState<Set<string|number>>(new Set());

    const handleOutlierSelection = (id: string|number, checked: boolean) => {
        setSelectedOutliers(prev => {
            const newSet = new Set(prev);
            if (checked) newSet.add(id);
            else newSet.delete(id);
            return newSet;
        });
    };

    const handleSelectAllOutliers = (checked: boolean) => {
        if(checked) {
            setSelectedOutliers(new Set(outliers.map(o => o.id)));
        } else {
            setSelectedOutliers(new Set());
        }
    };

    const handleDeactivateClick = () => {
        if (selectedOutliers.size === 0) {
            alert("Por favor, seleccione al menos un outlier para desactivar.");
            return;
        }
        onDeactivateOutliers(Array.from(selectedOutliers));
        setSelectedOutliers(new Set());
    };

    const TabButton = ({ tabId, children }: { tabId: string; children: React.ReactNode }) => (
        <button
            className={`px-4 py-2 text-sm font-medium rounded-t-lg border-b-2 transition-colors ${activeTab === tabId ? 'text-brand-primary border-brand-primary' : 'text-gray-500 border-transparent hover:text-gray-700 hover:border-gray-300'}`}
            onClick={() => setActiveTab(tabId)}
        >
            {children}
        </button>
    );

    return (
        <Card>
            <div className="flex border-b border-gray-200 mb-4">
                <TabButton tabId="correlation">Correlación</TabButton>
                <TabButton tabId="residuals">Residuos</TabButton>
                <TabButton tabId="outliers">Outliers</TabButton>
                <TabButton tabId="full-data">Datos Completos</TabButton>
            </div>

            {activeTab === 'correlation' && (
                <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
                    <div className="md:col-span-2 flex flex-col">
                        <p className="text-center text-xs text-gray-500 mb-2">Haga clic y arrastre el gráfico para rotarlo.</p>
                        <div ref={chartWrapperRef} onMouseDown={handleMouseDown} className="relative h-96 cursor-grab" style={{ perspective: '1200px', transformStyle: 'preserve-3d' }}>
                            <canvas ref={chartRef} style={{ transition: 'transform 0.1s linear', transform: `rotateX(${rotation.x}deg) rotateY(${rotation.y}deg)` }}></canvas>
                        </div>
                    </div>
                    <div className="flex flex-col justify-center space-y-2">
                        <h3 className="font-semibold text-lg mb-2">Métricas del Modelo</h3>
                        <p className="text-sm text-gray-600">Propiedad: <span className="font-semibold text-gray-900">{propertyName}</span></p>
                        <p className="text-sm text-gray-600">Lambda (λ): <span className="font-mono text-brand-primary text-base">{results.lambda.toExponential(2)}</span></p>
                        <hr className="my-2 border-gray-200" />
                        <p className="text-sm text-gray-600">R² (Calibración): <span className="font-mono text-brand-primary text-base">{results.model.r2.toFixed(4)}</span></p>
                        <p className="text-sm text-gray-600">RMSEC: <span className="font-mono text-brand-primary text-base">{results.model.rmsec.toFixed(4)}</span></p>
                        <div className="pt-4">
                            <Button variant="secondary" onClick={handleExportConfig} className="w-full">Exportar Configuración</Button>
                        </div>
                    </div>
                </div>
            )}

            {activeTab === 'residuals' && (
                 <div>
                    <h3 className="font-semibold text-lg mb-2">Análisis de Residuos del Modelo</h3>
                    <p className="text-sm text-gray-500 mb-4">Las muestras con residuos altos (resaltadas) pueden ser outliers de predicción.</p>
                    <div className="max-h-96 overflow-y-auto pr-2 border rounded-md">
                        <table className="w-full text-sm text-left">
                            <thead className="text-xs text-gray-500 uppercase bg-gray-100 sticky top-0">
                                <tr>
                                    <th scope="col" className="px-4 py-2">ID Muestra</th>
                                    <th scope="col" className="px-4 py-2">Valor Real</th>
                                    <th scope="col" className="px-4 py-2">Valor Predicho</th>
                                    <th scope="col" className="px-4 py-2">Residuo</th>
                                </tr>
                            </thead>
                            <tbody>
                                {residuals.map(r => {
                                    const isOutlier = Math.abs(r.residual) > residualOutlierThreshold;
                                    return (
                                        <tr key={r.id} className={`${isOutlier ? 'bg-red-50' : ''} border-b border-gray-200 last:border-b-0`}>
                                            <td className="px-4 py-2 font-medium">{r.id}</td>
                                            <td className="px-4 py-2 font-mono">{r.actual.toFixed(4)}</td>
                                            <td className="px-4 py-2 font-mono">{r.predicted.toFixed(4)}</td>
                                            <td className={`px-4 py-2 font-mono ${isOutlier ? 'text-red-600 font-bold' : ''}`}>{r.residual.toFixed(4)}</td>
                                        </tr>
                                    );
                                })}
                            </tbody>
                        </table>
                    </div>
                 </div>
            )}

            {activeTab === 'outliers' && (
                 <div>
                    <h3 className="font-semibold text-lg mb-2">Análisis de Outliers (Distancia de Mahalanobis)</h3>
                    <p className="text-sm text-gray-500 mb-4">Muestras espectralmente anómalas (Distancia > 3.0). Seleccione las que desea desactivar del modelo.</p>
                     {outliers.length === 0 ? (
                        <p className="text-center text-gray-500 p-8">No se detectaron outliers espectrales en este modelo.</p>
                     ) : (
                        <>
                            <div className="max-h-96 overflow-y-auto pr-2 mb-4 border border-gray-200 rounded-md">
                                <table className="w-full text-sm text-left">
                                    <thead className="text-xs text-gray-500 uppercase bg-gray-100 sticky top-0">
                                        <tr>
                                            <th scope="col" className="px-4 py-2 w-12"><input type="checkbox" onChange={e => handleSelectAllOutliers(e.target.checked)} className="form-checkbox h-4 w-4 rounded text-brand-primary border-gray-300 focus:ring-brand-primary" /></th>
                                            <th scope="col" className="px-4 py-2">ID Muestra</th>
                                            <th scope="col" className="px-4 py-2">Distancia (GH)</th>
                                            <th scope="col" className="px-4 py-2">Valor Real</th>
                                            <th scope="col" className="px-4 py-2">Valor Predicho</th>
                                            <th scope="col" className="px-4 py-2">Residuo</th>
                                        </tr>
                                    </thead>
                                    <tbody>
                                        {outliers.map(outlier => {
