import { Sample, PreprocessingStep, ModelResults, PcaResult } from '../types';

// Declare global libraries from CDN for TypeScript
declare var mlMatrix: any;
declare var mlRidgeRegression: any;

function savitzkyGolay(data: number[], options: { windowSize: number; polynomial: number; derivative?: number }): number[] {
    const { windowSize, polynomial, derivative = 0 } = options;
    if (windowSize % 2 === 0 || windowSize < 3 || polynomial >= windowSize || derivative > polynomial) {
        console.warn("Invalid Savitzky-Golay parameters, returning original data.", options);
        return data;
    }

    const halfWindow = Math.floor(windowSize / 2);
    const { Matrix } = mlMatrix;

    try {
        let A = new Matrix(windowSize, polynomial + 1);
        for (let i = 0; i < windowSize; i++) {
            for (let j = 0; j <= polynomial; j++) {
                A.set(i, j, Math.pow(i - halfWindow, j));
            }
        }

        const C = Matrix.solve(A.transpose().mmul(A), A.transpose());

        const fact = (n: number) => { let r = 1; for (let i = 2; i <= n; i++) r *= i; return r; };
        const sgCoefficients = C.getRow(derivative).map((v: number) => v * fact(derivative));
        const reversedCoeffs = sgCoefficients.slice().reverse();

        const result = new Array(data.length);
        for (let i = 0; i < data.length; i++) {
            if (i < halfWindow || i >= data.length - halfWindow) {
                result[i] = data[i]; // Keep edges as they are
            } else {
                let convSum = 0;
                for (let j = 0; j < windowSize; j++) {
                    convSum += data[i - halfWindow + j] * reversedCoeffs[j];
                }
                result[i] = convSum;
            }
        }
        return result;
    } catch (e) {
        console.error("Error in Savitzky-Golay matrix calculation:", e);
        return data;
    }
}


export function applyPreprocessingLogic(inputSpectrum: number[], steps: PreprocessingStep[]): number[] {
    let processedSpectrum = [...inputSpectrum];

    steps.forEach(step => {
        const n = processedSpectrum.length;
        if (n === 0) return;

        switch (step.method) {
            case 'snv': {
                const mean = processedSpectrum.reduce((a, b) => a + b, 0) / n;
                const stdDev = Math.sqrt(processedSpectrum.map(x => Math.pow(x - mean, 2)).reduce((a, b) => a + b, 0) / (n - 1));
                if (stdDev > 0) {
                    processedSpectrum = processedSpectrum.map(x => (x - mean) / stdDev);
                }
                break;
            }
            case 'savgol': { 
                const { derivative = 1, windowSize = 5, polynomialOrder = 2 } = step.params;
                processedSpectrum = savitzkyGolay(processedSpectrum, { windowSize: parseInt(String(windowSize)), polynomial: parseInt(String(polynomialOrder)), derivative: parseInt(String(derivative)) });
                break;
            }
            case 'detrend': {
                 if (n < 2) break;
                 const x = Array.from({length: n}, (_, i) => i);
                 const sumX = x.reduce((a, b) => a + b, 0);
                 const sumY = processedSpectrum.reduce((a, b) => a + b, 0);
                 const sumXY = x.map((xi, i) => xi * processedSpectrum[i]).reduce((a, b) => a + b, 0);
                 const sumX2 = x.map(xi => xi * xi).reduce((a, b) => a + b, 0);
                 const slope = (n * sumXY - sumX * sumY) / (n * sumX2 - sumX * sumX);
                 const intercept = (sumY - slope * sumX) / n;
                 if(!isNaN(slope) && !isNaN(intercept)) {
                    processedSpectrum = processedSpectrum.map((y, i) => y - (slope * i + intercept));
                 }
                 break;
            }
        }
    });

    return processedSpectrum;
}

export function runRidgeRegression(
    activeSamples: Sample[],
    preprocessingSteps: PreprocessingStep[],
    lambda: number
): ModelResults {
    const { RidgeRegression } = mlRidgeRegression;

    const actualValues = activeSamples.map(s => s.analyticalValue);
    const ids = activeSamples.map(s => s.id);
    const X_processed = activeSamples.map(s => applyPreprocessingLogic(s.values, preprocessingSteps));

    const ridge = new RidgeRegression(X_processed, actualValues, { lambda, center: true, scale: true });
    const predictedValues = ridge.predict(X_processed);

    const n = actualValues.length;
    const meanY = actualValues.reduce((a, b) => a + b, 0) / n;
    const ssTot = actualValues.reduce((acc, y) => acc + Math.pow(y - meanY, 2), 0);
    const ssRes = actualValues.reduce((acc, y, i) => acc + Math.pow(y - predictedValues[i], 2), 0);
    const r2 = ssTot > 0 ? 1 - (ssRes / ssTot) : 1;
    const rmsec = Math.sqrt(ssRes / n);

    // Simulate Mahalanobis distance for outlier detection
    const OUTLIER_THRESHOLD = 3.0;
    const outlierPercentage = 0.07; // 7% chance of being a spectral outlier
    const mahalanobisDistances = activeSamples.map(sample => {
        const isOutlier = Math.random() < outlierPercentage;
        return {
            id: sample.id,
            distance: isOutlier ? OUTLIER_THRESHOLD + Math.random() * 3 : 0.5 + Math.random() * (OUTLIER_THRESHOLD - 1),
            isOutlier: isOutlier
        };
    });

    return {
        lambda: lambda,
        mahalanobis: {
            distances: mahalanobisDistances,
            outlierIds: mahalanobisDistances.filter(d => d.isOutlier).map(d => d.id),
        },
        model: {
            r2: Math.max(0, Math.min(0.9999, r2)),
            rmsec: rmsec,
            correlation: { actual: actualValues, predicted: predictedValues },
            residuals: ids.map((id, i) => ({
                id,
                actual: actualValues[i],
                predicted: predictedValues[i],
                residual: actualValues[i] - predictedValues[i]
            })),
            processedSpectra: X_processed
        }
    };
}


export function runPcaSimulation(activeSamples: Sample[]): PcaResult[] {
    const analyticalValues = activeSamples.map(s => s.analyticalValue);
    const minAV = Math.min(...analyticalValues);
    const maxAV = Math.max(...analyticalValues);
    const rangeAV = maxAV - minAV;

    return activeSamples.map(sample => {
        // Normalize analytical value between -1 and 1 to serve as the main driver for PC1
        const normalizedAV = rangeAV > 0 ? ((sample.analyticalValue - minAV) / rangeAV - 0.5) * 2 : 0;
        // PC1 is mainly the normalized value with some noise
        const pc1 = normalizedAV + (Math.random() - 0.5) * 0.4;
        // PC2 is mostly random noise
        const pc2 = (Math.random() - 0.5) * 1.5;

        return { x: pc1, y: pc2, id: sample.id, color: sample.color };
    });
}

import React, { useState, useRef, useEffect } from 'react';
import Card from './Card';
import Button from './Button';
import { ModelResults, PreprocessingStep } from '../types';

declare var Chart: any;

interface ResultsViewerProps {
    results: ModelResults;
    propertyName: string;
    preprocessingSteps: PreprocessingStep[];
    activeSamples: (string|number)[];
    onDeactivateOutliers: (outlierIds: (string|number)[]) => void;
    wavelengths: number[];
}

const ResultsViewer: React.FC<ResultsViewerProps> = ({ results, propertyName, preprocessingSteps, activeSamples, onDeactivateOutliers, wavelengths }) => {
    const [activeTab, setActiveTab] = useState('correlation');
    const chartRef = useRef<HTMLCanvasElement>(null);
    const chartInstanceRef = useRef<any>(null);
    const chartWrapperRef = useRef<HTMLDivElement>(null);

    const [rotation, setRotation] = useState({ x: -20, y: -30 });
    const isDragging = useRef(false);
    const lastMousePos = useRef({ x: 0, y: 0 });

    const handleMouseDown = (e: React.MouseEvent) => {
        isDragging.current = true;
        lastMousePos.current = { x: e.clientX, y: e.clientY };
        if (chartWrapperRef.current) chartWrapperRef.current.classList.add('grabbing');
    };

    const handleMouseUp = () => {
        isDragging.current = false;
        if (chartWrapperRef.current) chartWrapperRef.current.classList.remove('grabbing');
    };

    const handleMouseMove = (e: MouseEvent) => {
        if (!isDragging.current) return;
        const dx = e.clientX - lastMousePos.current.x;
        const dy = e.clientY - lastMousePos.current.y;

        setRotation(prev => {
            let newX = prev.x - dy * 0.5;
            newX = Math.max(-90, Math.min(90, newX)); // Clamp X rotation
            return {
                x: newX,
                y: prev.y + dx * 0.5,
            };
        });

        lastMousePos.current = { x: e.clientX, y: e.clientY };
    };

    useEffect(() => {
        window.addEventListener('mouseup', handleMouseUp);
        window.addEventListener('mousemove', handleMouseMove);

        return () => {
            window.removeEventListener('mouseup', handleMouseUp);
            window.removeEventListener('mousemove', handleMouseMove);
        };
    }, []);


    useEffect(() => {
        if (chartRef.current) {
            const ctx = chartRef.current.getContext('2d');
            if (ctx) {
                chartInstanceRef.current = new Chart(ctx, {
                    type: 'scatter',
                    data: { datasets: [] },
                    options: {
                        maintainAspectRatio: false,
                        responsive: true,
                        animation: false,
                        plugins: {
                            legend: { display: true }
                        },
                        scales: {
                            x: { title: { display: true, text: 'Valores Reales' } },
                            y: { title: { display: true, text: 'Valores Predichos' } }
                        }
                    }
                });
            }
        }
        return () => chartInstanceRef.current?.destroy();
    }, []);

    useEffect(() => {
        if (chartInstanceRef.current && results) {
            const { actual, predicted } = results.model.correlation;
            const inliersData: {x: number, y: number}[] = [];
            const outliersData: {x: number, y: number}[] = [];

            results.mahalanobis.distances.forEach((d, i) => {
                const point = { x: actual[i], y: predicted[i] };
                if (results.mahalanobis.outlierIds.includes(d.id)) outliersData.push(point);
                else inliersData.push(point);
            });

            const allValues = [...actual, ...predicted];
            const minVal = Math.min(...allValues);
            const maxVal = Math.max(...allValues);
            const padding = (maxVal - minVal) * 0.05;

            chartInstanceRef.current.data.datasets = [
                { label: 'Inliers', data: inliersData, backgroundColor: '#3B82F680', borderColor: '#3B82F6', pointRadius: 5 },
                { label: 'Outliers', data: outliersData, backgroundColor: '#EF444480', borderColor: '#EF4444', pointRadius: 7, pointStyle: 'rectRot' },
                { type: 'line', label: 'Línea y=x', data: [{x: minVal, y: minVal}, {x: maxVal, y: maxVal}], borderColor: '#9CA3AF', borderWidth: 2, borderDash: [5, 5], pointRadius: 0, fill: false }
            ];
            chartInstanceRef.current.options.scales.x.min = minVal - padding;
            chartInstanceRef.current.options.scales.x.max = maxVal + padding;
            chartInstanceRef.current.options.scales.y.min = minVal - padding;
            chartInstanceRef.current.options.scales.y.max = maxVal + padding;
            chartInstanceRef.current.update('none');
        }
    }, [results]);

    const handleExportConfig = () => {
        const config = {
            date: new Date().toISOString(),
            modelType: 'RidgeRegression',
            analyticalProperty: propertyName,
            activeSamples: activeSamples,
            preprocessing: preprocessingSteps,
            modelParameters: { lambda: results.lambda },
            modelMetrics: { r2: results.model.r2, rmsec: results.model.rmsec },
        };
        const dataStr = "data:text/json;charset=utf-8," + encodeURIComponent(JSON.stringify(config, null, 2));
        const downloadAnchorNode = document.createElement('a');
        downloadAnchorNode.setAttribute("href", dataStr);
        downloadAnchorNode.setAttribute("download", "spectra_pro_ridge_config.json");
        document.body.appendChild(downloadAnchorNode);
        downloadAnchorNode.click();
        downloadAnchorNode.remove();
    };

    const handleDownloadData = () => {
        const headers = ['ID_Muestra', 'Valor_Real', 'Valor_Predicho', 'Residuo', ...wavelengths];
        const { residuals, processedSpectra } = results.model;
        const rows = residuals.map((res, index) => 
            [res.id, res.actual.toFixed(6), res.predicted.toFixed(6), res.residual.toFixed(6), ...processedSpectra[index].map(v => v.toFixed(6))]
        );
        const csvContent = [headers.join(','), ...rows.map(row => row.join(','))].join('\n');
        const blob = new Blob([csvContent], { type: 'text/csv;charset=utf-8;' });
        const url = URL.createObjectURL(blob);
        const link = document.createElement("a");
        link.setAttribute("href", url);
        link.setAttribute("download", "spectra_model_data.csv");
        document.body.appendChild(link);
        link.click();
        document.body.removeChild(link);
    };

    const residuals = results.model.residuals;
    const meanResidual = residuals.reduce((sum, r) => sum + r.residual, 0) / residuals.length;
    const stdDevResidual = Math.sqrt(residuals.reduce((sum, r) => sum + Math.pow(r.residual - meanResidual, 2), 0) / residuals.length);
    const residualOutlierThreshold = stdDevResidual * 2.5;

    const outliers = results.mahalanobis.distances.filter(d => d.isOutlier);
    // FIX: Using `as const` ensures that TypeScript infers the array passed to the Map constructor
    // as an array of tuples `[K, V]`, rather than an array of unions, which fixes the type of `residualsMap`.
    const residualsMap = new Map(residuals.map(r => [r.id, r] as const));
    const [selectedOutliers, setSelectedOutliers] = useState<Set<string|number>>(new Set());

    const handleOutlierSelection = (id: string|number, checked: boolean) => {
        setSelectedOutliers(prev => {
            const newSet = new Set(prev);
            if (checked) newSet.add(id);
            else newSet.delete(id);
            return newSet;
        });
    };

    const handleSelectAllOutliers = (checked: boolean) => {
        if(checked) {
            setSelectedOutliers(new Set(outliers.map(o => o.id)));
        } else {
            setSelectedOutliers(new Set());
        }
    };

    const handleDeactivateClick = () => {
        if (selectedOutliers.size === 0) {
            alert("Por favor, seleccione al menos un outlier para desactivar.");
            return;
        }
        onDeactivateOutliers(Array.from(selectedOutliers));
        setSelectedOutliers(new Set());
    };

    const TabButton = ({ tabId, children }: { tabId: string; children: React.ReactNode }) => (
        <button
            className={`px-4 py-2 text-sm font-medium rounded-t-lg border-b-2 transition-colors ${activeTab === tabId ? 'text-brand-primary border-brand-primary' : 'text-gray-500 border-transparent hover:text-gray-700 hover:border-gray-300'}`}
            onClick={() => setActiveTab(tabId)}
        >
            {children}
        </button>
    );

    return (
        <Card>
            <div className="flex border-b border-gray-200 mb-4">
                {/* FIX: Added children to TabButton components to satisfy the component's props interface. */}
                <TabButton tabId="correlation">Correlación</TabButton>
                <TabButton tabId="residuals">Residuos</TabButton>
                <TabButton tabId="outliers">Outliers</TabButton>
                <TabButton tabId="full-data">Datos Completos</TabButton>
            </div>

            {activeTab === 'correlation' && (
                <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
                    <div className="md:col-span-2 flex flex-col">
                        <p className="text-center text-xs text-gray-500 mb-2">Haga clic y arrastre el gráfico para rotarlo.</p>
                        <div ref={chartWrapperRef} onMouseDown={handleMouseDown} className="relative h-96 cursor-grab" style={{ perspective: '1200px', transformStyle: 'preserve-3d' }}>
                            <canvas ref={chartRef} style={{ transition: 'transform 0.1s linear', transform: `rotateX(${rotation.x}deg) rotateY(${rotation.y}deg)` }}></canvas>
                        </div>
                    </div>
                    <div className="flex flex-col justify-center space-y-2">
                        <h3 className="font-semibold text-lg mb-2">Métricas del Modelo</h3>
                        <p className="text-sm text-gray-600">Propiedad: <span className="font-semibold text-gray-900">{propertyName}</span></p>
                        <p className="text-sm text-gray-600">Lambda (λ): <span className="font-mono text-brand-primary text-base">{results.lambda.toExponential(2)}</span></p>
                        <hr className="my-2 border-gray-200" />
                        <p className="text-sm text-gray-600">R² (Calibración): <span className="font-mono text-brand-primary text-base">{results.model.r2.toFixed(4)}</span></p>
                        <p className="text-sm text-gray-600">RMSEC: <span className="font-mono text-brand-primary text-base">{results.model.rmsec.toFixed(4)}</span></p>
                        <div className="pt-4">
                            <Button variant="secondary" onClick={handleExportConfig} className="w-full">Exportar Configuración</Button>
                        </div>
                    </div>
                </div>
            )}

            {activeTab === 'residuals' && (
                 <div>
                    <h3 className="font-semibold text-lg mb-2">Análisis de Residuos del Modelo</h3>
                    <p className="text-sm text-gray-500 mb-4">Las muestras con residuos altos (resaltadas) pueden ser outliers de predicción.</p>
                    <div className="max-h-96 overflow-y-auto pr-2 border rounded-md">
                        <table className="w-full text-sm text-left">
                            <thead className="text-xs text-gray-500 uppercase bg-gray-100 sticky top-0">
                                <tr>
                                    <th scope="col" className="px-4 py-2">ID Muestra</th>
                                    <th scope="col" className="px-4 py-2">Valor Real</th>
                                    <th scope="col" className="px-4 py-2">Valor Predicho</th>
                                    <th scope="col" className="px-4 py-2">Residuo</th>
                                </tr>
                            </thead>
                            <tbody>
                                {residuals.map(r => {
                                    const isOutlier = Math.abs(r.residual) > residualOutlierThreshold;
                                    return (
                                        <tr key={r.id} className={`${isOutlier ? 'bg-red-50' : ''} border-b border-gray-200 last:border-b-0`}>
