const ModelGenerator: React.FC<ModelGeneratorProps> = ({ onRunModel, disabled }) => {
    const [lambda, setLambda] = useState('0.01');

    const handleRun = () => {
        const lambdaValue = parseFloat(lambda);
        if (!isNaN(lambdaValue) && lambdaValue >= 0) {
            onRunModel({ type: 'ridge', lambda: lambdaValue });
        } else {
            alert('Por favor, introduzca un valor de Lambda no negativo.');
        }
    };

    return (
        <Card>
            <h2 className="text-lg font-semibold mb-4 flex items-center gap-2">
                <GenerateIcon />
                4. Generación de Modelo (Ridge)
            </h2>
            <div className="flex flex-col gap-4">
                <div>
                    <label htmlFor="lambda-input" className="block text-sm text-gray-500 mb-1">Lambda (λ) de Regularización:</label>
                    <input
                        type="number"
                        id="lambda-input"
                        value={lambda}
                        onChange={(e) => setLambda(e.target.value)}
                        min="0"
                        step="0.001"
                        className="w-full bg-white border border-gray-300 rounded-md px-2 py-1 text-sm focus:outline-none focus:ring-1 focus:ring-brand-primary"
                    />
                    <p className="text-xs text-gray-400 mt-1">Controla la penalización para evitar sobreajuste.</p>
                </div>

                 <Button onClick={handleRun} disabled={disabled} className="w-full">
                    <RunIcon />
                    Generar Modelo Ridge
                </Button>
            </div>
        </Card>
    );
};

export default ModelGenerator;

import React, { useState, useRef, useEffect } from 'react';
import Card from './Card';
import Button from './Button';
import { ModelResults, PreprocessingStep } from '../types';

declare var Chart: any;

interface ResultsViewerProps {
    results: ModelResults;
    propertyName: string;
    preprocessingSteps: PreprocessingStep[];
    activeSamples: (string|number)[];
    onDeactivateOutliers: (outlierIds: (string|number)[]) => void;
    wavelengths: number[];
}

const ResultsViewer: React.FC<ResultsViewerProps> = ({ results, propertyName, preprocessingSteps, activeSamples, onDeactivateOutliers, wavelengths }) => {
    const [activeTab, setActiveTab] = useState('correlation');
    const chartRef = useRef<HTMLCanvasElement>(null);
    const chartInstanceRef = useRef<any>(null);
    const chartWrapperRef = useRef<HTMLDivElement>(null);

    const [rotation, setRotation] = useState({ x: -20, y: -30 });
    const isDragging = useRef(false);
    const lastMousePos = useRef({ x: 0, y: 0 });

    const handleMouseDown = (e: React.MouseEvent) => {
        isDragging.current = true;
        lastMousePos.current = { x: e.clientX, y: e.clientY };
        if (chartWrapperRef.current) chartWrapperRef.current.classList.add('grabbing');
    };

    const handleMouseUp = () => {
        isDragging.current = false;
        if (chartWrapperRef.current) chartWrapperRef.current.classList.remove('grabbing');
    };

    const handleMouseMove = (e: MouseEvent) => {
        if (!isDragging.current) return;
        const dx = e.clientX - lastMousePos.current.x;
        const dy = e.clientY - lastMousePos.current.y;

        setRotation(prev => {
            let newX = prev.x - dy * 0.5;
            newX = Math.max(-90, Math.min(90, newX)); // Clamp X rotation
            return {
                x: newX,
                y: prev.y + dx * 0.5,
            };
        });

        lastMousePos.current = { x: e.clientX, y: e.clientY };
    };

    useEffect(() => {
        window.addEventListener('mouseup', handleMouseUp);
        window.addEventListener('mousemove', handleMouseMove);

        return () => {
            window.removeEventListener('mouseup', handleMouseUp);
            window.removeEventListener('mousemove', handleMouseMove);
        };
    }, []);


    useEffect(() => {
        if (chartRef.current) {
            const ctx = chartRef.current.getContext('2d');
            if (ctx) {
                chartInstanceRef.current = new Chart(ctx, {
                    type: 'scatter',
                    data: { datasets: [] },
                    options: {
                        maintainAspectRatio: false,
                        responsive: true,
                        animation: false,
                        plugins: {
                            legend: { display: true }
                        },
                        scales: {
                            x: { title: { display: true, text: 'Valores Reales' } },
                            y: { title: { display: true, text: 'Valores Predichos' } }
                        }
                    }
                });
            }
        }
        return () => chartInstanceRef.current?.destroy();
    }, []);

    useEffect(() => {
        if (chartInstanceRef.current && results) {
            const { actual, predicted } = results.model.correlation;
            const inliersData: {x: number, y: number}[] = [];
            const outliersData: {x: number, y: number}[] = [];

            results.mahalanobis.distances.forEach((d, i) => {
                const point = { x: actual[i], y: predicted[i] };
                if (results.mahalanobis.outlierIds.includes(d.id)) outliersData.push(point);
                else inliersData.push(point);
            });

            const allValues = [...actual, ...predicted];
            const minVal = Math.min(...allValues);
            const maxVal = Math.max(...allValues);
            const padding = (maxVal - minVal) * 0.05;

            chartInstanceRef.current.data.datasets = [
                { label: 'Inliers', data: inliersData, backgroundColor: '#3B82F680', borderColor: '#3B82F6', pointRadius: 5 },
                { label: 'Outliers', data: outliersData, backgroundColor: '#EF444480', borderColor: '#EF4444', pointRadius: 7, pointStyle: 'rectRot' },
                { type: 'line', label: 'Línea y=x', data: [{x: minVal, y: minVal}, {x: maxVal, y: maxVal}], borderColor: '#9CA3AF', borderWidth: 2, borderDash: [5, 5], pointRadius: 0, fill: false }
            ];
            chartInstanceRef.current.options.scales.x.min = minVal - padding;
            chartInstanceRef.current.options.scales.x.max = maxVal + padding;
            chartInstanceRef.current.options.scales.y.min = minVal - padding;
            chartInstanceRef.current.options.scales.y.max = maxVal + padding;
            chartInstanceRef.current.update('none');
        }
    }, [results]);

    const handleExportConfig = () => {
        const config = {
            date: new Date().toISOString(),
            modelType: results.modelType,
            analyticalProperty: propertyName,
            activeSamples: activeSamples,
            preprocessing: preprocessingSteps,
            modelParameters: { lambda: results.lambda },
            modelMetrics: { r2: results.model.r2, rmsec: results.model.rmsec },
        };
        const dataStr = "data:text/json;charset=utf-8," + encodeURIComponent(JSON.stringify(config, null, 2));
        const downloadAnchorNode = document.createElement('a');
        downloadAnchorNode.setAttribute("href", dataStr);
        downloadAnchorNode.setAttribute("download", `spectra_pro_ridge_config.json`);
        document.body.appendChild(downloadAnchorNode);
        downloadAnchorNode.click();
        downloadAnchorNode.remove();
    };

    const handleDownloadData = () => {
        const headers = ['ID_Muestra', 'Valor_Real', 'Valor_Predicho', 'Residuo', ...wavelengths];
        const { residuals, processedSpectra } = results.model;
        const rows = residuals.map((res, index) => 
            [res.id, res.actual.toFixed(6), res.predicted.toFixed(6), res.residual.toFixed(6), ...processedSpectra[index].map(v => v.toFixed(6))]
        );
        const csvContent = [headers.join(','), ...rows.map(row => row.join(','))].join('\n');
        const blob = new Blob([csvContent], { type: 'text/csv;charset=utf-8;' });
        const url = URL.createObjectURL(blob);
        const link = document.createElement("a");
        link.setAttribute("href", url);
        link.setAttribute("download", "spectra_model_data.csv");
        document.body.appendChild(link);
        link.click();
        document.body.removeChild(link);
    };

    const residuals = results.model.residuals;
    const meanResidual = residuals.reduce((sum, r) => sum + r.residual, 0) / residuals.length;
    const stdDevResidual = Math.sqrt(residuals.reduce((sum, r) => sum + Math.pow(r.residual - meanResidual, 2), 0) / residuals.length);
    const residualOutlierThreshold = stdDevResidual * 2.5;

    const outliers = results.mahalanobis.distances.filter(d => d.isOutlier);
    const residualsMap: Map<string | number, (typeof residuals)[number]> = new Map(residuals.map((r) => [r.id, r]));
    const [selectedOutliers, setSelectedOutliers] = useState<Set<string|number>>(new Set());

    const handleOutlierSelection = (id: string|number, checked: boolean) => {
        setSelectedOutliers(prev => {
            const newSet = new Set(prev);
            if (checked) newSet.add(id);
            else newSet.delete(id);
            return newSet;
        });
    };

    const handleSelectAllOutliers = (checked: boolean) => {
        if(checked) {
            setSelectedOutliers(new Set(outliers.map(o => o.id)));
        } else {
            setSelectedOutliers(new Set());
        }
    };

    const handleDeactivateClick = () => {
        if (selectedOutliers.size === 0) {
            alert("Por favor, seleccione al menos un outlier para desactivar.");
            return;
        }
        onDeactivateOutliers(Array.from(selectedOutliers));
        setSelectedOutliers(new Set());
    };

    const TabButton = ({ tabId, label }: { tabId: string; label: React.ReactNode }) => (
        <button
            className={`px-4 py-2 text-sm font-medium rounded-t-lg border-b-2 transition-colors ${activeTab === tabId ? 'text-brand-primary border-brand-primary' : 'text-gray-500 border-transparent hover:text-gray-700 hover:border-gray-300'}`}
            onClick={() => setActiveTab(tabId)}
        >
            {label}
        </button>
    );

    return (
        <Card>
            <div className="flex border-b border-gray-200 mb-4">
                <TabButton tabId="correlation" label="Correlación" />
                <TabButton tabId="residuals" label="Residuos" />
                <TabButton tabId="outliers" label="Outliers" />
                <TabButton tabId="full-data" label="Datos Completos" />
            </div>

            {activeTab === 'correlation' && (
                <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
                    <div className="md:col-span-2 flex flex-col">
                        <p className="text-center text-xs text-gray-500 mb-2">Haga clic y arrastre el gráfico para rotarlo.</p>
                        <div ref={chartWrapperRef} onMouseDown={handleMouseDown} className="relative h-96 cursor-grab" style={{ perspective: '1200px', transformStyle: 'preserve-3d' }}>
                            <canvas ref={chartRef} style={{ transition: 'transform 0.1s linear', transform: `rotateX(${rotation.x}deg) rotateY(${rotation.y}deg)` }}></canvas>
                        </div>
                    </div>
                    <div className="flex flex-col justify-center space-y-2">
                        <h3 className="font-semibold text-lg mb-2">Métricas del Modelo</h3>
                        <p className="text-sm text-gray-600">Propiedad: <span className="font-semibold text-gray-900">{propertyName}</span></p>
                        <p className="text-sm text-gray-600">Lambda (λ): <span className="font-mono text-brand-primary text-base">{results.lambda?.toExponential(2)}</span></p>
                        <hr className="my-2 border-gray-200" />
                        <p className="text-sm text-gray-600">R² (Calibración): <span className="font-mono text-brand-primary text-base">{results.model.r2.toFixed(4)}</span></p>
                        <p className="text-sm text-gray-600">RMSEC: <span className="font-mono text-brand-primary text-base">{results.model.rmsec.toFixed(4)}</span></p>
                        <div className="pt-4">
                            <Button variant="secondary" onClick={handleExportConfig} className="w-full">Exportar Configuración</Button>
                        </div>
                    </div>
                </div>
            )}

            {activeTab === 'residuals' && (
                 <div>
                    <h3 className="font-semibold text-lg mb-2">Análisis de Residuos del Modelo</h3>
                    <p className="text-sm text-gray-500 mb-4">Las muestras con residuos altos (resaltadas) pueden ser outliers de predicción.</p>
                    <div className="max-h-96 overflow-y-auto pr-2 border rounded-md">
                        <table className="w-full text-sm text-left">
                            <thead className="text-xs text-gray-500 uppercase bg-gray-100 sticky top-0">
                                <tr>
                                    <th scope="col" className="px-4 py-2">ID Muestra</th>
                                    <th scope="col" className="px-4 py-2">Valor Real</th>
                                    <th scope="col" className="px-4 py-2">Valor Predicho</th>
                                    <th scope="col" className="px-4 py-2">Residuo</th>
                                </tr>
                            </thead>
                            <tbody>
                                {residuals.map(r => {
                                    const isOutlier = Math.abs(r.residual) > residualOutlierThreshold;
                                    return (
                                        <tr key={r.id} className={`${isOutlier ? 'bg-red-50' : ''} border-b border-gray-200 last:border-b-0`}>
                                            <td className="px-4 py-2 font-medium">{r.id}</td>
                                            <td className="px-4 py-2 font-mono">{r.actual.toFixed(4)}</td>
                                            <td className="px-4 py-2 font-mono">{r.predicted.toFixed(4)}</td>
                                            <td className={`px-4 py-2 font-mono ${isOutlier ? 'text-red-600 font-bold' : ''}`}>{r.residual.toFixed(4)}</td>
                                        </tr>
                                    );
                                })}
                            </tbody>
                        </table>
                    </div>
                 </div>
            )}

            {activeTab === 'outliers' && (
                 <div>
                    <h3 className="font-semibold text-lg mb-2">Análisis de Outliers (Distancia de Mahalanobis)</h3>
                    <p className="text-sm text-gray-500 mb-4">Muestras espectralmente anómalas (Distancia > 3.0). Seleccione las que desea desactivar del modelo.</p>
                     {outliers.length === 0 ? (
                        <p className="text-center text-gray-500 p-8">No se detectaron outliers espectrales en este modelo.</p>
                     ) : (
                        <>
                            <div className="max-h-96 overflow-y-auto pr-2 mb-4 border border-gray-200 rounded-md">
                                <table className="w-full text-sm text-left">
                                    <thead className="text-xs text-gray-500 uppercase bg-gray-100 sticky top-0">
                                        <tr>
                                            <th scope="col" className="px-4 py-2 w-12"><input type="checkbox" onChange={e => handleSelectAllOutliers(e.target.checked)} className="form-checkbox h-4 w-4 rounded text-brand-primary border-gray-300 focus:ring-brand-primary" /></th>
                                            <th scope="col" className="px-4 py-2">ID Muestra</th>
                                            <th scope="col" className="px-4 py-2">Distancia (GH)</th>
                                            <th scope="col" className="px-4 py-2">Valor Real</th>
                                            <th scope="col" className="px-4 py-2">Valor Predicho</th>
                                            <th scope="col" className="px-4 py-2">Residuo</th>
                                        </tr>
                                    </thead>
                                    <tbody>
                                        {outliers.map(outlier => {
                                            const resData = residualsMap.get(outlier.id);
                                            return(
                                            <tr key={outlier.id} className="border-b border-gray-200 hover:bg-gray-50">
                                                <td className="px-4 py-2"><input type="checkbox" checked={selectedOutliers.has(outlier.id)} onChange={e => handleOutlierSelection(outlier.id, e.target.checked)} className="form-checkbox h-4 w-4 rounded text-brand-primary border-gray-300 focus:ring-brand-primary" /></td>
                                                <td className="px-4 py-2 font-semibold">{outlier.id}</td>
                                                <td className="px-4 py-2 font-mono text-red-600">{outlier.distance.toFixed(4)}</td>
                                                <td className="px-4 py-2 font-mono">{resData ? resData.actual.toFixed(4) : 'N/A'}</td>
                                                <td className="px-4 py-2 font-mono">{resData ? resData.predicted.toFixed(4) : 'N/A'}</td>
                                                <td className="px-4 py-2 font-mono">{resData ? resData.residual.toFixed(4) : 'N/A'}</td>
                                            </tr>
                                            );
                                        })}
                                    </tbody>
                                </table>
                            </div>
                            <Button onClick={handleDeactivateClick} className="w-full max-w-sm mx-auto">Desactivar Seleccionados y Recalcular</Button>
                        </>
                     )}
                </div>
            )}

            {activeTab === 'full-data' && (
                <div>
                     <h3 className="font-semibold text-lg mb-2">Datos Completos del Modelo y Espectros</h3>
                     <p className="text-sm text-gray-500 mb-4">Tabla con los datos utilizados para generar el modelo de correlación. La tabla es desplazable horizontalmente.</p>
                     <Button onClick={handleDownloadData} className="mb-4">Descargar Datos (CSV)</Button>
                     <div className="max-h-96 overflow-auto border border-gray-200 rounded-md">
                         <table className="w-full text-sm text-left whitespace-nowrap">
                             <thead className="text-xs text-gray-500 uppercase bg-gray-100 sticky top-0">
                                 <tr>
                                     <th scope="col" className="px-4 py-2 sticky left-0 bg-gray-100 z-10">ID Muestra</th>
                                     <th scope="col" className="px-4 py-2">Valor Real</th>
                                     <th scope="col" className="px-4 py-2">Valor Predicho</th>
                                     <th scope="col" className="px-4 py-2">Residuo</th>
                                     {wavelengths.map(wl => <th key={wl} scope="col" className="px-4 py-2 font-mono">{wl}</th>)}
                                 </tr>
                             </thead>
                             <tbody>
                                 {results.model.residuals.map((res, index) => (
                                     <tr key={res.id} className="border-b border-gray-200 bg-white">
                                         <td className="px-4 py-2 sticky left-0 bg-white font-semibold z-10">{res.id}</td>
                                         <td className="px-4 py-2 font-mono">{res.actual.toFixed(4)}</td>
                                         <td className="px-4 py-2 font-mono">{res.predicted.toFixed(4)}</td>
                                         <td className="px-4 py-2 font-mono">{res.residual.toFixed(4)}</td>
                                         {results.model.processedSpectra[index].map((val, i) => <td key={i} className="px-4 py-2 font-mono">{val.toFixed(4)}</td>)}
                                     </tr>
                                 ))}
                             </tbody>
                         </table>
                     </div>
                </div>
            )}
        </Card>
    );
};

export default ResultsViewer;

import React, { useState, useCallback } from 'react';
import { Sample, PreprocessingStep, ModelResults } from './types';
import { parseCSV, DEMO_DATA_STRING } from './services/csvParser';
import { runRidgeRegression, applyPreprocessingLogic } from './services/chemometrics';
import Header from './components/Header';
import Loader from './components/Loader';
import DataUploader from './components/DataUploader';
import SampleManager from './components/SampleManager';
import SpectraViewer from './components/SpectraViewer';
import PreprocessingEditor from './components/PreprocessingEditor';
import ModelGenerator, { ModelParams } from './components/ModelGenerator';
import ResultsViewer from './components/ResultsViewer';
import Card from './components/Card';

const App: React.FC = () => {
    const [loadingMessage, setLoadingMessage] = useState<string | null>(null);
    const [wavelengths, setWavelengths] = useState<number[]>([]);
    const [samples, setSamples] = useState<Sample[]>([]);
    const [analyticalProperty, setAnalyticalProperty] = useState<string>('Propiedad');
    const [preprocessingSteps, setPreprocessingSteps] = useState<PreprocessingStep[]>([]);
    const [modelResults, setModelResults] = useState<ModelResults | null>(null);
    const [processedSpectra, setProcessedSpectra] = useState<{ id: string | number; values: number[] }[] | null>(null);

    const handleDataLoaded = (data: { wavelengths: number[]; samples: Sample[]; analyticalProperty: string }) => {
        setWavelengths(data.wavelengths);
        setSamples(data.samples);
        setAnalyticalProperty(data.analyticalProperty);
        setModelResults(null);
        setProcessedSpectra(null);
        setPreprocessingSteps([]);
    };

    const handleFileSelected = (file: File) => {
        setLoadingMessage('Cargando datos...');
        parseCSV(file, (results) => {
            handleDataLoaded(results);
            setLoadingMessage(null);
        });
    };

    const handleLoadDemoData = () => {
        setLoadingMessage('Cargando datos de demostración...');
        // Simulate async loading for UX
        setTimeout(() => {
            parseCSV(DEMO_DATA_STRING, (results) => {
                handleDataLoaded(results);
                setLoadingMessage(null);
            });
        }, 100);
    };

    const handleToggleSample = (index: number) => {
        setSamples(prev => prev.map((s, i) => i === index ? { ...s, active: !s.active } : s));
    };

    const handleToggleAllSamples = (active: boolean) => {
        setSamples(prev => prev.map(s => ({ ...s, active })));
    };

    const handleVisualizePreprocessing = () => {
        const activeSamples = samples.filter(s => s.active);
        if (activeSamples.length === 0) return;
        const processed = activeSamples.map(sample => ({
            ...sample,
            values: applyPreprocessingLogic(sample.values, preprocessingSteps)
        }));
        setProcessedSpectra(processed);
    };

    const handleResetVisualization = useCallback(() => {
        setProcessedSpectra(null);
    }, []);

    const handleRunModel = async (params: ModelParams) => {
        const activeSamples = samples.filter(s => s.active);
        if (activeSamples.length < 2) {
            alert('Se necesitan al menos 2 muestras activas para generar el modelo.');
            return;
        }
        setLoadingMessage(`Generando modelo ${params.type.toUpperCase()}...`);
        await new Promise(resolve => setTimeout(resolve, 50)); 
        try {
            // Only Ridge is supported now
            const results = runRidgeRegression(activeSamples, preprocessingSteps, params.lambda);
            setModelResults(results);
        } catch (error) {
            console.error(`Error during ${params.type} run:`, error);
            const errorMessage = error instanceof Error ? error.message : "Ocurrió un error desconocido.";
            alert(`Ocurrió un error al generar el modelo: ${errorMessage}`);
        } finally {
            setLoadingMessage(null);
        }
    };

    const handleDeactivateOutliers = (outlierIds: (string|number)[]) => {
         setSamples(prev => prev.map(s => outlierIds.includes(s.id) ? { ...s, active: false } : s));
         // Automatically rerun model after deactivating
         setTimeout(() => {
            if (!modelResults) return;
            const params: ModelParams = { type: 'ridge', lambda: modelResults.lambda! };
            handleRunModel(params);
         }, 100);
    }

    const activeSamples = samples.filter(s => s.active);
    const spectraToDisplay = processedSpectra ? processedSpectra.map(p => {
        const originalSample = samples.find(s => s.id === p.id);
        return { ...p, color: originalSample?.color || '#000000' };
    }) : activeSamples;

    return (
        <>
            {loadingMessage && <Loader message={loadingMessage} />}
            <div className="min-h-screen flex flex-col bg-gray-50 text-gray-800">
                <Header />
                <main className="flex-grow p-4 lg:p-6 grid grid-cols-1 xl:grid-cols-4 gap-4 lg:gap-6">
                    {/* Controls Column */}
                    <div className="xl:col-span-1 flex flex-col gap-4 lg:gap-6">
                        <DataUploader onFileSelected={handleFileSelected} onLoadDemo={handleLoadDemoData} />
                        <SampleManager
                            samples={samples}
                            onToggle={handleToggleSample}
                            onToggleAll={handleToggleAllSamples}
                        />
                    </div>

                    {/* Visualization and Model Column */}
                    <div className="xl:col-span-3 flex flex-col gap-4 lg:gap-6">
                        <SpectraViewer
                            wavelengths={wavelengths}
                            samples={spectraToDisplay}
                            isProcessed={!!processedSpectra}
                            onReset={handleResetVisualization}
                        />
                        {/* PCA Analyzer module removed */}

                        <PreprocessingEditor
                            steps={preprocessingSteps}
                            setSteps={setPreprocessingSteps}
                            onVisualize={handleVisualizePreprocessing}
                            disabled={activeSamples.length === 0}
                        />
                        <ModelGenerator onRunModel={handleRunModel} disabled={activeSamples.length < 2} />

                        {modelResults ? (
                            <ResultsViewer 
                                results={modelResults}
                                propertyName={analyticalProperty}
                                preprocessingSteps={preprocessingSteps}
                                activeSamples={activeSamples.map(s => s.id)}
                                onDeactivateOutliers={handleDeactivateOutliers}
                                wavelengths={wavelengths}
                            />
                        ) : (
                            <Card>
                                <div className="flex items-center justify-center h-40">
                                    <p className="text-gray-400">Genere un modelo para ver los resultados.</p>
                                </div>
                            </Card>
                        )}
                    </div>
                </main>
            </div>
        </>
    );
};

export default App;

export interface Sample {
    id: string | number;
    values: number[];
    color: string;
    active: boolean;
    analyticalValue: number;
}

export interface PcaResult {
    id: string | number;
    x: number;
    y: number;
    color: string;
}

export interface PreprocessingStep {
    method: 'none' | 'savgol' | 'snv' | 'msc' | 'detrend';
    params: { [key: string]: any };
}

export interface ModelResults {
    modelType: 'Ridge';
    lambda?: number;
    mahalanobis: {
        distances: { id: string | number; distance: number; isOutlier: boolean }[];
        outlierIds: (string | number)[];
    };
    model: {
        r2: number;
        rmsec: number;
        correlation: {
            actual: number[];
            predicted: number[];
        };
        residuals: { id: string | number; actual: number; predicted: number; residual: number }[];
        processedSpectra: number[][];
    };
}

export interface Sample {
    id: string | number;
    values: number[];
    color: string;
    active: boolean;
    analyticalValue: number;
}

export interface PreprocessingStep {
    method: 'none' | 'savgol' | 'snv' | 'msc' | 'detrend';
    params: { [key: string]: any };
}

import { PreprocessingStep } from '../types';

// ===============================================

function savitzkyGolay(data: number[], options: { windowSize: number; polynomial: number; derivative?: number }): number[] {
    const { windowSize, polynomial, derivative = 0 } = options;
    if (windowSize % 2 === 0 || windowSize < 3 || polynomial >= windowSize || derivative > polynomial) {
        console.warn("Invalid Savitzky-Golay parameters, returning original data.", options);
        return data;
    }

    const halfWindow = Math.floor(windowSize / 2);
    const mlMatrix = (window as any).mlMatrix;
    if (!mlMatrix) {
        console.error("mlMatrix library not loaded");
        return data;
    }
    const { Matrix } = mlMatrix;

    try {
        let A = new Matrix(windowSize, polynomial + 1);
        for (let i = 0; i < windowSize; i++) {
            for (let j = 0; j <= polynomial; j++) {
                A.set(i, j, Math.pow(i - halfWindow, j));
            }
        }

        const C = Matrix.solve(A.transpose().mmul(A), A.transpose());

        const fact = (n: number) => { let r = 1; for (let i = 2; i <= n; i++) r *= i; return r; };
        const sgCoefficients = C.getRow(derivative).map((v: number) => v * fact(derivative));
        const reversedCoeffs = sgCoefficients.slice().reverse();

        const result = new Array(data.length);
        for (let i = 0; i < data.length; i++) {
            if (i < halfWindow || i >= data.length - halfWindow) {
                result[i] = data[i]; // Keep edges as they are
            } else {
                let convSum = 0;
                for (let j = 0; j < windowSize; j++) {
                    convSum += data[i - halfWindow + j] * reversedCoeffs[j];
                }
                result[i] = convSum;
            }
        }
        return result;
    } catch (e) {
        console.error("Error in Savitzky-Golay matrix calculation:", e);
        return data;
    }
}


export function applyPreprocessingLogic(inputSpectrum: number[], steps: PreprocessingStep[]): number[] {
    let processedSpectrum = [...inputSpectrum];

    steps.forEach(step => {
        const n = processedSpectrum.length;
        if (n === 0) return;

        switch (step.method) {
            case 'snv': {
                const mean = processedSpectrum.reduce((a, b) => a + b, 0) / n;
                const stdDev = Math.sqrt(processedSpectrum.map(x => Math.pow(x - mean, 2)).reduce((a, b) => a + b, 0) / (n - 1));
                if (stdDev > 0) {
                    processedSpectrum = processedSpectrum.map(x => (x - mean) / stdDev);
                }
                break;
            }
            case 'savgol': { 
                const { derivative = 1, windowSize = 5, polynomialOrder = 2 } = step.params;
                processedSpectrum = savitzkyGolay(processedSpectrum, { windowSize: parseInt(String(windowSize)), polynomial: parseInt(String(polynomialOrder)), derivative: parseInt(String(derivative)) });
                break;
            }
            case 'detrend': {
                 if (n < 2) break;
                 const x = Array.from({length: n}, (_, i) => i);
                 const sumX = x.reduce((a, b) => a + b, 0);
                 const sumY = processedSpectrum.reduce((a, b) => a + b, 0);
                 const sumXY = x.map((xi, i) => xi * processedSpectrum[i]).reduce((a, b) => a + b, 0);
                 const sumX2 = x.map(xi => xi * xi).reduce((a, b) => a + b, 0);
                 const slope = (n * sumXY - sumX * sumY) / (n * sumX2 - sumX * sumX);
                 const intercept = (sumY - slope * sumX) / n;
                 if(!isNaN(slope) && !isNaN(intercept)) {
                    processedSpectrum = processedSpectrum.map((y, i) => y - (slope * i + intercept));
                 }
                 break;
            }
        }
    });

    return processedSpectrum;
}

import React, { useState, useCallback } from 'react';
import { Sample, PreprocessingStep } from './types';
import { parseCSV, DEMO_DATA_STRING } from './services/csvParser';
import { applyPreprocessingLogic } from './services/chemometrics';
import Header from './components/Header';
import Loader from './components/Loader';
import DataUploader from './components/DataUploader';
import SampleManager from './components/SampleManager';
import SpectraViewer from './components/SpectraViewer';
import PreprocessingEditor from './components/PreprocessingEditor';

const App: React.FC = () => {
    const [loadingMessage, setLoadingMessage] = useState<string | null>(null);
    const [wavelengths, setWavelengths] = useState<number[]>([]);
    const [samples, setSamples] = useState<Sample[]>([]);
    const [preprocessingSteps, setPreprocessingSteps] = useState<PreprocessingStep[]>([]);
    const [processedSpectra, setProcessedSpectra] = useState<{ id: string | number; values: number[] }[] | null>(null);

    const handleDataLoaded = (data: { wavelengths: number[]; samples: Sample[]; analyticalProperty: string }) => {
        setWavelengths(data.wavelengths);
        setSamples(data.samples);
        setProcessedSpectra(null);
        setPreprocessingSteps([]);
    };

    const handleFileSelected = (file: File) => {
        setLoadingMessage('Cargando datos...');
        parseCSV(file, (results) => {
            handleDataLoaded(results);
            setLoadingMessage(null);
        });
    };

    const handleLoadDemoData = () => {
        setLoadingMessage('Cargando datos de demostración...');
        // Simulate async loading for UX
        setTimeout(() => {
            parseCSV(DEMO_DATA_STRING, (results) => {
                handleDataLoaded(results);
                setLoadingMessage(null);
            });
        }, 100);
    };

    const handleToggleSample = (index: number) => {
        setSamples(prev => prev.map((s, i) => i === index ? { ...s, active: !s.active } : s));
    };

    const handleToggleAllSamples = (active: boolean) => {
        setSamples(prev => prev.map(s => ({ ...s, active })));
    };

    const handleVisualizePreprocessing = () => {
        const activeSamples = samples.filter(s => s.active);
        if (activeSamples.length === 0) return;
        const processed = activeSamples.map(sample => ({
            ...sample,
            values: applyPreprocessingLogic(sample.values, preprocessingSteps)
        }));
        setProcessedSpectra(processed);
    };

    const handleResetVisualization = useCallback(() => {
        setProcessedSpectra(null);
    }, []);

    const activeSamples = samples.filter(s => s.active);
    const spectraToDisplay = processedSpectra ? processedSpectra.map(p => {
        const originalSample = samples.find(s => s.id === p.id);
        return { ...p, color: originalSample?.color || '#000000' };
    }) : activeSamples;

    return (
        <>
            {loadingMessage && <Loader message={loadingMessage} />}
            <div className="min-h-screen flex flex-col bg-gray-50 text-gray-800">
                <Header />
                <main className="flex-grow p-4 lg:p-6 grid grid-cols-1 xl:grid-cols-4 gap-4 lg:gap-6">
                    {/* Controls Column */}
                    <div className="xl:col-span-1 flex flex-col gap-4 lg:gap-6">
                        <DataUploader onFileSelected={handleFileSelected} onLoadDemo={handleLoadDemoData} />
                        <SampleManager
                            samples={samples}
                            onToggle={handleToggleSample}
                            onToggleAll={handleToggleAllSamples}
                        />
                    </div>

                    {/* Visualization Column */}
                    <div className="xl:col-span-3 flex flex-col gap-4 lg:gap-6">
                        <SpectraViewer
                            wavelengths={wavelengths}
                            samples={spectraToDisplay}
                            isProcessed={!!processedSpectra}
                            onReset={handleResetVisualization}
                        />

                        <PreprocessingEditor
                            steps={preprocessingSteps}
                            setSteps={setPreprocessingSteps}
                            onVisualize={handleVisualizePreprocessing}
                            disabled={activeSamples.length === 0}
                        />
                    </div>
                </main>
            </div>
        </>
    );
};

export default App;

