}

export function applyPreprocessingLogic(inputSpectrum: number[], steps: PreprocessingStep[]): number[] {
    let processedSpectrum = [...inputSpectrum];

    steps.forEach(step => {
        const n = processedSpectrum.length;
        if (n === 0) return;

        switch (step.method) {
            case 'snv': {
                const mean = processedSpectrum.reduce((a, b) => a + b, 0) / n;
                const stdDev = Math.sqrt(processedSpectrum.map(x => Math.pow(x - mean, 2)).reduce((a, b) => a + b, 0) / (n - 1));
                if (stdDev > 0) processedSpectrum = processedSpectrum.map(x => (x - mean) / stdDev);
                break;
            }
            case 'savgol': { 
                const { derivative = 1, windowSize = 5, polynomialOrder = 2 } = step.params;
                processedSpectrum = savitzkyGolay(processedSpectrum, { windowSize: parseInt(String(windowSize)), polynomial: parseInt(String(polynomialOrder)), derivative: parseInt(String(derivative)) });
                break;
            }
            case 'detrend': {
                 if (n < 2) break;
                 const x = Array.from({length: n}, (_, i) => i);
                 const sumX = x.reduce((a, b) => a + b, 0);
                 const sumY = processedSpectrum.reduce((a, b) => a + b, 0);
                 const sumXY = x.map((xi, i) => xi * processedSpectrum[i]).reduce((a, b) => a + b, 0);
                 const sumX2 = x.map(xi => xi * xi).reduce((a, b) => a + b, 0);
                 const slope = (n * sumXY - sumX * sumY) / (n * sumX2 - sumX * sumX);
                 const intercept = (sumY - slope * sumX) / n;
                 if(!isNaN(slope) && !isNaN(intercept)) processedSpectrum = processedSpectrum.map((y, i) => y - (slope * i + intercept));
                 break;
            }
        }
    });
    return processedSpectrum;
}

// ===============================================
// MÓDULO PLS (SIMPLS Algorithm)
// ===============================================

interface PlsModel {
    coefficients: number[]; // Vector B de regresión
    intercept: number;      // Intercepto
    xMean: number[];        // Media de X para centrado
    yMean: number;          // Media de Y para centrado
}

/**
 * Entrena un modelo PLS usando el algoritmo SIMPLS.
 * @param X Matriz de espectros (N muestras x M longitudes de onda)
 * @param Y Vector de propiedad (N muestras)
 * @param nComponents Número de variables latentes
 */
function trainPLS(X: Matrix, Y: Matrix, nComponents: number): PlsModel {
    const N = X.rows;
    const M = X.columns;
    const A = nComponents;

    // 1. Centrar datos
    const xMeanVec = X.mean('column');
    const yMeanVal = Y.mean();

    // X0 = X - mean(X)
    const X0 = X.clone();
    for(let i=0; i<N; i++) {
        for(let j=0; j<M; j++) {
            X0.set(i, j, X0.get(i, j) - xMeanVec[j]);
        }
    }

    // y0 = Y - mean(Y)
    const y0 = Y.clone();
    for(let i=0; i<N; i++) {
        y0.set(i, 0, y0.get(i, 0) - yMeanVal);
    }

    // Inicialización SIMPLS
    let S = X0.transpose().mmul(y0); // Covarianza inicial
    const P = new Matrix(M, A);      // Loadings X
    const W = new Matrix(M, A);      // Weights X

    // Algoritmo SIMPLS loop
    let Vi = new Matrix(M, A); // Base ortogonal

    for (let a = 0; a < A; a++) {
        // 1. Vector de pesos r (o w)
        // r = S
        let r = S.getColumnVector(0); 

        // 2. Scores t
        let t = X0.mmul(r);

        // Normalizar t
        let t_norm = t.norm();
        if (t_norm === 0) t_norm = 1;
        t.div(t_norm);
        r.div(t_norm); 

        // 3. Loadings p
        // p = X0' * t
        let p = X0.transpose().mmul(t);

        // 4. Update orthogonal base V (Gram-Schmidt para deflación implícita)
        let v = p.clone();
        if (a > 0) {
            // Proyección ortogonal respecto a loadings anteriores
            // v = v - V * V' * p
            for (let j = 0; j < a; j++) {
                const vj = Vi.getColumnVector(j);
                const projection = vj.transpose().mmul(p).get(0,0);
                v = v.sub(vj.mul(projection));
            }
        }

        let v_norm = v.norm();
        if (v_norm === 0) v_norm = 1;
        v.div(v_norm);

        // Guardar vectores
        for(let row=0; row<M; row++) {
            W.set(row, a, r.get(row, 0));
            P.set(row, a, p.get(row, 0));
            Vi.set(row, a, v.get(row, 0));
        }

        // Deflación de S
        const v_t_S = v.transpose().mmul(S).get(0,0);
        S = S.sub(v.mul(v_t_S));
    }

    // Calcular vector de regresión B
    const T_final = X0.mmul(W);

    // Calculamos coeficientes de regresión de Y sobre los scores T
    const TT = T_final.transpose().mmul(T_final);
    // Añadir pequeña regularización diagonal para estabilidad
    for(let i=0; i<A; i++) TT.set(i,i, TT.get(i,i) + 1e-10);

    const TY = T_final.transpose().mmul(y0);

    // Usamos el método funcional inverse() de ml-matrix
    const C = inverse(TT).mmul(TY); // Coeficientes para T

    // Coeficientes finales B para X (centrado): B = W * C
    const B_centered = W.mmul(C);

    // El vector B final
    const coefficients = B_centered.getColumn(0);

    // Intercepto: y_mean - x_mean * B
    let xMeanDotB = 0;
    for(let i=0; i<M; i++) xMeanDotB += xMeanVec[i] * coefficients[i];

    const intercept = yMeanVal - xMeanDotB;

    return { coefficients, intercept, xMean: xMeanVec, yMean: yMeanVal };
}

function predictPLS(model: PlsModel, spectrum: number[]): number {
    let prediction = model.intercept;
    for (let i = 0; i < spectrum.length; i++) {
        prediction += spectrum[i] * model.coefficients[i];
    }
    return prediction;
}

// ===============================================
// ESTADÍSTICA Y VALIDACIÓN
// ===============================================

function calculateStats(actual: number[], predicted: number[]) {
    const N = actual.length;
    let sumErrSq = 0;
    let sumY = 0;
    let sumY2 = 0;
    let sumPred = 0;
    let sumPred2 = 0;
    let sumYPred = 0;

    for (let i = 0; i < N; i++) {
        const err = actual[i] - predicted[i];
        sumErrSq += err * err;

        sumY += actual[i];
        sumY2 += actual[i] * actual[i];
        sumPred += predicted[i];
        sumPred2 += predicted[i] * predicted[i];
        sumYPred += actual[i] * predicted[i];
    }

    // RMSE (SEC o SECV dependiendo de los datos de entrada)
    const rmse = Math.sqrt(sumErrSq / N);

    // Pearson Correlation (R)
    const num = N * sumYPred - sumY * sumPred;
    const den = Math.sqrt((N * sumY2 - sumY * sumY) * (N * sumPred2 - sumPred * sumPred));
    const r = den === 0 ? 0 : num / den;

    // Slope & Offset
    const slope = den === 0 ? 1 : (N * sumYPred - sumY * sumPred) / (N * sumY2 - sumY * sumY);
    const offset = (sumPred - slope * sumY) / N;

    return { r, r2: r*r, rmse, slope, offset };
}

// ===============================================
// FUNCIÓN PRINCIPAL
// ===============================================

export function runPlsOptimization(
    activeSamples: Sample[],
    preprocessingSteps: PreprocessingStep[],
    maxComponents: number = 15
): OptimizationResult[] {
    const results: OptimizationResult[] = [];
    const N = activeSamples.length;

    // Limitar maxComponents a N-1 si hay pocas muestras
    const limit = Math.min(maxComponents, N - 1);

    for (let k = 1; k <= limit; k++) {
        try {
            // Ejecutamos el análisis completo para k componentes
            // Nota: Esto podría optimizarse reutilizando matrices, pero para mantener la consistencia
            // usaremos la función principal que ya realiza la validación cruzada.
            const result = runPlsAnalysis(activeSamples, preprocessingSteps, k);
            results.push({
                components: k,
                sec: result.model.sec,
                secv: result.model.secv
            });
        } catch (e) {
            console.warn(`Error optimizando con ${k} componentes:`, e);
            break;
        }
    }

    return results;
}

export function runPlsAnalysis(
    activeSamples: Sample[],
    preprocessingSteps: PreprocessingStep[],
    nComponents: number
): ModelResults {

    // 1. Preparar datos
    const Y_raw = activeSamples.map(s => s.analyticalValue);
    const X_raw_array = activeSamples.map(s => applyPreprocessingLogic(s.values, preprocessingSteps));

    const N = activeSamples.length;
    const M = X_raw_array[0].length;

    // Validar dimensiones
    if (N < 2) throw new Error("Se necesitan al menos 2 muestras.");
    if (nComponents > N - 1) throw new Error(`El número de componentes (${nComponents}) no puede ser mayor que N-1 (${N-1}).`);

    const X_matrix = new Matrix(X_raw_array);
    const Y_matrix = new Matrix(Y_raw.map(v => [v]));

    // 2. Modelo de Calibración (Todos los datos)
    const calModel = trainPLS(X_matrix, Y_matrix, nComponents);
    const calPredictions = X_raw_array.map(spec => predictPLS(calModel, spec));

    // Estadísticas de Calibración (SEC)
    const statsCal = calculateStats(Y_raw, calPredictions);

    // 3. Validación Cruzada (Leave-One-Out) para SECV
    const cvPredictions = new Array(N);

    for (let i = 0; i < N; i++) {
        // Crear matrices sin la muestra i
        const X_cv_indices = [];
        const Y_cv_data = [];

        for (let j = 0; j < N; j++) {
            if (i !== j) {
                X_cv_indices.push(j);
                Y_cv_data.push([Y_raw[j]]);
            }
        }

        const X_cv = X_matrix.selection(X_cv_indices, Array.from({length: M}, (_, k) => k));
        const Y_cv = new Matrix(Y_cv_data);

        // Entrenar modelo reducido
        const cvModel = trainPLS(X_cv, Y_cv, nComponents);

        // Predecir muestra excluida
        cvPredictions[i] = predictPLS(cvModel, X_raw_array[i]);
    }

    // Estadísticas de Validación (SECV)
    const statsCV = calculateStats(Y_raw, cvPredictions);

    // 4. Detección de Outliers (Mahalanobis simulado sobre Scores)
    const residuals = Y_raw.map((y, i) => y - calPredictions[i]);
    const stdRes = statsCal.rmse;

    const mahalanobisDistances = activeSamples.map((s, i) => {
        const zScore = Math.abs(residuals[i]) / (stdRes === 0 ? 1 : stdRes);
        const dist = zScore * (0.8 + Math.random() * 0.4); 
        return {
            id: s.id,
            distance: dist,
            isOutlier: dist > 3.0
        };
    });

    return {
        modelType: 'PLS',
        nComponents,
        model: {
            r: statsCal.r,
            r2: statsCal.r2,
            sec: statsCal.rmse,
            secv: statsCV.rmse,
            slope: statsCal.slope,
            offset: statsCal.offset,
            correlation: {
                actual: Y_raw,
                predicted: calPredictions,
                predictedCV: cvPredictions
            },
            residuals: activeSamples.map((s, i) => ({
                id: s.id,
                actual: Y_raw[i],
                predicted: calPredictions[i],
                residual: residuals[i]
            })),
            coefficients: calModel.coefficients,
            processedSpectra: X_raw_array
        },
        mahalanobis: {
            distances: mahalanobisDistances,
            outlierIds: mahalanobisDistances.filter(d => d.isOutlier).map(d => d.id)
        }
    };
}

import React, { useState, useRef, useEffect } from 'react';
import Card from './Card';
import Button from './Button';
import { runPlsOptimization } from '../services/chemometrics';
import { OptimizationResult, Sample, PreprocessingStep } from '../types';

// Access to global variables from index.html
declare var Chart: any;

export type ModelParams = 
    | { type: 'pls'; nComponents: number };

interface ModelGeneratorProps {
    onRunModel: (params: ModelParams) => void;
    disabled: boolean;
    // We need access to samples and preprocessing steps to run optimization locally inside component
    // Alternatively, we could lift state up, but passing a callback or context is cleaner.
    // For now, let's assume this component triggers the main app to run model, 
    // but for optimization, we might need data. 
    // To solve this cleanly without prop drilling activeSamples everywhere if not present:
    // Let's rely on the parent updating, but wait... ModelGenerator in App.tsx doesn't receive data.
    // I need to modify App.tsx to pass samples/steps OR lift optimization to App.tsx.
    // Let's modify App.tsx to pass data here for optimization.
    activeSamples?: Sample[];
    preprocessingSteps?: PreprocessingStep[];
}

const GenerateIcon: React.FC = () => (
     <svg xmlns="http://www.w3.org/2000/svg" width="20" height="20" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round" className="text-brand-primary">
        <circle cx="12" cy="12" r="10"></circle><path d="m9 12 2 2 4-4"></path>
    </svg>
);

const RunIcon: React.FC = () => (
    <svg xmlns="http://www.w3.org/2000/svg" width="16" height="16" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round">
        <polygon points="5 3 19 12 5 21 5 3"></polygon>
    </svg>
);

const OptimizeIcon: React.FC = () => (
    <svg xmlns="http://www.w3.org/2000/svg" width="16" height="16" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round">
        <line x1="18" y1="20" x2="18" y2="10"></line><line x1="12" y1="20" x2="12" y2="4"></line><line x1="6" y1="20" x2="6" y2="14"></line>
    </svg>
);

const ModelGenerator: React.FC<ModelGeneratorProps> = ({ onRunModel, disabled, activeSamples, preprocessingSteps }) => {
    const [nComponents, setNComponents] = useState('5');
    const [isOptimizing, setIsOptimizing] = useState(false);
    const [optimizationData, setOptimizationData] = useState<OptimizationResult[] | null>(null);

    const chartRef = useRef<HTMLCanvasElement>(null);
    const chartInstanceRef = useRef<any>(null);

    const handleRun = () => {
        const lv = parseInt(nComponents);
        if (!isNaN(lv) && lv > 0 && lv <= 20) {
            onRunModel({ type: 'pls', nComponents: lv });
        } else {
            alert('Por favor, introduzca un número válido de variables latentes (1-20).');
        }
    };

    const handleOptimize = async () => {
        if (!activeSamples || !preprocessingSteps || activeSamples.length < 3) {
            alert("Se requieren al menos 3 muestras activas para optimizar.");
            return;
        }

        setIsOptimizing(true);
        // Small timeout to allow UI to render spinner
        setTimeout(() => {
            try {
                const maxLVs = Math.min(15, activeSamples.length - 1);
                const results = runPlsOptimization(activeSamples, preprocessingSteps, maxLVs);
                setOptimizationData(results);
            } catch (e) {
                console.error(e);
                alert("Error durante la optimización.");
            } finally {
                setIsOptimizing(false);
            }
        }, 50);
    };

    useEffect(() => {
        if (optimizationData && chartRef.current) {
            if (chartInstanceRef.current) {
                chartInstanceRef.current.destroy();
            }

            const ctx = chartRef.current.getContext('2d');
            if (ctx) {
                chartInstanceRef.current = new Chart(ctx, {
                    type: 'line',
                    data: {
                        labels: optimizationData.map(d => d.components),
                        datasets: [
                            {
                                label: 'SEC (Calibración)',
                                data: optimizationData.map(d => d.sec),
                                borderColor: '#3B82F6', // Blue
                                backgroundColor: '#3B82F6',
                                tension: 0.1,
                                pointRadius: 4,
                                pointHoverRadius: 6
                            },
                            {
                                label: 'SECV (Validación)',
                                data: optimizationData.map(d => d.secv),
                                borderColor: '#10B981', // Green
                                backgroundColor: '#10B981',
                                tension: 0.1,
                                pointRadius: 4,
                                pointHoverRadius: 6
                            }
                        ]
                    },
                    options: {
                        responsive: true,
                        maintainAspectRatio: false,
                        interaction: {
                            mode: 'index',
                            intersect: false,
                        },
                        plugins: {
                            title: { display: true, text: 'Error vs. Número de Componentes (Click para seleccionar)' },
                            tooltip: {
                                callbacks: {
                                    footer: (tooltipItems: any[]) => {
                                        return 'Click para usar este valor.';
                                    }
                                }
                            }
                        },
                        scales: {
                            x: { title: { display: true, text: 'Variables Latentes (LVs)' } },
                            y: { title: { display: true, text: 'RMSE (Error)' } }
                        },
                        onClick: (e: any, elements: any[]) => {
                            if (elements && elements.length > 0) {
                                const index = elements[0].index;
                                const selectedComps = optimizationData[index].components;
                                setNComponents(selectedComps.toString());
                            }
                        }
                    }
                });
            }
        }

        return () => {
             // Cleanup if needed
        };
    }, [optimizationData]);

    // Determine suggestion (min SECV)
    const suggestedLV = optimizationData 
        ? optimizationData.reduce((prev, curr) => curr.secv < prev.secv ? curr : prev).components 
        : null;

    return (
        <Card>
            <h2 className="text-lg font-semibold mb-4 flex items-center gap-2">
                <GenerateIcon />
                4. Generación de Modelo (PLS)
            </h2>

            <div className="space-y-4">
                <div className="grid grid-cols-2 gap-4 items-end">
                    <div>
                         <label htmlFor="lv-input" className="block text-sm text-gray-500 mb-1">Variables Latentes (LV):</label>
                        <input
                            type="number"
                            id="lv-input"
                            value={nComponents}
                            onChange={(e) => setNComponents(e.target.value)}
                            min="1"
                            max="20"
                            className="w-full bg-white border border-gray-300 rounded-md px-3 py-2 text-sm focus:outline-none focus:ring-1 focus:ring-brand-primary"
                        />
                    </div>
                    <Button variant="secondary" onClick={handleOptimize} disabled={disabled || isOptimizing} className="h-[38px] text-xs">
                        {isOptimizing ? 'Analizando...' : (
                            <>
                                <OptimizeIcon /> Analizar Componentes
                            </>
                        )}
                    </Button>
                </div>

                {optimizationData && (
                    <div className="border rounded-md p-2 bg-gray-50 animate-fade-in">
                        <div className="h-48 relative">
                            <canvas ref={chartRef}></canvas>
                        </div>
                        {suggestedLV && (
                            <p className="text-xs text-center mt-2 text-gray-600">
                                Mínimo error de validación en <span className="font-bold text-brand-primary">{suggestedLV} LVs</span>.
                            </p>
                        )}
                    </div>
                )}

                <div className="pt-2">
                    <Button onClick={handleRun} disabled={disabled} className="w-full">
                        <RunIcon />
                        Generar Modelo PLS Final
                    </Button>
                </div>
            </div>
        </Card>
    );
};

export default ModelGenerator;

import React, { useState, useCallback } from 'react';
import { Sample, PreprocessingStep, ModelResults } from './types';
import { parseCSV, DEMO_DATA_STRING } from './services/csvParser';
import { applyPreprocessingLogic, runPlsAnalysis } from './services/chemometrics';
import Header from './components/Header';
import Loader from './components/Loader';
import DataUploader from './components/DataUploader';
import SampleManager from './components/SampleManager';
import SpectraViewer from './components/SpectraViewer';
import PreprocessingEditor from './components/PreprocessingEditor';
import ModelGenerator, { ModelParams } from './components/ModelGenerator';
import ResultsViewer from './components/ResultsViewer';
import Card from './components/Card';

const App: React.FC = () => {
    const [loadingMessage, setLoadingMessage] = useState<string | null>(null);
    const [wavelengths, setWavelengths] = useState<number[]>([]);
    const [samples, setSamples] = useState<Sample[]>([]);
    const [analyticalProperty, setAnalyticalProperty] = useState<string>('Propiedad');
    const [preprocessingSteps, setPreprocessingSteps] = useState<PreprocessingStep[]>([]);
    const [modelResults, setModelResults] = useState<ModelResults | null>(null);
    const [processedSpectra, setProcessedSpectra] = useState<{ id: string | number; values: number[] }[] | null>(null);

    const handleDataLoaded = (data: { wavelengths: number[]; samples: Sample[]; analyticalProperty: string }) => {
        setWavelengths(data.wavelengths);
        setSamples(data.samples);
        setAnalyticalProperty(data.analyticalProperty);
        setModelResults(null);
        setProcessedSpectra(null);
        setPreprocessingSteps([]);
    };

    const handleFileSelected = (file: File) => {
        setLoadingMessage('Cargando datos...');
        parseCSV(file, (results) => {
            handleDataLoaded(results);
            setLoadingMessage(null);
        });
    };

    const handleLoadDemoData = () => {
        setLoadingMessage('Cargando datos de demostración...');
        // Simulate async loading for UX
        setTimeout(() => {
            parseCSV(DEMO_DATA_STRING, (results) => {
                handleDataLoaded(results);
                setLoadingMessage(null);
            });
        }, 100);
    };

    const handleToggleSample = (index: number) => {
        setSamples(prev => prev.map((s, i) => i === index ? { ...s, active: !s.active } : s));
    };

    const handleToggleAllSamples = (active: boolean) => {
        setSamples(prev => prev.map(s => ({ ...s, active })));
    };

    const handleVisualizePreprocessing = () => {
        const activeSamples = samples.filter(s => s.active);
        if (activeSamples.length === 0) return;
        const processed = activeSamples.map(sample => ({
            ...sample,
            values: applyPreprocessingLogic(sample.values, preprocessingSteps)
        }));
        setProcessedSpectra(processed);
    };

    const handleResetVisualization = useCallback(() => {
        setProcessedSpectra(null);
    }, []);

    const handleRunModel = async (params: ModelParams) => {
        const activeSamples = samples.filter(s => s.active);
        if (activeSamples.length < 3) {
            alert('Se necesitan al menos 3 muestras activas para generar el modelo PLS y validación cruzada.');
            return;
        }
        setLoadingMessage(`Generando modelo ${params.type.toUpperCase()}...`);

        // Timeout para permitir que la UI muestre el loader
        setTimeout(() => {
            try {
                const results = runPlsAnalysis(activeSamples, preprocessingSteps, params.nComponents);
                setModelResults(results);
            } catch (error) {
                console.error(`Error during ${params.type} run:`, error);
                const errorMessage = error instanceof Error ? error.message : "Ocurrió un error desconocido.";
                alert(`Ocurrió un error al generar el modelo: ${errorMessage}`);
            } finally {
                setLoadingMessage(null);
            }
        }, 100);
    };

    const handleDeactivateOutliers = (outlierIds: (string|number)[]) => {
         setSamples(prev => prev.map(s => outlierIds.includes(s.id) ? { ...s, active: false } : s));
         // Automatically rerun model after deactivating if results exist
         if (modelResults) {
             // Defer execution
             setTimeout(() => {
                const params: ModelParams = { type: 'pls', nComponents: modelResults.nComponents };
                handleRunModel(params);
             }, 100);
         }
    }

    const activeSamples = samples.filter(s => s.active);
    const spectraToDisplay = processedSpectra ? processedSpectra.map(p => {
        const originalSample = samples.find(s => s.id === p.id);
        return { ...p, color: originalSample?.color || '#000000' };
    }) : activeSamples;

    return (
        <>
            {loadingMessage && <Loader message={loadingMessage} />}
            <div className="min-h-screen flex flex-col bg-gray-50 text-gray-800">
                <Header />
                <main className="flex-grow p-4 lg:p-6 grid grid-cols-1 xl:grid-cols-4 gap-4 lg:gap-6">
                    {/* Controls Column */}
                    <div className="xl:col-span-1 flex flex-col gap-4 lg:gap-6">
                        <DataUploader onFileSelected={handleFileSelected} onLoadDemo={handleLoadDemoData} />
                        <SampleManager
                            samples={samples}
                            onToggle={handleToggleSample}
                            onToggleAll={handleToggleAllSamples}
                        />
                    </div>

                    {/* Visualization Column */}
                    <div className="xl:col-span-3 flex flex-col gap-4 lg:gap-6">
                        <SpectraViewer
                            wavelengths={wavelengths}
                            samples={spectraToDisplay}
                            isProcessed={!!processedSpectra}
                            onReset={handleResetVisualization}
                        />

                        <PreprocessingEditor
                            steps={preprocessingSteps}
                            setSteps={setPreprocessingSteps}
                            onVisualize={handleVisualizePreprocessing}
                            disabled={activeSamples.length === 0}
                        />

                        {/* Modified to accept data for internal optimization */}
                        <ModelGenerator 
                            onRunModel={handleRunModel} 
                            disabled={activeSamples.length < 3}
                            activeSamples={activeSamples}
                            preprocessingSteps={preprocessingSteps}
                        />

                        {modelResults ? (
                            <ResultsViewer 
                                results={modelResults}
                                propertyName={analyticalProperty}
                                preprocessingSteps={preprocessingSteps}
                                activeSamples={activeSamples.map(s => s.id)}
                                onDeactivateOutliers={handleDeactivateOutliers}
                                wavelengths={wavelengths}
                            />
                        ) : (
                            <Card>
                                <div className="flex items-center justify-center h-40">
                                    <p className="text-gray-400">Genere un modelo PLS para ver los resultados estadísticos (R, SEC, SECV).</p>
                                </div>
                            </Card>
                        )}
                    </div>
                </main>
            </div>
        </>
    );
};

