                                                        <th className="px-4 py-2 text-right">Distancia</th>
                                                        <th className="px-4 py-2 text-right">Estado</th>
                                                    </tr>
                                                </thead>
                                                <tbody className="divide-y divide-slate-100">
                                                    {outliers.map(o => (
                                                        <tr key={o.id} className="hover:bg-slate-50 transition-colors">
                                                            <td className="px-4 py-2 text-center">
                                                                <input 
                                                                    type="checkbox" 
                                                                    className="rounded text-brand-600 focus:ring-brand-500 border-slate-300"
                                                                    checked={selectedOutliers.has(o.id)} 
                                                                    onChange={e => handleOutlierSelection(o.id, e.target.checked)} 
                                                                />
                                                            </td>
                                                            <td className="px-4 py-2 font-medium text-slate-700">{o.id}</td>
                                                            <td className="px-4 py-2 text-right font-mono text-red-600 font-bold">{o.distance.toFixed(2)}</td>
                                                            <td className="px-4 py-2 text-right"><span className="text-[10px] uppercase font-bold text-red-500 bg-red-50 px-1.5 py-0.5 rounded">Crítico</span></td>
