                                        <p className="text-sm text-slate-500">No se detectaron outliers espectrales significativos.</p>
                                    </div>
                                )}
                            </div>
                         </div>
                    </div>
                )}

                {activeTab === 'residuals' && (
                     <div className="animate-fade-in bg-white rounded-xl border border-slate-200 shadow-sm overflow-hidden">
                        <div className="max-h-[500px] overflow-y-auto">
                            <table className="w-full text-sm text-left">
                                <thead className="text-xs text-slate-500 uppercase bg-slate-100 sticky top-0 z-10 shadow-sm">
                                    <tr>
                                        <th className="px-6 py-3 font-semibold">ID Muestra</th>
                                        <th className="px-6 py-3 text-right font-semibold">Valor Real</th>
                                        <th className="px-6 py-3 text-right font-semibold">Valor Predicho</th>
                                        <th className="px-6 py-3 text-right font-semibold">Error Absoluto</th>
                                        <th className="px-6 py-3 text-right font-semibold">% Error Relativo</th>
                                    </tr>
                                </thead>
                                <tbody className="divide-y divide-slate-100">
                                    {residuals.map((r, idx) => {
                                        const relError = (Math.abs(r.residual) / Math.abs(r.actual)) * 100;
                                        const isHighError = Math.abs(r.residual) > results.model.sec * 2;
                                        return (
                                            <tr key={r.id} className={`hover:bg-slate-50 transition-colors ${idx % 2 === 0 ? 'bg-white' : 'bg-slate-50/30'}`}>
                                                <td className="px-6 py-3 font-medium text-slate-700">{r.id}</td>
                                                <td className="px-6 py-3 text-right font-mono text-slate-600">{r.actual.toFixed(4)}</td>
                                                <td className="px-6 py-3 text-right font-mono text-slate-600">{r.predicted.toFixed(4)}</td>
                                                <td className={`px-6 py-3 text-right font-mono font-medium ${isHighError ? 'text-red-600' : 'text-slate-600'}`}>
                                                    {r.residual > 0 ? '+' : ''}{r.residual.toFixed(4)}
                                                </td>
                                                <td className="px-6 py-3 text-right font-mono text-slate-500">
                                                    {relError.toFixed(2)}%
                                                </td>
                                            </tr>
                                        );
                                    })}
                                </tbody>
                            </table>
                        </div>
                     </div>
                )}

                {activeTab === 'full-data' && (
                    <div className="flex flex-col items-center justify-center py-12 gap-6 animate-fade-in bg-white rounded-xl border border-slate-200 border-dashed">
                         <div className="text-center max-w-md">
                            <div className="bg-brand-50 h-16 w-16 rounded-full flex items-center justify-center mx-auto mb-4 text-brand-600">
                                <svg className="w-8 h-8" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M4 16v1a3 3 0 003 3h10a3 3 0 003-3v-1m-4-4l-4 4m0 0l-4-4m4 4V4"></path></svg>
                            </div>
                            <h3 className="text-lg font-semibold text-slate-900 mb-2">Exportación de Datos</h3>
                            <p className="text-slate-500 mb-6">Descargue los resultados completos para reportes externos o el archivo de configuración JSON para reproducir este modelo más tarde.</p>
                         </div>
                         <div className="flex gap-4">
                            <Button onClick={handleDownloadData} size="lg">
                                Descargar CSV
                            </Button>
                            <Button variant="secondary" onClick={handleExportConfig} size="lg">
                                Exportar Modelo (JSON)
                            </Button>
                         </div>
                    </div>
                )}
            </div>
        </Card>
    );
};

