export default Card;

import React from 'react';

interface ButtonProps extends React.ButtonHTMLAttributes<HTMLButtonElement> {
    variant?: 'primary' | 'secondary' | 'danger' | 'ghost';
    size?: 'sm' | 'md' | 'lg';
    children: React.ReactNode;
}

const Button: React.FC<ButtonProps> = ({ variant = 'primary', size = 'md', children, className = '', ...props }) => {

    const baseClasses = 'inline-flex items-center justify-center gap-2 rounded-lg font-medium transition-all duration-200 ease-in-out disabled:opacity-50 disabled:cursor-not-allowed select-none focus:outline-none focus:ring-2 focus:ring-offset-1 focus:ring-brand-500 focus:ring-offset-slate-900';

    const sizeClasses = {
        sm: 'px-3 py-1.5 text-xs',
        md: 'px-4 py-2 text-sm',
        lg: 'px-6 py-3 text-base',
    };

    const variantClasses = {
        primary: 'bg-brand-500 text-slate-900 hover:bg-brand-400 shadow-[0_0_10px_rgba(6,182,212,0.3)] hover:shadow-[0_0_15px_rgba(34,211,238,0.5)] border border-transparent font-semibold',
        secondary: 'bg-slate-800 text-slate-200 hover:bg-slate-700 border border-slate-600 hover:border-slate-500 shadow-sm',
        danger: 'bg-slate-800 text-red-400 hover:bg-red-900/20 border border-red-900/30 hover:border-red-500/50',
        ghost: 'bg-transparent text-slate-400 hover:text-brand-400 hover:bg-slate-800 border border-transparent',
    };

    return (
        <button className={`${baseClasses} ${sizeClasses[size]} ${variantClasses[variant]} ${className}`} {...props}>
            {children}
        </button>
    );
};

