import React from 'react';
import Card from './Card';
import Button from './Button';
import { PreprocessingStep } from '../types';

interface PreprocessingEditorProps {
    steps: PreprocessingStep[];
    setSteps: React.Dispatch<React.SetStateAction<PreprocessingStep[]>>;
    onVisualize: () => void;
    disabled: boolean;
}

const PREPROCESSING_METHODS = {
    'none': { name: 'Ninguno', params: [] },
    'savgol': {
        name: 'Savitzky-Golay',
        params: [
            { id: 'derivative', name: 'Orden Derivada', type: 'number', default: 1 },
            { id: 'windowSize', name: 'Tamaño Ventana (impar)', type: 'number', default: 5 },
            { id: 'polynomialOrder', name: 'Orden Polinomio', type: 'number', default: 2 },
        ],
    },
    'snv': { name: 'Standard Normal Variate (SNV)', params: [] },
    'msc': { name: 'Multiplicative Scatter Correction (MSC)', params: [] },
    'detrend': { name: 'Detrend', params: [] },
};

const EditIcon: React.FC = () => (
    <svg xmlns="http://www.w3.org/2000/svg" width="20" height="20" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round" className="text-brand-400"><path d="M12 20h9"></path><path d="M16.5 3.5a2.12 2.12 0 0 1 3 3L7 19l-4 1 1-4Z"></path></svg>
);
const VisualizeIcon: React.FC = () => (
    <svg xmlns="http://www.w3.org/2000/svg" width="16" height="16" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"><path d="m21.14 10.28-9.23-9.23a1.5 1.5 0 0 0-2.12 0l-9.23 9.23a1.5 1.5 0 0 0 0 2.12l9.23 9.23a1.5 1.5 0 0 0 2.12 0l9.23-9.23a1.5 1.5 0 0 0 0-2.12z"></path><path d="M12 22V2"></path></svg>
);
const AddIcon: React.FC = () => (
    <svg xmlns="http://www.w3.org/2000/svg" width="16" height="16" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"><line x1="12" y1="5" x2="12" y2="19"></line><line x1="5" y1="12" x2="19" y2="12"></line></svg>
);
const RemoveIcon: React.FC = () => (
    <svg xmlns="http://www.w3.org/2000/svg" width="16" height="16" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"><polyline points="3 6 5 6 21 6"></polyline><path d="M19 6v14a2 2 0 0 1-2 2H7a2 2 0 0 1-2-2V6m3 0V4a2 2 0 0 1 2-2h4a2 2 0 0 1 2 2v2"></path></svg>
);


const PreprocessingEditor: React.FC<PreprocessingEditorProps> = ({ steps, setSteps, onVisualize, disabled }) => {

    const addStep = () => {
        const newStep: PreprocessingStep = { method: 'savgol', params: {} };
        PREPROCESSING_METHODS['savgol'].params.forEach(p => newStep.params[p.id] = p.default);
        setSteps([...steps, newStep]);
    };

    const removeStep = (index: number) => {
        setSteps(steps.filter((_, i) => i !== index));
    };

    const handleMethodChange = (index: number, newMethod: PreprocessingStep['method']) => {
        const newSteps = [...steps];
        newSteps[index].method = newMethod;
        newSteps[index].params = {};
        (PREPROCESSING_METHODS[newMethod].params as any[]).forEach(p => {
            newSteps[index].params[p.id] = p.default;
        });
        setSteps(newSteps);
    };

    const handleParamChange = (stepIndex: number, paramId: string, value: string) => {
        const newSteps = [...steps];
        newSteps[stepIndex].params[paramId] = parseFloat(value);
        setSteps(newSteps);
    };

    return (
        <Card>
            <h2 className="text-lg font-bold mb-4 flex items-center gap-2 text-brand-400"><EditIcon />3. Pre-procesamiento</h2>
            <div className="space-y-3 mb-4">
                {steps.map((step, index) => {
                    const methodInfo = PREPROCESSING_METHODS[step.method];
                    return (
                        <div key={index} className="p-3 border border-slate-700 rounded-md bg-slate-800/50 shadow-sm">
                            <div className="flex items-center justify-between">
                                <select
                                    value={step.method}
                                    onChange={(e) => handleMethodChange(index, e.target.value as PreprocessingStep['method'])}
                                    className="w-full bg-slate-900 border border-slate-600 text-slate-200 rounded-md px-2 py-1 text-sm focus:outline-none focus:ring-1 focus:ring-brand-500"
                                >
                                    {Object.entries(PREPROCESSING_METHODS).map(([key, value]) => (
                                        <option key={key} value={key}>{value.name}</option>
                                    ))}
                                </select>
                                <button onClick={() => removeStep(index)} className="ml-2 p-1 text-slate-500 hover:text-red-400 transition-colors">
                                    <RemoveIcon />
                                </button>
                            </div>
                             {methodInfo.params.length > 0 && (
                                <div className="grid grid-cols-3 gap-2 mt-2">
                                    {(methodInfo.params as any[]).map(param => (
                                        <div key={param.id} className="text-xs">
                                            <label htmlFor={`${param.id}-${index}`} className="text-slate-400">{param.name}</label>
                                            <input
                                                type={param.type}
                                                id={`${param.id}-${index}`}
                                                value={step.params[param.id] || ''}
                                                onChange={(e) => handleParamChange(index, param.id, e.target.value)}
                                                className="w-full bg-slate-900 border border-slate-600 text-slate-200 rounded-md px-2 py-1 text-xs mt-1 focus:outline-none focus:ring-1 focus:ring-brand-500"
                                            />
                                        </div>
                                    ))}
                                </div>
                            )}
                        </div>
                    );
                })}
            </div>
            <div className="flex flex-col gap-2">
                <Button onClick={onVisualize} disabled={disabled}><VisualizeIcon />Visualizar Pre-procesamiento</Button>
                <Button variant="secondary" onClick={addStep} disabled={disabled}><AddIcon />Añadir Paso</Button>
            </div>
        </Card>
    );
};

export default PreprocessingEditor;

import React, { useState, useRef, useEffect } from 'react';
import Card from './Card';
import Button from './Button';
import { runPlsOptimization } from '../services/chemometrics';
import { OptimizationResult, Sample, PreprocessingStep } from '../types';

declare var Chart: any;

export type ModelParams = 
    | { type: 'pls'; nComponents: number };

interface ModelGeneratorProps {
    onRunModel: (params: ModelParams) => void;
    disabled: boolean;
    activeSamples?: Sample[];
    preprocessingSteps?: PreprocessingStep[];
}

const GenerateIcon: React.FC = () => (
     <svg xmlns="http://www.w3.org/2000/svg" width="20" height="20" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round" className="text-brand-400">
        <circle cx="12" cy="12" r="10"></circle><path d="m9 12 2 2 4-4"></path>
    </svg>
);

const RunIcon: React.FC = () => (
    <svg xmlns="http://www.w3.org/2000/svg" width="16" height="16" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round">
        <polygon points="5 3 19 12 5 21 5 3"></polygon>
    </svg>
);

const OptimizeIcon: React.FC = () => (
    <svg xmlns="http://www.w3.org/2000/svg" width="16" height="16" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round">
        <line x1="18" y1="20" x2="18" y2="10"></line><line x1="12" y1="20" x2="12" y2="4"></line><line x1="6" y1="20" x2="6" y2="14"></line>
    </svg>
);

const ModelGenerator: React.FC<ModelGeneratorProps> = ({ onRunModel, disabled, activeSamples, preprocessingSteps }) => {
    const [nComponents, setNComponents] = useState('5');
    const [isOptimizing, setIsOptimizing] = useState(false);
    const [optimizationData, setOptimizationData] = useState<OptimizationResult[] | null>(null);

    const chartRef = useRef<HTMLCanvasElement>(null);
    const chartInstanceRef = useRef<any>(null);

    const handleRun = () => {
        const lv = parseInt(nComponents);
        if (!isNaN(lv) && lv > 0 && lv <= 20) {
            onRunModel({ type: 'pls', nComponents: lv });
        } else {
            alert('Por favor, introduzca un número válido de variables latentes (1-20).');
        }
    };

    const handleOptimize = async () => {
        if (!activeSamples || !preprocessingSteps || activeSamples.length < 3) {
            alert("Se requieren al menos 3 muestras activas para optimizar.");
            return;
        }

        setIsOptimizing(true);
        setTimeout(() => {
            try {
                const maxLVs = Math.min(15, activeSamples.length - 1);
                const results = runPlsOptimization(activeSamples, preprocessingSteps, maxLVs);
                setOptimizationData(results);
            } catch (e) {
                console.error(e);
                alert("Error durante la optimización.");
            } finally {
                setIsOptimizing(false);
            }
        }, 50);
    };

    useEffect(() => {
        if (optimizationData && chartRef.current) {
            if (chartInstanceRef.current) {
                chartInstanceRef.current.destroy();
            }

            const ctx = chartRef.current.getContext('2d');
            if (ctx) {
                chartInstanceRef.current = new Chart(ctx, {
                    type: 'line',
                    data: {
                        labels: optimizationData.map(d => d.components),
                        datasets: [
                            {
                                label: 'SEC (Calibración)',
                                data: optimizationData.map(d => d.sec),
                                borderColor: '#0ea5e9', // Sky 500
                                backgroundColor: '#0ea5e9',
                                tension: 0.1,
                                pointRadius: 4,
                                pointHoverRadius: 6
                            },
                            {
                                label: 'SECV (Validación)',
                                data: optimizationData.map(d => d.secv),
                                borderColor: '#10b981', // Emerald 500
                                backgroundColor: '#10b981',
                                tension: 0.1,
                                pointRadius: 4,
                                pointHoverRadius: 6
                            }
                        ]
                    },
                    options: {
                        responsive: true,
                        maintainAspectRatio: false,
                        interaction: {
                            mode: 'index',
                            intersect: false,
                        },
                        plugins: {
                            legend: { labels: { color: '#cbd5e1' } },
                            title: { display: true, text: 'Error vs. LVs', color: '#94a3b8' },
                            tooltip: {
                                backgroundColor: 'rgba(15, 23, 42, 0.9)',
                                titleColor: '#e2e8f0',
                                bodyColor: '#cbd5e1',
                                borderColor: '#334155',
                                borderWidth: 1,
                                callbacks: {
                                    footer: (tooltipItems: any[]) => {
                                        return 'Click para usar este valor.';
                                    }
                                }
                            }
                        },
                        scales: {
                            x: { 
                                title: { display: true, text: 'Variables Latentes (LVs)', color: '#94a3b8' },
                                ticks: { color: '#64748b' },
                                grid: { color: '#1e293b' }
                            },
                            y: { 
                                title: { display: true, text: 'RMSE (Error)', color: '#94a3b8' },
                                ticks: { color: '#64748b' },
                                grid: { color: '#1e293b' }
                            }
                        },
                        onClick: (e: any, elements: any[]) => {
                            if (elements && elements.length > 0) {
                                const index = elements[0].index;
                                const selectedComps = optimizationData[index].components;
                                setNComponents(selectedComps.toString());
                            }
                        }
                    }
                });
            }
        }

        return () => {
             // Cleanup if needed
        };
    }, [optimizationData]);

    const suggestedLV = optimizationData 
        ? optimizationData.reduce((prev, curr) => curr.secv < prev.secv ? curr : prev).components 
        : null;

    return (
        <Card>
            <h2 className="text-lg font-bold mb-4 flex items-center gap-2 text-brand-400">
                <GenerateIcon />
                4. Generación de Modelo (PLS)
            </h2>

            <div className="space-y-4">
                <div className="grid grid-cols-2 gap-4 items-end">
                    <div>
                         <label htmlFor="lv-input" className="block text-sm text-slate-400 mb-1">Variables Latentes (LV):</label>
                        <input
                            type="number"
                            id="lv-input"
                            value={nComponents}
                            onChange={(e) => setNComponents(e.target.value)}
                            min="1"
                            max="20"
                            className="w-full bg-slate-900 border border-slate-700 text-slate-200 rounded-md px-3 py-2 text-sm focus:outline-none focus:ring-1 focus:ring-brand-500"
                        />
                    </div>
                    <Button variant="secondary" onClick={handleOptimize} disabled={disabled || isOptimizing} className="h-[38px] text-xs">
                        {isOptimizing ? 'Analizando...' : (
                            <>
                                <OptimizeIcon /> Analizar Componentes
                            </>
                        )}
                    </Button>
                </div>

                {optimizationData && (
                    <div className="border border-slate-700 rounded-md p-2 bg-slate-900/50 animate-fade-in">
                        <div className="h-48 relative">
                            <canvas ref={chartRef}></canvas>
                        </div>
                        {suggestedLV && (
                            <p className="text-xs text-center mt-2 text-slate-400">
                                Mínimo error de validación en <span className="font-bold text-brand-400">{suggestedLV} LVs</span>.
                            </p>
                        )}
                    </div>
                )}

                <div className="pt-2">
                    <Button onClick={handleRun} disabled={disabled} className="w-full">
                        <RunIcon />
                        Generar Modelo PLS Final
                    </Button>
                </div>
            </div>
        </Card>
    );
};

export default ModelGenerator;

import React, { useState, useRef, useEffect } from 'react';
import Card from './Card';
import Button from './Button';
import { ModelResults, PreprocessingStep } from '../types';

declare var Chart: any;

interface ResultsViewerProps {
    results: ModelResults;
    propertyName: string;
    preprocessingSteps: PreprocessingStep[];
    activeSamples: (string|number)[];
    onDeactivateOutliers: (outlierIds: (string|number)[]) => void;
    wavelengths: number[];
}

const StatCard = ({ label, value, subtext, colorClass }: { label: string, value: string | number, subtext?: string, colorClass: string }) => (
    <div className="bg-slate-800 p-4 rounded-lg border border-slate-700 shadow-sm flex flex-col items-center justify-center hover:shadow-glow transition-shadow hover:border-brand-500/30">
        <span className="text-xs font-semibold text-slate-500 uppercase tracking-wider mb-1">{label}</span>
        <span className={`text-2xl font-bold font-mono ${colorClass}`}>{value}</span>
        {subtext && <span className="text-[10px] text-slate-500 mt-1">{subtext}</span>}
    </div>
);

const ResultsViewer: React.FC<ResultsViewerProps> = ({ results, propertyName, preprocessingSteps, activeSamples, onDeactivateOutliers, wavelengths }) => {
    const [activeTab, setActiveTab] = useState('correlation');
    const chartRef = useRef<HTMLCanvasElement>(null);
    const chartInstanceRef = useRef<any>(null);

    const residuals = results.model.residuals;
    const outliers = results.mahalanobis.distances.filter(d => d.isOutlier);
    const [selectedOutliers, setSelectedOutliers] = useState<Set<string|number>>(new Set());

    useEffect(() => {
        if (activeTab === 'correlation' && chartRef.current) {
            const ctx = chartRef.current.getContext('2d');
            if (ctx) {
                const chartInstance = new Chart(ctx, {
                    type: 'scatter',
                    data: { datasets: [] },
                    options: {
                        maintainAspectRatio: false,
                        responsive: true,
                        animation: false,
                        plugins: {
                            legend: { 
                                position: 'bottom',
                                labels: { usePointStyle: true, padding: 20, font: { family: 'Inter', size: 12 }, color: '#cbd5e1' }
                            },
                            title: { display: false },
                            tooltip: {
                                backgroundColor: 'rgba(15, 23, 42, 0.95)',
                                titleColor: '#e2e8f0',
                                bodyColor: '#cbd5e1',
                                borderColor: '#334155',
                                borderWidth: 1,
                                padding: 10,
                                cornerRadius: 6,
                                callbacks: {
                                    label: (context: any) => {
                                        const label = context.dataset.label || '';
                                        const x = context.parsed.x;
                                        const y = context.parsed.y;
                                        return `${label}: Ref ${x.toFixed(2)} / Pred ${y.toFixed(2)}`;
                                    }
                                }
                            }
                        },
                        scales: {
                            x: { 
                                title: { display: true, text: `Valor Referencia (${propertyName})`, font: { weight: '600' }, color: '#94a3b8' },
                                grid: { color: '#1e293b' },
                                ticks: { color: '#64748b', font: { family: 'JetBrains Mono' } }
                            },
                            y: { 
                                title: { display: true, text: 'Valor Predicho (NIR)', font: { weight: '600' }, color: '#94a3b8' },
                                grid: { color: '#1e293b' },
                                ticks: { color: '#64748b', font: { family: 'JetBrains Mono' } }
                            }
                        }
                    }
                });

                chartInstanceRef.current = chartInstance;

                if (results) {
                    const { actual, predicted } = results.model.correlation;
                    const inliersData: {x: number, y: number}[] = [];
                    const outliersData: {x: number, y: number}[] = [];

                    results.mahalanobis.distances.forEach((d, i) => {
                        const point = { x: actual[i], y: predicted[i] };
                        if (d.isOutlier) outliersData.push(point);
                        else inliersData.push(point);
                    });

                    const allValues = [...actual, ...predicted];
                    if (allValues.length > 0) {
                        const minVal = Math.min(...allValues);
                        const maxVal = Math.max(...allValues);
                        const padding = (maxVal - minVal) * 0.1;

                        chartInstance.data.datasets = [
                            { 
                                label: 'Muestras Válidas', 
                                data: inliersData, 
                                backgroundColor: '#22d3ee', // Brand 400 (Cyan)
                                borderColor: '#0891b2', 
                                borderWidth: 1,
                                pointRadius: 5,
                                pointHoverRadius: 7
                            },
                            { 
                                label: 'Posibles Outliers', 
                                data: outliersData, 
                                backgroundColor: '#ef4444', 
                                borderColor: '#b91c1c', 
                                borderWidth: 1,
                                pointRadius: 6, 
                                pointStyle: 'triangle',
                                pointHoverRadius: 8
                            },
                            { 
                                type: 'line', 
                                label: 'Línea Ideal (1:1)', 
                                data: [{x: minVal - padding, y: minVal - padding}, {x: maxVal + padding, y: maxVal + padding}], 
                                borderColor: '#475569', 
                                borderWidth: 2, 
                                borderDash: [6, 6], 
                                pointRadius: 0, 
                                fill: false 
                            }
                        ];

                        chartInstance.options.scales.x.min = minVal - padding;
                        chartInstance.options.scales.x.max = maxVal + padding;
                        chartInstance.options.scales.y.min = minVal - padding;
                        chartInstance.options.scales.y.max = maxVal + padding;

                        chartInstance.update();
                    }
                }
            }
        }

        return () => {
            if (chartInstanceRef.current) {
                chartInstanceRef.current.destroy();
                chartInstanceRef.current = null;
            }
        };
    }, [activeTab, results]);

    const handleExportConfig = () => {
        const config = {
            date: new Date().toISOString(),
            modelType: results.modelType,
            nComponents: results.nComponents,
            analyticalProperty: propertyName,
            activeSamples: activeSamples,
            preprocessing: preprocessingSteps,
            metrics: results.model,
            coefficients: results.model.coefficients
        };
        const dataStr = "data:text/json;charset=utf-8," + encodeURIComponent(JSON.stringify(config, null, 2));
        const anchor = document.createElement('a');
        anchor.href = dataStr;
        anchor.download = `model_config_${new Date().toISOString().slice(0,10)}.json`;
        anchor.click();
    };

    const handleDownloadData = () => {
        const headers = ['ID', 'Reference', 'Predicted', 'Residual', ...wavelengths];
        const { residuals, processedSpectra } = results.model;
        const rows = residuals.map((res, index) => 
            [res.id, res.actual, res.predicted, res.residual, ...processedSpectra[index]]
        );
        const csvContent = [headers.join(','), ...rows.map(row => row.join(','))].join('\n');
        const blob = new Blob([csvContent], { type: 'text/csv;charset=utf-8;' });
        const url = URL.createObjectURL(blob);
        const link = document.createElement("a");
        link.href = url;
        link.download = "pls_prediction_results.csv";
        link.click();
    };

    const handleOutlierSelection = (id: string|number, checked: boolean) => {
        setSelectedOutliers(prev => {
            const newSet = new Set(prev);
            if (checked) newSet.add(id);
            else newSet.delete(id);
            return newSet;
        });
    };

    const handleDeactivateClick = () => {
        if (selectedOutliers.size === 0) return alert("Seleccione al menos un outlier.");
        onDeactivateOutliers(Array.from(selectedOutliers));
        setSelectedOutliers(new Set());
    };

    const TabButton = ({ tabId, label, icon }: { tabId: string; label: string; icon?: React.ReactNode }) => (
        <button
            className={`flex items-center gap-2 px-5 py-3 text-sm font-medium transition-all relative ${activeTab === tabId ? 'text-brand-400 bg-brand-500/10' : 'text-slate-400 hover:text-slate-200 hover:bg-slate-700/50'}`}
            onClick={() => setActiveTab(tabId)}
        >
            {icon}
            {label}
            {activeTab === tabId && <span className="absolute bottom-0 left-0 w-full h-0.5 bg-brand-400"></span>}
        </button>
    );

    return (
        <Card noPadding className="overflow-hidden">
            <div className="bg-slate-800 border-b border-slate-700">
                <div className="flex overflow-x-auto no-scrollbar">
                    <TabButton tabId="correlation" label="Diagnóstico Gráfico" icon={<svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M7 12l3-3 3 3 4-4M8 21l4-4 4 4M3 4h18M4 4h16v12a1 1 0 01-1 1H5a1 1 0 01-1-1V4z"></path></svg>} />
                    <TabButton tabId="stats" label="Métricas & Outliers" icon={<svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M9 19v-6a2 2 0 00-2-2H5a2 2 0 00-2 2v6a2 2 0 002 2h2a2 2 0 002-2zm0 0V9a2 2 0 012-2h2a2 2 0 012 2v10m-6 0a2 2 0 002 2h2a2 2 0 002-2m0 0V5a2 2 0 012-2h2a2 2 0 012 2v14a2 2 0 01-2 2h-2a2 2 0 01-2-2z"></path></svg>} />
                    <TabButton tabId="residuals" label="Tabla Residuos" icon={<svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M3 10h18M3 14h18m-9-4v8m-7 0h14a2 2 0 002-2V8a2 2 0 00-2-2H5a2 2 0 00-2 2v8a2 2 0 002 2z"></path></svg>} />
                    <TabButton tabId="full-data" label="Exportar" icon={<svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M4 16v1a3 3 0 003 3h10a3 3 0 003-3v-1m-4-4l-4 4m0 0l-4-4m4 4V4"></path></svg>} />
                </div>
            </div>

            <div className="p-6 bg-slate-900/30 min-h-[400px]">
                {activeTab === 'correlation' && (
                    <div className="grid grid-cols-1 lg:grid-cols-12 gap-6 animate-fade-in">
                        {/* KPI Column */}
                        <div className="lg:col-span-3 space-y-4">
                            <div className="bg-gradient-to-br from-slate-900 to-slate-800 text-white p-5 rounded-xl shadow-lg border border-slate-700">
                                <h3 className="text-brand-400 text-xs font-bold uppercase tracking-widest mb-1">Modelo PLS</h3>
                                <div className="text-3xl font-bold font-mono">{results.nComponents} <span className="text-base font-normal text-slate-400 font-sans">LVs</span></div>
                                <div className="mt-4 pt-4 border-t border-slate-700 flex flex-col gap-1">
                                    <div className="flex justify-between text-sm">
                                        <span className="text-slate-400">R² Score</span>
                                        <span className="font-mono text-brand-200 font-bold">{results.model.r2.toFixed(4)}</span>
                                    </div>
                                    <div className="flex justify-between text-sm">
                                        <span className="text-slate-400">Correlación (r)</span>
                                        <span className="font-mono text-white">{results.model.r.toFixed(4)}</span>
                                    </div>
                                </div>
                            </div>

                            <div className="grid grid-cols-2 lg:grid-cols-1 gap-3">
                                <StatCard label="SEC (Calibración)" value={results.model.sec.toFixed(4)} colorClass="text-brand-400" />
                                <StatCard label="SECV (Validación)" value={results.model.secv.toFixed(4)} colorClass="text-emerald-400" subtext="Target Minimization" />
                            </div>
                        </div>

                        {/* Chart Column */}
                        <div className="lg:col-span-9 bg-slate-900/50 p-4 rounded-xl border border-slate-700 shadow-inner relative h-[450px]">
                            <canvas ref={chartRef}></canvas>
                        </div>
                    </div>
                )}

                {activeTab === 'stats' && (
                    <div className="grid grid-cols-1 lg:grid-cols-2 gap-6 animate-fade-in">
                         <div className="bg-slate-800 rounded-xl border border-slate-700 shadow-sm overflow-hidden">
                            <div className="bg-slate-800/80 px-4 py-3 border-b border-slate-700 flex justify-between items-center">
                                <h4 className="font-semibold text-slate-200">Parámetros de Regresión</h4>
                            </div>
                            <div className="p-4 space-y-4">
                                <div className="grid grid-cols-2 gap-4">
                                    <div className="p-3 bg-slate-900/50 rounded border border-slate-700/50">
                                        <div className="text-xs text-slate-500 mb-1">Pendiente (Slope)</div>
                                        <div className="font-mono font-medium text-slate-200">{results.model.slope.toFixed(5)}</div>
                                    </div>
                                    <div className="p-3 bg-slate-900/50 rounded border border-slate-700/50">
                                        <div className="text-xs text-slate-500 mb-1">Offset (Bias)</div>
                                        <div className="font-mono font-medium text-slate-200">{results.model.offset.toFixed(5)}</div>
                                    </div>
                                </div>
                                <div className="text-sm text-slate-400">
                                    <p className="mb-2"><strong>Validación de Sesgo:</strong> Compruebe si la pendiente es cercana a 1.0 y el offset cercano a 0.0 para asegurar robustez.</p>
                                    <p><strong>Ratio Desempeño:</strong> {results.model.sec > 0 ? `RPD ≈ ${(results.model.secv / results.model.sec).toFixed(2)}` : 'N/A'}</p>
