                            </div>
                         </div>

                         <div className="bg-slate-800 rounded-xl border border-slate-700 shadow-sm overflow-hidden flex flex-col">
                            <div className="bg-slate-800/80 px-4 py-3 border-b border-slate-700 flex justify-between items-center">
                                <h4 className="font-semibold text-slate-200">Detección de Outliers (Mahalanobis)</h4>
                                {outliers.length > 0 && <span className="bg-red-900/30 text-red-400 text-xs font-bold px-2 py-0.5 rounded-full border border-red-900/50">{outliers.length} Detectados</span>}
                            </div>

                            <div className="flex-1 p-0 overflow-hidden flex flex-col">
                                {outliers.length > 0 ? (
                                    <>
                                        <div className="flex-1 overflow-y-auto max-h-60 custom-scrollbar">
                                            <table className="w-full text-sm text-left">
                                                <thead className="text-xs text-slate-500 uppercase bg-slate-900 sticky top-0">
                                                    <tr>
                                                        <th className="px-4 py-2 w-12 text-center">Sel.</th>
                                                        <th className="px-4 py-2">ID Muestra</th>
                                                        <th className="px-4 py-2 text-right">Distancia</th>
                                                        <th className="px-4 py-2 text-right">Estado</th>
                                                    </tr>
                                                </thead>
                                                <tbody className="divide-y divide-slate-700">
                                                    {outliers.map(o => (
                                                        <tr key={o.id} className="hover:bg-slate-700/50 transition-colors">
                                                            <td className="px-4 py-2 text-center">
                                                                <input 
                                                                    type="checkbox" 
                                                                    className="rounded bg-slate-700 border-slate-500 text-brand-500 focus:ring-brand-500 focus:ring-offset-slate-800"
                                                                    checked={selectedOutliers.has(o.id)} 
                                                                    onChange={e => handleOutlierSelection(o.id, e.target.checked)} 
                                                                />
                                                            </td>
                                                            <td className="px-4 py-2 font-medium text-slate-300">{o.id}</td>
                                                            <td className="px-4 py-2 text-right font-mono text-red-400 font-bold">{o.distance.toFixed(2)}</td>
                                                            <td className="px-4 py-2 text-right"><span className="text-[10px] uppercase font-bold text-red-400 bg-red-900/20 px-1.5 py-0.5 rounded border border-red-900/30">Crítico</span></td>
                                                        </tr>
                                                    ))}
                                                </tbody>
                                            </table>
                                        </div>
                                        <div className="p-3 border-t border-slate-700 bg-slate-800">
                                            <Button onClick={handleDeactivateClick} variant="danger" size="sm" className="w-full">
                                                Desactivar Outliers Seleccionados
                                            </Button>
                                        </div>
                                    </>
                                ) : (
                                    <div className="p-8 text-center flex flex-col items-center justify-center h-full">
                                        <div className="h-12 w-12 bg-green-900/20 text-green-400 rounded-full flex items-center justify-center mb-3">
                                            <svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M5 13l4 4L19 7"></path></svg>
                                        </div>
                                        <p className="text-slate-200 font-medium">Todo limpio</p>
                                        <p className="text-sm text-slate-500">No se detectaron outliers espectrales significativos.</p>
                                    </div>
                                )}
                            </div>
                         </div>
                    </div>
                )}

                {activeTab === 'residuals' && (
                     <div className="animate-fade-in bg-slate-800 rounded-xl border border-slate-700 shadow-sm overflow-hidden">
                        <div className="max-h-[500px] overflow-y-auto custom-scrollbar">
                            <table className="w-full text-sm text-left">
                                <thead className="text-xs text-slate-400 uppercase bg-slate-900 sticky top-0 z-10 shadow-sm">
                                    <tr>
                                        <th className="px-6 py-3 font-semibold">ID Muestra</th>
                                        <th className="px-6 py-3 text-right font-semibold">Valor Real</th>
                                        <th className="px-6 py-3 text-right font-semibold">Valor Predicho</th>
                                        <th className="px-6 py-3 text-right font-semibold">Error Absoluto</th>
                                        <th className="px-6 py-3 text-right font-semibold">% Error Relativo</th>
                                    </tr>
                                </thead>
                                <tbody className="divide-y divide-slate-700">
                                    {residuals.map((r, idx) => {
                                        const relError = (Math.abs(r.residual) / Math.abs(r.actual)) * 100;
                                        const isHighError = Math.abs(r.residual) > results.model.sec * 2;
                                        return (
                                            <tr key={r.id} className={`hover:bg-slate-700/50 transition-colors ${idx % 2 === 0 ? 'bg-slate-800' : 'bg-slate-900/30'}`}>
                                                <td className="px-6 py-3 font-medium text-slate-300">{r.id}</td>
                                                <td className="px-6 py-3 text-right font-mono text-slate-400">{r.actual.toFixed(4)}</td>
                                                <td className="px-6 py-3 text-right font-mono text-slate-400">{r.predicted.toFixed(4)}</td>
                                                <td className={`px-6 py-3 text-right font-mono font-medium ${isHighError ? 'text-red-400' : 'text-slate-400'}`}>
                                                    {r.residual > 0 ? '+' : ''}{r.residual.toFixed(4)}
                                                </td>
                                                <td className="px-6 py-3 text-right font-mono text-slate-500">
                                                    {relError.toFixed(2)}%
                                                </td>
                                            </tr>
                                        );
                                    })}
                                </tbody>
                            </table>
                        </div>
                     </div>
                )}

                {activeTab === 'full-data' && (
                    <div className="flex flex-col items-center justify-center py-12 gap-6 animate-fade-in bg-slate-800 rounded-xl border border-slate-700 border-dashed">
                         <div className="text-center max-w-md">
                            <div className="bg-brand-900/20 h-16 w-16 rounded-full flex items-center justify-center mx-auto mb-4 text-brand-400 border border-brand-500/20">
                                <svg className="w-8 h-8" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M4 16v1a3 3 0 003 3h10a3 3 0 003-3v-1m-4-4l-4 4m0 0l-4-4m4 4V4"></path></svg>
                            </div>
                            <h3 className="text-lg font-semibold text-slate-200 mb-2">Exportación de Datos</h3>
                            <p className="text-slate-400 mb-6">Descargue los resultados completos para reportes externos o el archivo de configuración JSON para reproducir este modelo más tarde.</p>
                         </div>
                         <div className="flex gap-4">
                            <Button onClick={handleDownloadData} size="lg">
                                Descargar CSV
                            </Button>
                            <Button variant="secondary" onClick={handleExportConfig} size="lg">
                                Exportar Modelo (JSON)
                            </Button>
                         </div>
                    </div>
                )}
            </div>
        </Card>
    );
};

export default ResultsViewer;

import React, { useState, useCallback } from 'react';
import { Sample, PreprocessingStep, ModelResults } from './types';
import { parseCSV, DEMO_DATA_STRING } from './services/csvParser';
import { applyPreprocessingLogic, runPlsAnalysis } from './services/chemometrics';
import Header from './components/Header';
import Loader from './components/Loader';
import DataUploader from './components/DataUploader';
import SampleManager from './components/SampleManager';
import SpectraViewer from './components/SpectraViewer';
import PreprocessingEditor from './components/PreprocessingEditor';
import ModelGenerator, { ModelParams } from './components/ModelGenerator';
import ResultsViewer from './components/ResultsViewer';
import Card from './components/Card';

const App: React.FC = () => {
    const [loadingMessage, setLoadingMessage] = useState<string | null>(null);
    const [wavelengths, setWavelengths] = useState<number[]>([]);
    const [samples, setSamples] = useState<Sample[]>([]);
    const [analyticalProperty, setAnalyticalProperty] = useState<string>('Propiedad');
    const [preprocessingSteps, setPreprocessingSteps] = useState<PreprocessingStep[]>([]);
    const [modelResults, setModelResults] = useState<ModelResults | null>(null);
    const [processedSpectra, setProcessedSpectra] = useState<{ id: string | number; values: number[] }[] | null>(null);

    const handleDataLoaded = (data: { wavelengths: number[]; samples: Sample[]; analyticalProperty: string }) => {
        setWavelengths(data.wavelengths);
        setSamples(data.samples);
        setAnalyticalProperty(data.analyticalProperty);
        setModelResults(null);
        setProcessedSpectra(null);
        setPreprocessingSteps([]);
    };

    const handleFileSelected = (file: File) => {
        setLoadingMessage('Cargando datos...');
        parseCSV(file, (results) => {
            handleDataLoaded(results);
            setLoadingMessage(null);
        });
    };

    const handleLoadDemoData = () => {
        setLoadingMessage('Cargando datos de demostración...');
        setTimeout(() => {
            parseCSV(DEMO_DATA_STRING, (results) => {
                handleDataLoaded(results);
                setLoadingMessage(null);
            });
        }, 100);
    };

    const handleToggleSample = (index: number) => {
        setSamples(prev => prev.map((s, i) => i === index ? { ...s, active: !s.active } : s));
    };

    const handleToggleAllSamples = (active: boolean) => {
        setSamples(prev => prev.map(s => ({ ...s, active })));
    };

    const handleVisualizePreprocessing = () => {
        const activeSamples = samples.filter(s => s.active);
        if (activeSamples.length === 0) return;
        const processed = activeSamples.map(sample => ({
            ...sample,
            values: applyPreprocessingLogic(sample.values, preprocessingSteps)
        }));
        setProcessedSpectra(processed);
    };

    const handleResetVisualization = useCallback(() => {
        setProcessedSpectra(null);
    }, []);

    const handleRunModel = async (params: ModelParams) => {
        const activeSamples = samples.filter(s => s.active);
        if (activeSamples.length < 3) {
            alert('Se necesitan al menos 3 muestras activas para generar el modelo PLS y validación cruzada.');
            return;
        }
        setLoadingMessage(`Generando modelo ${params.type.toUpperCase()}...`);

        setTimeout(() => {
            try {
                const results = runPlsAnalysis(activeSamples, preprocessingSteps, params.nComponents);
                setModelResults(results);
            } catch (error) {
                console.error(`Error during ${params.type} run:`, error);
                const errorMessage = error instanceof Error ? error.message : "Ocurrió un error desconocido.";
                alert(`Ocurrió un error al generar el modelo: ${errorMessage}`);
            } finally {
                setLoadingMessage(null);
            }
        }, 100);
    };

    const handleDeactivateOutliers = (outlierIds: (string|number)[]) => {
         setSamples(prev => prev.map(s => outlierIds.includes(s.id) ? { ...s, active: false } : s));
         if (modelResults) {
             setTimeout(() => {
                const params: ModelParams = { type: 'pls', nComponents: modelResults.nComponents };
                handleRunModel(params);
             }, 100);
         }
    }

    const activeSamples = samples.filter(s => s.active);
    const spectraToDisplay = processedSpectra ? processedSpectra.map(p => {
        const originalSample = samples.find(s => s.id === p.id);
        return { ...p, color: originalSample?.color || '#000000' };
    }) : activeSamples;

    return (
        <>
            {loadingMessage && <Loader message={loadingMessage} />}
            <div className="min-h-screen flex flex-col bg-slate-800 text-slate-200">
                <Header />
                <main className="flex-grow p-4 lg:p-6 grid grid-cols-1 xl:grid-cols-4 gap-4 lg:gap-6">
                    {/* Controls Column */}
                    <div className="xl:col-span-1 flex flex-col gap-4 lg:gap-6">
                        <DataUploader onFileSelected={handleFileSelected} onLoadDemo={handleLoadDemoData} />
                        <SampleManager
                            samples={samples}
                            onToggle={handleToggleSample}
                            onToggleAll={handleToggleAllSamples}
                        />
                    </div>

                    {/* Visualization Column */}
                    <div className="xl:col-span-3 flex flex-col gap-4 lg:gap-6">
                        <SpectraViewer
                            wavelengths={wavelengths}
                            samples={spectraToDisplay}
                            isProcessed={!!processedSpectra}
                            onReset={handleResetVisualization}
                        />

                        <PreprocessingEditor
                            steps={preprocessingSteps}
                            setSteps={setPreprocessingSteps}
                            onVisualize={handleVisualizePreprocessing}
                            disabled={activeSamples.length === 0}
                        />

                        <ModelGenerator 
                            onRunModel={handleRunModel} 
                            disabled={activeSamples.length < 3}
                            activeSamples={activeSamples}
                            preprocessingSteps={preprocessingSteps}
                        />

                        {modelResults ? (
                            <ResultsViewer 
                                results={modelResults}
                                propertyName={analyticalProperty}
                                preprocessingSteps={preprocessingSteps}
                                activeSamples={activeSamples.map(s => s.id)}
                                onDeactivateOutliers={handleDeactivateOutliers}
                                wavelengths={wavelengths}
                            />
                        ) : (
                            <Card>
                                <div className="flex items-center justify-center h-40">
                                    <p className="text-slate-500">Genere un modelo PLS para ver los resultados estadísticos (R, SEC, SECV).</p>
                                </div>
                            </Card>
                        )}
                    </div>
                </main>
            </div>
        </>
    );
};

export default App;

