                                        <th className="px-6 py-3 text-right font-semibold">Valor Real</th>
                                        <th className="px-6 py-3 text-right font-semibold">Valor Predicho</th>
                                        <th className="px-6 py-3 text-right font-semibold">Error Absoluto</th>
                                        <th className="px-6 py-3 text-right font-semibold">% Error Relativo</th>
                                    </tr>
                                </thead>
                                <tbody className="divide-y divide-slate-700">
                                    {residuals.map((r, idx) => {
                                        const relError = (Math.abs(r.residual) / Math.abs(r.actual)) * 100;
                                        const isHighError = Math.abs(r.residual) > results.model.sec * 2;
                                        return (
                                            <tr key={r.id} className={`hover:bg-slate-700/50 transition-colors ${idx % 2 === 0 ? 'bg-slate-800' : 'bg-slate-700/30'}`}>
