import React from 'react';
import Card from './Card';
import Button from './Button';
import { PreprocessingStep } from '../types';

interface PreprocessingEditorProps {
    steps: PreprocessingStep[];
    setSteps: React.Dispatch<React.SetStateAction<PreprocessingStep[]>>;
    onVisualize: () => void;
    disabled: boolean;
}

const PREPROCESSING_METHODS = {
    'none': { name: 'Ninguno', params: [] },
    'savgol': {
        name: 'Savitzky-Golay',
        params: [
            { id: 'derivative', name: 'Orden Derivada', type: 'number', default: 1 },
            { id: 'windowSize', name: 'Tamaño Ventana (impar)', type: 'number', default: 5 },
            { id: 'polynomialOrder', name: 'Orden Polinomio', type: 'number', default: 2 },
        ],
    },
    'snv': { name: 'Standard Normal Variate (SNV)', params: [] },
    'msc': { name: 'Multiplicative Scatter Correction (MSC)', params: [] },
    'detrend': { name: 'Detrend', params: [] },
};

const EditIcon: React.FC = () => (
    <svg xmlns="http://www.w3.org/2000/svg" width="20" height="20" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round" className="text-brand-400"><path d="M12 20h9"></path><path d="M16.5 3.5a2.12 2.12 0 0 1 3 3L7 19l-4 1 1-4Z"></path></svg>
);
const VisualizeIcon: React.FC = () => (
    <svg xmlns="http://www.w3.org/2000/svg" width="16" height="16" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"><path d="m21.14 10.28-9.23-9.23a1.5 1.5 0 0 0-2.12 0l-9.23 9.23a1.5 1.5 0 0 0 0 2.12l9.23 9.23a1.5 1.5 0 0 0 2.12 0l9.23-9.23a1.5 1.5 0 0 0 0-2.12z"></path><path d="M12 22V2"></path></svg>
);
const AddIcon: React.FC = () => (
    <svg xmlns="http://www.w3.org/2000/svg" width="16" height="16" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"><line x1="12" y1="5" x2="12" y2="19"></line><line x1="5" y1="12" x2="19" y2="12"></line></svg>
);
const RemoveIcon: React.FC = () => (
    <svg xmlns="http://www.w3.org/2000/svg" width="16" height="16" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"><polyline points="3 6 5 6 21 6"></polyline><path d="M19 6v14a2 2 0 0 1-2 2H7a2 2 0 0 1-2-2V6m3 0V4a2 2 0 0 1 2-2h4a2 2 0 0 1 2 2v2"></path></svg>
);


const PreprocessingEditor: React.FC<PreprocessingEditorProps> = ({ steps, setSteps, onVisualize, disabled }) => {

    const addStep = () => {
        const newStep: PreprocessingStep = { method: 'savgol', params: {} };
        PREPROCESSING_METHODS['savgol'].params.forEach(p => newStep.params[p.id] = p.default);
        setSteps([...steps, newStep]);
    };

    const removeStep = (index: number) => {
        setSteps(steps.filter((_, i) => i !== index));
    };

    const handleMethodChange = (index: number, newMethod: PreprocessingStep['method']) => {
        const newSteps = [...steps];
        newSteps[index].method = newMethod;
        newSteps[index].params = {};
        (PREPROCESSING_METHODS[newMethod].params as any[]).forEach(p => {
            newSteps[index].params[p.id] = p.default;
        });
        setSteps(newSteps);
    };

    const handleParamChange = (stepIndex: number, paramId: string, value: string) => {
        const newSteps = [...steps];
        newSteps[stepIndex].params[paramId] = parseFloat(value);
        setSteps(newSteps);
    };

    return (
        <Card>
            <h2 className="text-lg font-bold mb-4 flex items-center gap-2 text-brand-400"><EditIcon />3. Pre-procesamiento</h2>
            <div className="space-y-3 mb-4">
                {steps.map((step, index) => {
                    const methodInfo = PREPROCESSING_METHODS[step.method];
                    return (
                        <div key={index} className="p-3 border border-slate-600 rounded-md bg-slate-800 shadow-sm">
                            <div className="flex items-center justify-between">
                                <select
                                    value={step.method}
                                    onChange={(e) => handleMethodChange(index, e.target.value as PreprocessingStep['method'])}
                                    className="w-full bg-slate-900 border border-slate-600 text-slate-200 rounded-md px-2 py-1 text-sm focus:outline-none focus:ring-1 focus:ring-brand-500"
                                >
                                    {Object.entries(PREPROCESSING_METHODS).map(([key, value]) => (
                                        <option key={key} value={key}>{value.name}</option>
                                    ))}
                                </select>
                                <button onClick={() => removeStep(index)} className="ml-2 p-1 text-slate-500 hover:text-red-400 transition-colors">
                                    <RemoveIcon />
                                </button>
                            </div>
                             {methodInfo.params.length > 0 && (
                                <div className="grid grid-cols-3 gap-2 mt-2">
                                    {(methodInfo.params as any[]).map(param => (
                                        <div key={param.id} className="text-xs">
                                            <label htmlFor={`${param.id}-${index}`} className="text-slate-400">{param.name}</label>
                                            <input
                                                type={param.type}
                                                id={`${param.id}-${index}`}
                                                value={step.params[param.id] || ''}
                                                onChange={(e) => handleParamChange(index, param.id, e.target.value)}
                                                className="w-full bg-slate-900 border border-slate-600 text-slate-200 rounded-md px-2 py-1 text-xs mt-1 focus:outline-none focus:ring-1 focus:ring-brand-500"
                                            />
                                        </div>
                                    ))}
                                </div>
                            )}
                        </div>
                    );
                })}
            </div>
            <div className="flex flex-col gap-2">
                <Button onClick={onVisualize} disabled={disabled}><VisualizeIcon />Visualizar Pre-procesamiento</Button>
                <Button variant="secondary" onClick={addStep} disabled={disabled}><AddIcon />Añadir Paso</Button>
            </div>
        </Card>
    );
};

export default PreprocessingEditor;

import React, { useRef, useState } from 'react';
import Card from './Card';
import Button from './Button';

interface DataUploaderProps {
    onFileSelected: (file: File) => void;
    onLoadDemo: () => void;
}

const DataUploader: React.FC<DataUploaderProps> = ({ onFileSelected, onLoadDemo }) => {
    const fileInputRef = useRef<HTMLInputElement>(null);
    const [fileName, setFileName] = useState('');
    const [isDragging, setIsDragging] = useState(false);

    const handleFileChange = (event: React.ChangeEvent<HTMLInputElement>) => {
        const file = event.target.files?.[0];
        if (file) processFile(file);
    };

    const processFile = (file: File) => {
        setFileName(file.name);
        onFileSelected(file);
    };

    const handleLoadDemo = () => {
        setFileName('demo_dataset_nir.csv');
        onLoadDemo();
    };

    const handleDragOver = (e: React.DragEvent) => {
        e.preventDefault();
        setIsDragging(true);
    };

    const handleDragLeave = () => {
        setIsDragging(false);
    };

    const handleDrop = (e: React.DragEvent) => {
        e.preventDefault();
        setIsDragging(false);
        const file = e.dataTransfer.files?.[0];
        if (file && file.name.endsWith('.csv')) {
            processFile(file);
        } else if (file) {
            alert("Por favor suba un archivo .csv");
        }
    };

    return (
        <Card className="h-full">
            <div className="flex items-center gap-2 mb-4 border-b border-slate-600 pb-2">
                <div className="h-6 w-6 bg-brand-900/50 text-brand-400 border border-brand-500/30 rounded-md flex items-center justify-center text-xs font-bold">1</div>
                <h2 className="text-base font-bold text-slate-100">Cargar Datos</h2>
            </div>

            <div className="space-y-4">
                <div 
                    className={`border-2 border-dashed rounded-lg p-6 text-center transition-all cursor-pointer ${isDragging ? 'border-brand-500 bg-brand-900/20' : 'border-slate-600 hover:border-brand-500/50 hover:bg-slate-600/30'}`}
                    onDragOver={handleDragOver}
                    onDragLeave={handleDragLeave}
                    onDrop={handleDrop}
                    onClick={() => fileInputRef.current?.click()}
                >
                    <input
                        type="file"
                        ref={fileInputRef}
                        accept=".csv"
                        onChange={handleFileChange}
                        className="hidden"
                    />
                    <div className="mx-auto h-10 w-10 text-slate-500 mb-2 group-hover:text-brand-400 transition-colors">
                        <svg xmlns="http://www.w3.org/2000/svg" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                            <path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M7 16a4 4 0 01-.88-7.903A5 5 0 1115.9 6L16 6a5 5 0 011 9.9M15 13l-3-3m0 0l-3 3m3-3v12" />
                        </svg>
                    </div>
                    <p className="text-sm font-medium text-slate-300">Click para subir CSV</p>
                    <p className="text-xs text-slate-500 mt-1">o arrastre el archivo aquí</p>
                </div>

                {fileName && (
                    <div className="flex items-center gap-2 text-xs bg-green-900/20 text-green-400 p-2 rounded border border-green-800 animate-fade-in">
                        <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M5 13l4 4L19 7"></path></svg>
                        <span className="truncate font-medium">{fileName}</span>
                    </div>
                )}

                <div className="relative">
                    <div className="absolute inset-0 flex items-center"><div className="w-full border-t border-slate-600"></div></div>
                    <div className="relative flex justify-center text-xs"><span className="px-2 bg-slate-700 text-slate-500">O use datos de prueba</span></div>
                </div>

                <Button variant="secondary" onClick={handleLoadDemo} className="w-full text-xs" size="sm">
                    Cargar Demo NIR
                </Button>

                <div className="text-[10px] text-slate-500 leading-tight bg-slate-800/50 p-2 rounded border border-slate-600/50">
                    <strong>Formato CSV:</strong> 1ª fila headers (IDs, wavelenghts, Propiedad). Última col debe ser el valor Y.
                </div>
            </div>
        </Card>
    );
};

export default DataUploader;

