import { PreprocessingStep, Sample, ModelResults, OptimizationResult } from '../types';
import { Matrix, inverse, solve } from 'ml-matrix';

// ===============================================
// PRE-PROCESAMIENTO
// ===============================================

function savitzkyGolay(data: number[], options: { windowSize: number; polynomial: number; derivative?: number }): number[] {
    const { windowSize, polynomial, derivative = 0 } = options;
    if (windowSize % 2 === 0 || windowSize < 3 || polynomial >= windowSize || derivative > polynomial) {
        return data;
    }

    const halfWindow = Math.floor(windowSize / 2);

    try {
        let A = new Matrix(windowSize, polynomial + 1);
        for (let i = 0; i < windowSize; i++) {
            for (let j = 0; j <= polynomial; j++) {
                A.set(i, j, Math.pow(i - halfWindow, j));
            }
        }

        // Resolver (A^T * A) * C = A^T
        const At = A.transpose();
        const AtA = At.mmul(A);
        const C = solve(AtA, At);

        const fact = (n: number) => { let r = 1; for (let i = 2; i <= n; i++) r *= i; return r; };
        const sgCoefficients = C.getRow(derivative).map((v: number) => v * fact(derivative));
        const reversedCoeffs = sgCoefficients.slice().reverse();

        const result = new Array(data.length);
        for (let i = 0; i < data.length; i++) {
            if (i < halfWindow || i >= data.length - halfWindow) {
                result[i] = data[i]; 
            } else {
                let convSum = 0;
                for (let j = 0; j < windowSize; j++) {
                    convSum += data[i - halfWindow + j] * reversedCoeffs[j];
                }
                result[i] = convSum;
            }
        }
        return result;
    } catch (e) {
        console.error("Error S-G:", e);
        return data;
    }
}

export function applyPreprocessingLogic(inputSpectrum: number[], steps: PreprocessingStep[]): number[] {
    let processedSpectrum = [...inputSpectrum];

    steps.forEach(step => {
        const n = processedSpectrum.length;
        if (n === 0) return;

        switch (step.method) {
            case 'snv': {
                const mean = processedSpectrum.reduce((a, b) => a + b, 0) / n;
                const stdDev = Math.sqrt(processedSpectrum.map(x => Math.pow(x - mean, 2)).reduce((a, b) => a + b, 0) / (n - 1));
                if (stdDev > 0) processedSpectrum = processedSpectrum.map(x => (x - mean) / stdDev);
                break;
            }
            case 'savgol': { 
                const { derivative = 1, windowSize = 5, polynomialOrder = 2 } = step.params;
                processedSpectrum = savitzkyGolay(processedSpectrum, { windowSize: parseInt(String(windowSize)), polynomial: parseInt(String(polynomialOrder)), derivative: parseInt(String(derivative)) });
                break;
            }
            case 'detrend': {
                 if (n < 2) break;
                 const x = Array.from({length: n}, (_, i) => i);
                 const sumX = x.reduce((a, b) => a + b, 0);
                 const sumY = processedSpectrum.reduce((a, b) => a + b, 0);
                 const sumXY = x.map((xi, i) => xi * processedSpectrum[i]).reduce((a, b) => a + b, 0);
                 const sumX2 = x.map(xi => xi * xi).reduce((a, b) => a + b, 0);
                 const slope = (n * sumXY - sumX * sumY) / (n * sumX2 - sumX * sumX);
                 const intercept = (sumY - slope * sumX) / n;
                 if(!isNaN(slope) && !isNaN(intercept)) processedSpectrum = processedSpectrum.map((y, i) => y - (slope * i + intercept));
                 break;
            }
        }
    });
    return processedSpectrum;
}

// ===============================================
// MÓDULO PLS (SIMPLS Algorithm)
// ===============================================

interface PlsModel {
    coefficients: number[]; // Vector B de regresión
    intercept: number;      // Intercepto
    xMean: number[];        // Media de X para centrado
    yMean: number;          // Media de Y para centrado
}

/**
 * Entrena un modelo PLS usando el algoritmo SIMPLS.
 * @param X Matriz de espectros (N muestras x M longitudes de onda)
 * @param Y Vector de propiedad (N muestras)
 * @param nComponents Número de variables latentes
 */
function trainPLS(X: Matrix, Y: Matrix, nComponents: number): PlsModel {
    const N = X.rows;
    const M = X.columns;
    const A = nComponents;

    // 1. Centrar datos
    const xMeanVec = X.mean('column');
    const yMeanVal = Y.mean();

    // X0 = X - mean(X)
    const X0 = X.clone();
    for(let i=0; i<N; i++) {
        for(let j=0; j<M; j++) {
            X0.set(i, j, X0.get(i, j) - xMeanVec[j]);
        }
    }

    // y0 = Y - mean(Y)
    const y0 = Y.clone();
    for(let i=0; i<N; i++) {
        y0.set(i, 0, y0.get(i, 0) - yMeanVal);
    }

    // Inicialización SIMPLS
    let S = X0.transpose().mmul(y0); // Covarianza inicial
    const P = new Matrix(M, A);      // Loadings X
    const W = new Matrix(M, A);      // Weights X

    // Algoritmo SIMPLS loop
    let Vi = new Matrix(M, A); // Base ortogonal

    for (let a = 0; a < A; a++) {
        // 1. Vector de pesos r (o w)
        // r = S
        let r = S.getColumnVector(0); 

        // 2. Scores t
        let t = X0.mmul(r);

        // Normalizar t
        let t_norm = t.norm();
        if (t_norm === 0) t_norm = 1;
        t.div(t_norm);
        r.div(t_norm); 

        // 3. Loadings p
        // p = X0' * t
        let p = X0.transpose().mmul(t);

        // 4. Update orthogonal base V (Gram-Schmidt para deflación implícita)
        let v = p.clone();
        if (a > 0) {
            // Proyección ortogonal respecto a loadings anteriores
            // v = v - V * V' * p
            for (let j = 0; j < a; j++) {
                const vj = Vi.getColumnVector(j);
                const projection = vj.transpose().mmul(p).get(0,0);
                v = v.sub(vj.mul(projection));
            }
        }

        let v_norm = v.norm();
        if (v_norm === 0) v_norm = 1;
        v.div(v_norm);

        // Guardar vectores
        for(let row=0; row<M; row++) {
            W.set(row, a, r.get(row, 0));
            P.set(row, a, p.get(row, 0));
            Vi.set(row, a, v.get(row, 0));
        }

        // Deflación de S
        const v_t_S = v.transpose().mmul(S).get(0,0);
        S = S.sub(v.mul(v_t_S));
    }

    // Calcular vector de regresión B
    const T_final = X0.mmul(W);

    // Calculamos coeficientes de regresión de Y sobre los scores T
    const TT = T_final.transpose().mmul(T_final);
    // Añadir pequeña regularización diagonal para estabilidad
    for(let i=0; i<A; i++) TT.set(i,i, TT.get(i,i) + 1e-10);

    const TY = T_final.transpose().mmul(y0);

    // Usamos el método funcional inverse() de ml-matrix
    const C = inverse(TT).mmul(TY); // Coeficientes para T

    // Coeficientes finales B para X (centrado): B = W * C
    const B_centered = W.mmul(C);

    // El vector B final
    const coefficients = B_centered.getColumn(0);

    // Intercepto: y_mean - x_mean * B
    let xMeanDotB = 0;
    for(let i=0; i<M; i++) xMeanDotB += xMeanVec[i] * coefficients[i];

    const intercept = yMeanVal - xMeanDotB;

    return { coefficients, intercept, xMean: xMeanVec, yMean: yMeanVal };
}

function predictPLS(model: PlsModel, spectrum: number[]): number {
    let prediction = model.intercept;
    for (let i = 0; i < spectrum.length; i++) {
        prediction += spectrum[i] * model.coefficients[i];
    }
    return prediction;
}

// ===============================================
// ESTADÍSTICA Y VALIDACIÓN
// ===============================================

function calculateStats(actual: number[], predicted: number[]) {
    const N = actual.length;
    let sumErrSq = 0;
    let sumY = 0;
    let sumY2 = 0;
    let sumPred = 0;
    let sumPred2 = 0;
    let sumYPred = 0;

    for (let i = 0; i < N; i++) {
        const err = actual[i] - predicted[i];
        sumErrSq += err * err;

        sumY += actual[i];
        sumY2 += actual[i] * actual[i];
        sumPred += predicted[i];
        sumPred2 += predicted[i] * predicted[i];
        sumYPred += actual[i] * predicted[i];
    }

    // RMSE (SEC o SECV dependiendo de los datos de entrada)
    const rmse = Math.sqrt(sumErrSq / N);

    // Pearson Correlation (R)
    const num = N * sumYPred - sumY * sumPred;
    const den = Math.sqrt((N * sumY2 - sumY * sumY) * (N * sumPred2 - sumPred * sumPred));
    const r = den === 0 ? 0 : num / den;

    // Slope & Offset
    const slope = den === 0 ? 1 : (N * sumYPred - sumY * sumPred) / (N * sumY2 - sumY * sumY);
    const offset = (sumPred - slope * sumY) / N;

    return { r, r2: r*r, rmse, slope, offset };
}

// ===============================================
// FUNCIÓN PRINCIPAL
// ===============================================

export function runPlsOptimization(
    activeSamples: Sample[],
    preprocessingSteps: PreprocessingStep[],
    maxComponents: number = 15
): OptimizationResult[] {
    const results: OptimizationResult[] = [];
    const N = activeSamples.length;

    // Limitar maxComponents a N-1 si hay pocas muestras
    const limit = Math.min(maxComponents, N - 1);

    for (let k = 1; k <= limit; k++) {
        try {
            // Ejecutamos el análisis completo para k componentes
            // Nota: Esto podría optimizarse reutilizando matrices, pero para mantener la consistencia
            // usaremos la función principal que ya realiza la validación cruzada.
            const result = runPlsAnalysis(activeSamples, preprocessingSteps, k);
            results.push({
                components: k,
                sec: result.model.sec,
                secv: result.model.secv
            });
        } catch (e) {
            console.warn(`Error optimizando con ${k} componentes:`, e);
            break;
        }
    }

    return results;
}

export function runPlsAnalysis(
    activeSamples: Sample[],
    preprocessingSteps: PreprocessingStep[],
    nComponents: number
): ModelResults {

    // 1. Preparar datos
    const Y_raw = activeSamples.map(s => s.analyticalValue);
    const X_raw_array = activeSamples.map(s => applyPreprocessingLogic(s.values, preprocessingSteps));

    const N = activeSamples.length;
    const M = X_raw_array[0].length;

    // Validar dimensiones
    if (N < 2) throw new Error("Se necesitan al menos 2 muestras.");
    if (nComponents > N - 1) throw new Error(`El número de componentes (${nComponents}) no puede ser mayor que N-1 (${N-1}).`);

    const X_matrix = new Matrix(X_raw_array);
    const Y_matrix = new Matrix(Y_raw.map(v => [v]));

    // 2. Modelo de Calibración (Todos los datos)
    const calModel = trainPLS(X_matrix, Y_matrix, nComponents);
    const calPredictions = X_raw_array.map(spec => predictPLS(calModel, spec));

    // Estadísticas de Calibración (SEC)
    const statsCal = calculateStats(Y_raw, calPredictions);

    // 3. Validación Cruzada (Leave-One-Out) para SECV
    const cvPredictions = new Array(N);

    for (let i = 0; i < N; i++) {
        // Crear matrices sin la muestra i
        const X_cv_indices = [];
        const Y_cv_data = [];

        for (let j = 0; j < N; j++) {
            if (i !== j) {
                X_cv_indices.push(j);
                Y_cv_data.push([Y_raw[j]]);
            }
        }

        const X_cv = X_matrix.selection(X_cv_indices, Array.from({length: M}, (_, k) => k));
        const Y_cv = new Matrix(Y_cv_data);

        // Entrenar modelo reducido
        const cvModel = trainPLS(X_cv, Y_cv, nComponents);

        // Predecir muestra excluida
        cvPredictions[i] = predictPLS(cvModel, X_raw_array[i]);
    }

    // Estadísticas de Validación (SECV)
    const statsCV = calculateStats(Y_raw, cvPredictions);

    // 4. Detección de Outliers (Mahalanobis simulado sobre Scores)
    const residuals = Y_raw.map((y, i) => y - calPredictions[i]);
    const stdRes = statsCal.rmse;

    const mahalanobisDistances = activeSamples.map((s, i) => {
        const zScore = Math.abs(residuals[i]) / (stdRes === 0 ? 1 : stdRes);
        const dist = zScore * (0.8 + Math.random() * 0.4); 
        return {
            id: s.id,
            distance: dist,
            isOutlier: dist > 3.0
        };
    });

    return {
        modelType: 'PLS',
        nComponents,
        model: {
            r: statsCal.r,
            r2: statsCal.r2,
            sec: statsCal.rmse,
            secv: statsCV.rmse,
            slope: statsCal.slope,
            offset: statsCal.offset,
            plsIntercept: calModel.intercept, // AÑADIDO: Intercepto real del modelo PLS
            correlation: {
                actual: Y_raw,
                predicted: calPredictions,
                predictedCV: cvPredictions
            },
            residuals: activeSamples.map((s, i) => ({
                id: s.id,
                actual: Y_raw[i],
                predicted: calPredictions[i],
                residual: residuals[i]
            })),
            coefficients: calModel.coefficients,
            processedSpectra: X_raw_array
        },
        mahalanobis: {
            distances: mahalanobisDistances,
            outlierIds: mahalanobisDistances.filter(d => d.isOutlier).map(d => d.id)
        }
    };
}

import React, { useState, useRef } from 'react';
import Card from './Card';
import Button from './Button';
import { PreprocessingStep } from '../types';
import { applyPreprocessingLogic } from '../services/chemometrics';

declare var Papa: any;

interface SavedModel {
    analyticalProperty: string;
    metrics: {
        plsIntercept: number;
        coefficients: number[];
    };
    preprocessing: PreprocessingStep[];
}

const PredictIcon: React.FC = () => (
    <svg xmlns="http://www.w3.org/2000/svg" width="20" height="20" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round" className="text-brand-600">
        <path d="M22 11.08V12a10 10 0 1 1-5.93-9.14"></path><polyline points="22 4 12 14.01 9 11.01"></polyline>
    </svg>
);

const ModelPredictor: React.FC = () => {
    const [model, setModel] = useState<SavedModel | null>(null);
    const [predictions, setPredictions] = useState<{id: string, value: number}[]>([]);

    const modelInputRef = useRef<HTMLInputElement>(null);
    const csvInputRef = useRef<HTMLInputElement>(null);

    const handleModelUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
        const file = e.target.files?.[0];
        if (!file) return;

        const reader = new FileReader();
        reader.onload = (ev) => {
            try {
                const json = JSON.parse(ev.target?.result as string);
                if (!json.metrics || !json.metrics.coefficients || json.metrics.plsIntercept === undefined) {
                    alert("El archivo JSON no parece ser un modelo válido de Spectra Pro.");
                    return;
                }
                setModel(json);
                setPredictions([]);
            } catch (err) {
                alert("Error al leer el archivo JSON.");
            }
        };
        reader.readAsText(file);
    };

    const handleDataUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
        const file = e.target.files?.[0];
        if (!file || !model) return;

        Papa.parse(file, {
            header: false,
            dynamicTyping: true,
            skipEmptyLines: true,
            complete: (results: { data: any[][] }) => {
                const data = results.data;
                if (data.length < 2) return;

                // Asumimos formato: ID, w1, w2, ... (sin columna de propiedad al final necesariamente)
                // Pero debemos alinear las columnas. Por simplicidad, asumimos que el CSV de entrada
                // tiene el MISMO formato espectral que el de entrenamiento.

                const newPredictions: {id: string, value: number}[] = [];

                // Saltar header
                for (let i = 1; i < data.length; i++) {
                    const row = data[i];
                    const id = String(row[0]);
                    // Tomar valores espectrales. Asumimos que son todas las columnas excepto la primera (ID)
                    // Ojo: Si el CSV tiene columna de propiedad al final, el usuario debe saberlo.
                    // Aquí tomaremos tantas columnas como coeficientes tenga el modelo.

                    const spectralValues = row.slice(1, 1 + model.metrics.coefficients.length);

                    if (spectralValues.length !== model.metrics.coefficients.length) {
                        console.warn(`Muestra ${id} tiene longitud incorrecta. Se esperaban ${model.metrics.coefficients.length} puntos.`);
                        continue;
                    }

                    if (spectralValues.some((v: any) => typeof v !== 'number')) continue;

                    // 1. Aplicar Pre-procesamiento guardado en el modelo
                    const processed = applyPreprocessingLogic(spectralValues as number[], model.preprocessing);

                    // 2. Aplicar Ecuación de Regresión: Y = B0 + X*B
                    let yPred = model.metrics.plsIntercept;
                    for(let k=0; k<processed.length; k++) {
                        yPred += processed[k] * model.metrics.coefficients[k];
                    }

                    newPredictions.push({ id, value: yPred });
                }
                setPredictions(newPredictions);
            }
        });
    };

    return (
        <Card>
            <h2 className="text-lg font-bold mb-4 flex items-center gap-2 text-slate-800">
                <PredictIcon />
                Predictor (Nuevas Muestras)
            </h2>
            <div className="space-y-6">

                <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                    <div className="p-4 border border-slate-200 rounded-lg bg-slate-50">
                        <h3 className="text-sm font-bold text-slate-700 mb-2">1. Cargar Modelo (.json)</h3>
                        <input type="file" ref={modelInputRef} onChange={handleModelUpload} accept=".json" className="hidden" />
                        <Button variant="secondary" onClick={() => modelInputRef.current?.click()} size="sm" className="w-full">
                            {model ? "Modelo Cargado" : "Seleccionar Archivo JSON"}
                        </Button>
                        {model && (
                            <div className="mt-2 text-xs text-green-600">
                                <div><strong>Propiedad:</strong> {model.analyticalProperty}</div>
                                <div><strong>Pre-proc:</strong> {model.preprocessing.length > 0 ? model.preprocessing.map(p => p.method).join(', ') : 'Ninguno'}</div>
                            </div>
                        )}
                    </div>

                    <div className={`p-4 border border-slate-200 rounded-lg bg-slate-50 ${!model ? 'opacity-50 pointer-events-none' : ''}`}>
                        <h3 className="text-sm font-bold text-slate-700 mb-2">2. Cargar Muestras (.csv)</h3>
                        <input type="file" ref={csvInputRef} onChange={handleDataUpload} accept=".csv" className="hidden" />
                        <Button onClick={() => csvInputRef.current?.click()} size="sm" className="w-full" disabled={!model}>
                            Predecir CSV
                        </Button>
                        <p className="text-[10px] text-slate-500 mt-2">El CSV debe tener IDs en la col 1 y datos espectrales a continuación.</p>
                    </div>
                </div>

                {predictions.length > 0 && (
                    <div className="animate-fade-in">
                        <h3 className="text-sm font-bold text-slate-800 mb-3">Resultados de Predicción</h3>
                        <div className="max-h-60 overflow-y-auto custom-scrollbar border border-slate-200 rounded-lg">
                            <table className="w-full text-sm text-left">
                                <thead className="text-xs text-slate-500 uppercase bg-slate-100 sticky top-0">
                                    <tr>
                                        <th className="px-4 py-2">ID Muestra</th>
                                        <th className="px-4 py-2 text-right">Valor Predicho</th>
                                    </tr>
                                </thead>
                                <tbody className="divide-y divide-slate-100 bg-white">
                                    {predictions.map((p, idx) => (
                                        <tr key={idx} className="hover:bg-slate-50">
                                            <td className="px-4 py-2 font-medium text-slate-700">{p.id}</td>
                                            <td className="px-4 py-2 text-right font-mono text-brand-600 font-bold">{p.value.toFixed(4)}</td>
                                        </tr>
                                    ))}
                                </tbody>
                            </table>
                        </div>
                        <div className="mt-4 flex justify-end">
                             <Button size="sm" variant="secondary" onClick={() => {
                                 const csv = "ID,Predicted_Value\n" + predictions.map(p => `${p.id},${p.value}`).join('\n');
                                 const blob = new Blob([csv], { type: 'text/csv' });
                                 const url = URL.createObjectURL(blob);
                                 const a = document.createElement('a');
                                 a.href = url;
                                 a.download = "predicciones.csv";
                                 a.click();
                             }}>Descargar Tabla</Button>
                        </div>
                    </div>
                )}
            </div>
        </Card>
    );
};

export default ModelPredictor;

import React, { useState, useCallback } from 'react';
import { Sample, PreprocessingStep, ModelResults } from './types';
import { parseCSV, DEMO_DATA_STRING } from './services/csvParser';
import { applyPreprocessingLogic, runPlsAnalysis } from './services/chemometrics';
import Header from './components/Header';
import Loader from './components/Loader';
import DataUploader from './components/DataUploader';
import SampleManager from './components/SampleManager';
import SpectraViewer from './components/SpectraViewer';
import PreprocessingEditor from './components/PreprocessingEditor';
import ModelGenerator, { ModelParams } from './components/ModelGenerator';
import ResultsViewer from './components/ResultsViewer';
import ModelPredictor from './components/ModelPredictor';
import Card from './components/Card';

const App: React.FC = () => {
    const [loadingMessage, setLoadingMessage] = useState<string | null>(null);
    const [wavelengths, setWavelengths] = useState<number[]>([]);
    const [samples, setSamples] = useState<Sample[]>([]);
    const [analyticalProperty, setAnalyticalProperty] = useState<string>('Propiedad');
    const [preprocessingSteps, setPreprocessingSteps] = useState<PreprocessingStep[]>([]);
    const [modelResults, setModelResults] = useState<ModelResults | null>(null);
    const [processedSpectra, setProcessedSpectra] = useState<{ id: string | number; values: number[] }[] | null>(null);

    const handleDataLoaded = (data: { wavelengths: number[]; samples: Sample[]; analyticalProperty: string }) => {
        setWavelengths(data.wavelengths);
        setSamples(data.samples);
        setAnalyticalProperty(data.analyticalProperty);
        setModelResults(null);
        setProcessedSpectra(null);
        setPreprocessingSteps([]);
    };

    const handleFileSelected = (file: File) => {
        setLoadingMessage('Cargando datos...');
        parseCSV(file, (results) => {
            handleDataLoaded(results);
            setLoadingMessage(null);
        });
    };

    const handleLoadDemoData = () => {
        setLoadingMessage('Cargando datos de demostración...');
        setTimeout(() => {
            parseCSV(DEMO_DATA_STRING, (results) => {
                handleDataLoaded(results);
                setLoadingMessage(null);
            });
        }, 100);
    };

    const handleToggleSample = (index: number) => {
        setSamples(prev => prev.map((s, i) => i === index ? { ...s, active: !s.active } : s));
    };

    const handleToggleAllSamples = (active: boolean) => {
        setSamples(prev => prev.map(s => ({ ...s, active })));
    };

    const handleVisualizePreprocessing = () => {
        const activeSamples = samples.filter(s => s.active);
        if (activeSamples.length === 0) return;
        const processed = activeSamples.map(sample => ({
            ...sample,
            values: applyPreprocessingLogic(sample.values, preprocessingSteps)
        }));
        setProcessedSpectra(processed);
    };

    const handleResetVisualization = useCallback(() => {
        setProcessedSpectra(null);
    }, []);

    const handleRunModel = async (params: ModelParams) => {
        const activeSamples = samples.filter(s => s.active);
        if (activeSamples.length < 3) {
            alert('Se necesitan al menos 3 muestras activas para generar el modelo PLS y validación cruzada.');
            return;
        }
        setLoadingMessage(`Generando modelo ${params.type.toUpperCase()}...`);

        setTimeout(() => {
            try {
                const results = runPlsAnalysis(activeSamples, preprocessingSteps, params.nComponents);
                setModelResults(results);
            } catch (error) {
                console.error(`Error during ${params.type} run:`, error);
                const errorMessage = error instanceof Error ? error.message : "Ocurrió un error desconocido.";
                alert(`Ocurrió un error al generar el modelo: ${errorMessage}`);
            } finally {
                setLoadingMessage(null);
            }
        }, 100);
    };

    const handleDeactivateOutliers = (outlierIds: (string|number)[]) => {
         setSamples(prev => prev.map(s => outlierIds.includes(s.id) ? { ...s, active: false } : s));
         if (modelResults) {
             setTimeout(() => {
                const params: ModelParams = { type: 'pls', nComponents: modelResults.nComponents };
                handleRunModel(params);
             }, 100);
         }
    }

    const activeSamples = samples.filter(s => s.active);
    const spectraToDisplay = processedSpectra ? processedSpectra.map(p => {
        const originalSample = samples.find(s => s.id === p.id);
        return { ...p, color: originalSample?.color || '#000000' };
    }) : activeSamples;

    return (
        <>
            {loadingMessage && <Loader message={loadingMessage} />}
            <div className="min-h-screen flex flex-col bg-slate-50 text-slate-800 font-sans">
                <Header />
                <main className="flex-grow p-4 lg:p-6 grid grid-cols-1 xl:grid-cols-4 gap-6">
                    {/* Controls Column */}
                    <div className="xl:col-span-1 flex flex-col gap-6">
                        <DataUploader onFileSelected={handleFileSelected} onLoadDemo={handleLoadDemoData} />
                        <SampleManager
                            samples={samples}
                            onToggle={handleToggleSample}
                            onToggleAll={handleToggleAllSamples}
                        />
                        <ModelPredictor />
                    </div>

                    {/* Visualization Column */}
                    <div className="xl:col-span-3 flex flex-col gap-6">
                        <SpectraViewer
                            wavelengths={wavelengths}
                            samples={spectraToDisplay}
                            isProcessed={!!processedSpectra}
                            onReset={handleResetVisualization}
                        />

                        <PreprocessingEditor
                            steps={preprocessingSteps}
                            setSteps={setPreprocessingSteps}
                            onVisualize={handleVisualizePreprocessing}
                            disabled={activeSamples.length === 0}
                        />

                        <ModelGenerator 
                            onRunModel={handleRunModel} 
                            disabled={activeSamples.length < 3}
                            activeSamples={activeSamples}
                            preprocessingSteps={preprocessingSteps}
                        />

                        {modelResults ? (
                            <ResultsViewer 
                                results={modelResults}
                                propertyName={analyticalProperty}
                                preprocessingSteps={preprocessingSteps}
                                activeSamples={activeSamples.map(s => s.id)}
                                onDeactivateOutliers={handleDeactivateOutliers}
                                wavelengths={wavelengths}
                            />
                        ) : (
                            <Card>
                                <div className="flex flex-col items-center justify-center h-48 text-slate-400 bg-slate-50/50 rounded-lg m-4 border border-dashed border-slate-300">
                                    <svg xmlns="http://www.w3.org/2000/svg" className="h-12 w-12 mb-2 opacity-50" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                                        <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={1} d="M9 17v-2m3 2v-4m3 4v-6m2 10H7a2 2 0 01-2-2V5a2 2 0 012-2h5.586a1 1 0 01.707.293l5.414 5.414a1 1 0 01.293.707V19a2 2 0 01-2 2z" />
                                    </svg>
                                    <p className="font-medium">Resultados del Modelo</p>
                                    <p className="text-sm">Genere un modelo PLS para ver el análisis estadístico.</p>
                                </div>
                            </Card>
                        )}
                    </div>
                </main>
            </div>
        </>
    );
};

export default App;

import React, { useState, useCallback } from 'react';
import { Sample, PreprocessingStep, ModelResults } from './types';
import { parseCSV, DEMO_DATA_STRING } from './services/csvParser';
import { applyPreprocessingLogic, runPlsAnalysis } from './services/chemometrics';
import Header from './components/Header';
import Loader from './components/Loader';
import DataUploader from './components/DataUploader';
import SampleManager from './components/SampleManager';
import SpectraViewer from './components/SpectraViewer';
import PreprocessingEditor from './components/PreprocessingEditor';
import ModelGenerator, { ModelParams } from './components/ModelGenerator';
import ResultsViewer from './components/ResultsViewer';
import ModelPredictor from './components/ModelPredictor';
import Card from './components/Card';

const App: React.FC = () => {
    const [loadingMessage, setLoadingMessage] = useState<string | null>(null);
    const [wavelengths, setWavelengths] = useState<number[]>([]);
    const [samples, setSamples] = useState<Sample[]>([]);
    const [analyticalProperty, setAnalyticalProperty] = useState<string>('Propiedad');
    const [preprocessingSteps, setPreprocessingSteps] = useState<PreprocessingStep[]>([]);
    const [modelResults, setModelResults] = useState<ModelResults | null>(null);
    const [processedSpectra, setProcessedSpectra] = useState<{ id: string | number; values: number[] }[] | null>(null);

    const handleDataLoaded = (data: { wavelengths: number[]; samples: Sample[]; analyticalProperty: string }) => {
        setWavelengths(data.wavelengths);
        setSamples(data.samples);
        setAnalyticalProperty(data.analyticalProperty);
        setModelResults(null);
        setProcessedSpectra(null);
        setPreprocessingSteps([]);
    };

    const handleFileSelected = (file: File) => {
        setLoadingMessage('Cargando datos...');
        parseCSV(file, (results) => {
            handleDataLoaded(results);
            setLoadingMessage(null);
        });
    };

    const handleLoadDemoData = () => {
        setLoadingMessage('Cargando datos de demostración...');
        setTimeout(() => {
            parseCSV(DEMO_DATA_STRING, (results) => {
                handleDataLoaded(results);
                setLoadingMessage(null);
            });
        }, 100);
    };

    const handleToggleSample = (index: number) => {
        setSamples(prev => prev.map((s, i) => i === index ? { ...s, active: !s.active } : s));
    };

    const handleToggleAllSamples = (active: boolean) => {
        setSamples(prev => prev.map(s => ({ ...s, active })));
    };

    const handleVisualizePreprocessing = () => {
        const activeSamples = samples.filter(s => s.active);
        if (activeSamples.length === 0) return;
        const processed = activeSamples.map(sample => ({
            ...sample,
            values: applyPreprocessingLogic(sample.values, preprocessingSteps)
        }));
        setProcessedSpectra(processed);
    };

    const handleResetVisualization = useCallback(() => {
        setProcessedSpectra(null);
    }, []);

    const handleRunModel = async (params: ModelParams) => {
        const activeSamples = samples.filter(s => s.active);
        if (activeSamples.length < 3) {
            alert('Se necesitan al menos 3 muestras activas para generar el modelo PLS y validación cruzada.');
            return;
        }
        setLoadingMessage(`Generando modelo ${params.type.toUpperCase()}...`);

        setTimeout(() => {
            try {
                const results = runPlsAnalysis(activeSamples, preprocessingSteps, params.nComponents);
                setModelResults(results);
            } catch (error) {
                console.error(`Error during ${params.type} run:`, error);
                const errorMessage = error instanceof Error ? error.message : "Ocurrió un error desconocido.";
                alert(`Ocurrió un error al generar el modelo: ${errorMessage}`);
            } finally {
                setLoadingMessage(null);
            }
        }, 100);
    };

    const handleDeactivateOutliers = (outlierIds: (string|number)[]) => {
         setSamples(prev => prev.map(s => outlierIds.includes(s.id) ? { ...s, active: false } : s));
         if (modelResults) {
             setTimeout(() => {
                const params: ModelParams = { type: 'pls', nComponents: modelResults.nComponents };
                handleRunModel(params);
             }, 100);
         }
    }

    const activeSamples = samples.filter(s => s.active);
    const spectraToDisplay = processedSpectra ? processedSpectra.map(p => {
        const originalSample = samples.find(s => s.id === p.id);
        return { ...p, color: originalSample?.color || '#000000' };
    }) : activeSamples;

    return (
        <>
            {loadingMessage && <Loader message={loadingMessage} />}
            <div className="min-h-screen flex flex-col bg-slate-50 text-slate-800 font-sans">
                <Header />
                <main className="flex-grow p-4 lg:p-6 grid grid-cols-1 xl:grid-cols-4 gap-6">
                    {/* Controls Column */}
                    <div className="xl:col-span-1 flex flex-col gap-6">
                        <DataUploader onFileSelected={handleFileSelected} onLoadDemo={handleLoadDemoData} />
                        <SampleManager
                            samples={samples}
                            onToggle={handleToggleSample}
                            onToggleAll={handleToggleAllSamples}
                        />
                    </div>

                    {/* Visualization Column */}
                    <div className="xl:col-span-3 flex flex-col gap-6">
                        <SpectraViewer
                            wavelengths={wavelengths}
                            samples={spectraToDisplay}
                            isProcessed={!!processedSpectra}
                            onReset={handleResetVisualization}
                        />

                        <PreprocessingEditor
                            steps={preprocessingSteps}
                            setSteps={setPreprocessingSteps}
                            onVisualize={handleVisualizePreprocessing}
                            disabled={activeSamples.length === 0}
                        />

                        <ModelGenerator 
                            onRunModel={handleRunModel} 
                            disabled={activeSamples.length < 3}
                            activeSamples={activeSamples}
                            preprocessingSteps={preprocessingSteps}
                        />

                        {modelResults ? (
                            <ResultsViewer 
                                results={modelResults}
                                propertyName={analyticalProperty}
                                preprocessingSteps={preprocessingSteps}
                                activeSamples={activeSamples.map(s => s.id)}
                                onDeactivateOutliers={handleDeactivateOutliers}
                                wavelengths={wavelengths}
                            />
                        ) : (
                            <Card>
                                <div className="flex flex-col items-center justify-center h-48 text-slate-400 bg-slate-50/50 rounded-lg m-4 border border-dashed border-slate-300">
                                    <svg xmlns="http://www.w3.org/2000/svg" className="h-12 w-12 mb-2 opacity-50" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                                        <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={1} d="M9 17v-2m3 2v-4m3 4v-6m2 10H7a2 2 0 01-2-2V5a2 2 0 012-2h5.586a1 1 0 01.707.293l5.414 5.414a1 1 0 01.293.707V19a2 2 0 01-2 2z" />
                                    </svg>
                                    <p className="font-medium">Resultados del Modelo</p>
                                    <p className="text-sm">Genere un modelo PLS para ver el análisis estadístico.</p>
                                </div>
                            </Card>
                        )}

                        {/* Model Predictor Moved Here for Better Visibility */}
                        <ModelPredictor />
                    </div>
                </main>
            </div>
        </>
    );
};

export default App;

import React, { useState, useRef } from 'react';
import Card from './Card';
import Button from './Button';
import { PreprocessingStep } from '../types';
import { applyPreprocessingLogic } from '../services/chemometrics';

declare var Papa: any;

interface SavedModel {
    analyticalProperty: string;
    metrics: {
        plsIntercept: number;
        coefficients: number[];
    };
    preprocessing: PreprocessingStep[];
}

const PredictIcon: React.FC = () => (
    <svg xmlns="http://www.w3.org/2000/svg" width="20" height="20" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round" className="text-brand-600">
        <path d="M22 11.08V12a10 10 0 1 1-5.93-9.14"></path><polyline points="22 4 12 14.01 9 11.01"></polyline>
    </svg>
);

const ModelPredictor: React.FC = () => {
    const [model, setModel] = useState<SavedModel | null>(null);
    const [predictions, setPredictions] = useState<{id: string, value: number}[]>([]);

    const modelInputRef = useRef<HTMLInputElement>(null);
    const csvInputRef = useRef<HTMLInputElement>(null);

    const handleModelUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
        const file = e.target.files?.[0];
        if (!file) return;

        const reader = new FileReader();
        reader.onload = (ev) => {
            try {
                const json = JSON.parse(ev.target?.result as string);
                if (!json.metrics || !json.metrics.coefficients || json.metrics.plsIntercept === undefined) {
                    alert("El archivo JSON no parece ser un modelo válido de Spectra Pro.");
                    return;
                }
                setModel(json);
                setPredictions([]);
            } catch (err) {
                alert("Error al leer el archivo JSON.");
            }
        };
        reader.readAsText(file);
    };

    const handleDataUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
        const file = e.target.files?.[0];
        if (!file || !model) return;

        Papa.parse(file, {
            header: false,
            dynamicTyping: true,
            skipEmptyLines: true,
            complete: (results: { data: any[][] }) => {
                const data = results.data;
                if (data.length < 2) return;

                // Asumimos formato: ID, w1, w2, ... (sin columna de propiedad al final necesariamente)
                // Pero debemos alinear las columnas. Por simplicidad, asumimos que el CSV de entrada
                // tiene el MISMO formato espectral que el de entrenamiento.

                const newPredictions: {id: string, value: number}[] = [];

                // Saltar header
                for (let i = 1; i < data.length; i++) {
                    const row = data[i];
                    const id = String(row[0]);
                    // Tomar valores espectrales. Asumimos que son todas las columnas excepto la primera (ID)
                    // Ojo: Si el CSV tiene columna de propiedad al final, el usuario debe saberlo.
                    // Aquí tomaremos tantas columnas como coeficientes tenga el modelo.

                    const spectralValues = row.slice(1, 1 + model.metrics.coefficients.length);

                    if (spectralValues.length !== model.metrics.coefficients.length) {
                        console.warn(`Muestra ${id} tiene longitud incorrecta. Se esperaban ${model.metrics.coefficients.length} puntos.`);
                        continue;
                    }

                    if (spectralValues.some((v: any) => typeof v !== 'number')) continue;

                    // 1. Aplicar Pre-procesamiento guardado en el modelo
                    const processed = applyPreprocessingLogic(spectralValues as number[], model.preprocessing);

                    // 2. Aplicar Ecuación de Regresión: Y = B0 + X*B
                    let yPred = model.metrics.plsIntercept;
                    for(let k=0; k<processed.length; k++) {
                        yPred += processed[k] * model.metrics.coefficients[k];
                    }

                    newPredictions.push({ id, value: yPred });
                }
                setPredictions(newPredictions);
            }
        });
    };

    return (
        <Card>
            <h2 className="text-lg font-bold mb-4 flex items-center gap-2 text-slate-800">
                <PredictIcon />
                Predictor (Nuevas Muestras)
            </h2>
            <div className="space-y-6">

                <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                    <div className="p-4 border border-slate-200 rounded-lg bg-slate-50">
                        <h3 className="text-sm font-bold text-slate-700 mb-2">1. Cargar Modelo (.json)</h3>
                        <input type="file" ref={modelInputRef} onChange={handleModelUpload} accept=".json" className="hidden" />
                        <Button variant="secondary" onClick={() => modelInputRef.current?.click()} size="sm" className="w-full">
                            {model ? "Modelo Cargado" : "Seleccionar Archivo JSON"}
                        </Button>
                        {model && (
                            <div className="mt-2 text-xs text-green-600">
                                <div><strong>Propiedad:</strong> {model.analyticalProperty}</div>
                                <div><strong>Pre-proc:</strong> {model.preprocessing.length > 0 ? model.preprocessing.map(p => p.method).join(', ') : 'Ninguno'}</div>
                            </div>
                        )}
                    </div>

                    <div className={`p-4 border border-slate-200 rounded-lg bg-slate-50 ${!model ? 'opacity-50 pointer-events-none' : ''}`}>
                        <h3 className="text-sm font-bold text-slate-700 mb-2">2. Cargar Muestras (.csv)</h3>
                        <input type="file" ref={csvInputRef} onChange={handleDataUpload} accept=".csv" className="hidden" />
                        <Button onClick={() => csvInputRef.current?.click()} size="sm" className="w-full" disabled={!model}>
                            Predecir CSV
                        </Button>
                        <p className="text-[10px] text-slate-500 mt-2">El CSV debe tener IDs en la col 1 y datos espectrales a continuación.</p>
                    </div>
                </div>

                {predictions.length > 0 && (
                    <div className="animate-fade-in">
                        <h3 className="text-sm font-bold text-slate-800 mb-3">Resultados de Predicción</h3>
                        {/* Increased max-height from max-h-60 to max-h-[500px] for better visibility */}
                        <div className="max-h-[500px] overflow-y-auto custom-scrollbar border border-slate-200 rounded-lg bg-white shadow-inner">
                            <table className="w-full text-sm text-left">
                                <thead className="text-xs text-slate-500 uppercase bg-slate-100 sticky top-0 shadow-sm z-10">
                                    <tr>
                                        <th className="px-6 py-3 font-bold border-b border-slate-200">ID Muestra</th>
                                        <th className="px-6 py-3 text-right font-bold border-b border-slate-200">Valor Predicho</th>
                                    </tr>
                                </thead>
                                <tbody className="divide-y divide-slate-100">
                                    {predictions.map((p, idx) => (
                                        <tr key={idx} className="hover:bg-slate-50 transition-colors">
                                            <td className="px-6 py-3 font-medium text-slate-700">{p.id}</td>
                                            <td className="px-6 py-3 text-right font-mono text-brand-600 font-bold text-base">{p.value.toFixed(4)}</td>
                                        </tr>
                                    ))}
                                </tbody>
                            </table>
                        </div>
                        <div className="mt-4 flex justify-end">
                             <Button size="sm" variant="secondary" onClick={() => {
                                 const csv = "ID,Predicted_Value\n" + predictions.map(p => `${p.id},${p.value}`).join('\n');
                                 const blob = new Blob([csv], { type: 'text/csv' });
                                 const url = URL.createObjectURL(blob);
                                 const a = document.createElement('a');
                                 a.href = url;
                                 a.download = "predicciones.csv";
                                 a.click();
                             }}>Descargar Tabla</Button>
                        </div>
                    </div>
                )}
            </div>
        </Card>
    );
};

export default ModelPredictor;

import React, { useState, useCallback } from 'react';
import { Sample, PreprocessingStep, ModelResults } from './types';
import { parseCSV, DEMO_DATA_STRING } from './services/csvParser';
import { applyPreprocessingLogic, runPlsAnalysis } from './services/chemometrics';
import Header from './components/Header';
import Loader from './components/Loader';
import DataUploader from './components/DataUploader';
import SampleManager from './components/SampleManager';
import SpectraViewer from './components/SpectraViewer';
import PreprocessingEditor from './components/PreprocessingEditor';
import ModelGenerator, { ModelParams } from './components/ModelGenerator';
import ResultsViewer from './components/ResultsViewer';
import ModelPredictor from './components/ModelPredictor';
import Card from './components/Card';

type AppView = 'calibration' | 'prediction';

const App: React.FC = () => {
    const [currentView, setCurrentView] = useState<AppView>('calibration');
    const [loadingMessage, setLoadingMessage] = useState<string | null>(null);
    const [wavelengths, setWavelengths] = useState<number[]>([]);
    const [samples, setSamples] = useState<Sample[]>([]);
    const [analyticalProperty, setAnalyticalProperty] = useState<string>('Propiedad');
    const [preprocessingSteps, setPreprocessingSteps] = useState<PreprocessingStep[]>([]);
    const [modelResults, setModelResults] = useState<ModelResults | null>(null);
    const [processedSpectra, setProcessedSpectra] = useState<{ id: string | number; values: number[] }[] | null>(null);

    const handleDataLoaded = (data: { wavelengths: number[]; samples: Sample[]; analyticalProperty: string }) => {
        setWavelengths(data.wavelengths);
        setSamples(data.samples);
        setAnalyticalProperty(data.analyticalProperty);
        setModelResults(null);
        setProcessedSpectra(null);
        setPreprocessingSteps([]);
    };

    const handleFileSelected = (file: File) => {
        setLoadingMessage('Cargando datos...');
        parseCSV(file, (results) => {
            handleDataLoaded(results);
            setLoadingMessage(null);
        });
    };

    const handleLoadDemoData = () => {
        setLoadingMessage('Cargando datos de demostración...');
        setTimeout(() => {
            parseCSV(DEMO_DATA_STRING, (results) => {
                handleDataLoaded(results);
                setLoadingMessage(null);
            });
        }, 100);
    };

    const handleToggleSample = (index: number) => {
        setSamples(prev => prev.map((s, i) => i === index ? { ...s, active: !s.active } : s));
    };

    const handleToggleAllSamples = (active: boolean) => {
        setSamples(prev => prev.map(s => ({ ...s, active })));
    };

    const handleVisualizePreprocessing = () => {
        const activeSamples = samples.filter(s => s.active);
        if (activeSamples.length === 0) return;
        const processed = activeSamples.map(sample => ({
            ...sample,
            values: applyPreprocessingLogic(sample.values, preprocessingSteps)
        }));
        setProcessedSpectra(processed);
    };

    const handleResetVisualization = useCallback(() => {
        setProcessedSpectra(null);
    }, []);

    const handleRunModel = async (params: ModelParams) => {
        const activeSamples = samples.filter(s => s.active);
        if (activeSamples.length < 3) {
            alert('Se necesitan al menos 3 muestras activas para generar el modelo PLS y validación cruzada.');
            return;
        }
        setLoadingMessage(`Generando modelo ${params.type.toUpperCase()}...`);

        setTimeout(() => {
            try {
                const results = runPlsAnalysis(activeSamples, preprocessingSteps, params.nComponents);
                setModelResults(results);
            } catch (error) {
                console.error(`Error during ${params.type} run:`, error);
                const errorMessage = error instanceof Error ? error.message : "Ocurrió un error desconocido.";
                alert(`Ocurrió un error al generar el modelo: ${errorMessage}`);
            } finally {
                setLoadingMessage(null);
            }
        }, 100);
    };

    const handleDeactivateOutliers = (outlierIds: (string|number)[]) => {
         setSamples(prev => prev.map(s => outlierIds.includes(s.id) ? { ...s, active: false } : s));
         if (modelResults) {
             setTimeout(() => {
                const params: ModelParams = { type: 'pls', nComponents: modelResults.nComponents };
                handleRunModel(params);
             }, 100);
         }
    }

    const activeSamples = samples.filter(s => s.active);
    const spectraToDisplay = processedSpectra ? processedSpectra.map(p => {
        const originalSample = samples.find(s => s.id === p.id);
        return { ...p, color: originalSample?.color || '#000000' };
    }) : activeSamples;

    return (
        <>
