import React, { useRef, useState } from 'react';
import Card from './Card';
import Button from './Button';

interface DataUploaderProps {
    onFileSelected: (file: File) => void;
    onLoadDemo: () => void;
}

const DataUploader: React.FC<DataUploaderProps> = ({ onFileSelected, onLoadDemo }) => {
    const fileInputRef = useRef<HTMLInputElement>(null);
    const [fileName, setFileName] = useState('');
    const [isDragging, setIsDragging] = useState(false);

    const handleFileChange = (event: React.ChangeEvent<HTMLInputElement>) => {
        const file = event.target.files?.[0];
        if (file) processFile(file);
    };

    const processFile = (file: File) => {
        setFileName(file.name);
        onFileSelected(file);
    };

    const handleLoadDemo = () => {
        setFileName('demo_dataset_nir.csv');
        onLoadDemo();
    };

    const handleDragOver = (e: React.DragEvent) => {
        e.preventDefault();
        setIsDragging(true);
    };

    const handleDragLeave = () => {
        setIsDragging(false);
    };

    const handleDrop = (e: React.DragEvent) => {
        e.preventDefault();
        setIsDragging(false);
        const file = e.dataTransfer.files?.[0];
        if (file && file.name.endsWith('.csv')) {
            processFile(file);
        } else if (file) {
            alert("Por favor suba un archivo .csv");
        }
    };

    return (
        <Card>
            <div className="flex items-center gap-3 mb-4 border-b border-slate-200 pb-3">
                <div className="h-7 w-7 bg-brand-50 text-brand-600 border border-brand-100 rounded-lg flex items-center justify-center text-sm font-bold shadow-sm">1</div>
                <h2 className="text-lg font-bold text-slate-800">Cargar Datos</h2>
            </div>

            <div className="grid grid-cols-1 md:grid-cols-5 gap-6 items-center">
                <div 
                    className={`md:col-span-3 border-2 border-dashed rounded-xl p-6 text-center transition-all cursor-pointer h-full flex flex-col justify-center ${isDragging ? 'border-brand-500 bg-brand-50' : 'border-slate-300 hover:border-brand-400 hover:bg-slate-50'}`}
                    onDragOver={handleDragOver}
                    onDragLeave={handleDragLeave}
                    onDrop={handleDrop}
                    onClick={() => fileInputRef.current?.click()}
                >
                    <input
                        type="file"
                        ref={fileInputRef}
                        accept=".csv"
                        onChange={handleFileChange}
                        className="hidden"
                    />
                    <div className="mx-auto h-10 w-10 text-slate-400 mb-2 group-hover:text-brand-500 transition-colors">
                        <svg xmlns="http://www.w3.org/2000/svg" fill="none" viewBox="0 0 24 24" strokeWidth="1.5" stroke="currentColor">
                          <path strokeLinecap="round" strokeLinejoin="round" d="M19.5 14.25v-2.625a3.375 3.375 0 00-3.375-3.375h-1.5A1.125 1.125 0 0113.5 7.125v-1.5a3.375 3.375 0 00-3.375-3.375H8.25m.75 12l3 3m0 0l3-3m-3 3v-6m-1.5-9H5.625c-.621 0-1.125.504-1.125 1.125v17.25c0 .621.504 1.125 1.125 1.125h12.75c.621 0 1.125-.504 1.125-1.125V11.25a9 9 0 00-9-9z" />
                        </svg>
                    </div>
                    <p className="text-sm font-semibold text-slate-700">Click o arrastre un CSV</p>
                    <p className="text-xs text-slate-500 mt-1">para iniciar el análisis</p>
                </div>

                <div className="md:col-span-2 flex flex-col gap-3">
                    {fileName && (
                        <div className="flex items-center gap-2 text-xs bg-emerald-50 text-emerald-700 p-2 rounded-lg border border-emerald-100 animate-fade-in shadow-sm">
                            <svg className="w-5 h-5 flex-shrink-0" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M5 13l4 4L19 7"></path></svg>
                            <span className="truncate font-medium">{fileName}</span>
                        </div>
                    )}
                    <Button variant="secondary" onClick={handleLoadDemo} className="w-full" size="sm">
                        Cargar Demo NIR
                    </Button>
                    <div className="text-[10px] text-slate-500 leading-relaxed bg-slate-50 p-2 rounded-lg border border-slate-100">
                        <strong className="text-slate-700">Formato CSV:</strong> 1ª fila: Headers. Última col: Propiedad (Y).
                    </div>
                </div>
            </div>
        </Card>
