                    )}
                    <div className="text-[10px] text-slate-500 leading-relaxed bg-slate-50 p-2 rounded-lg border border-slate-100">
                        <strong className="text-slate-700">Formato:</strong> 1ª fila: Headers. Última col: Propiedad (Y).
                    </div>
                </div>
