import React, { useState, useRef, useEffect } from 'react';
import Card from './Card';
import Button from './Button';
import { runPlsOptimization } from '../services/chemometrics';
import { OptimizationResult, Sample, PreprocessingStep } from '../types';

declare var Chart: any;

export type ModelParams = 
    | { type: 'pls'; nComponents: number };

interface ModelGeneratorProps {
    onRunModel: (params: ModelParams) => void;
    disabled: boolean;
    activeSamples?: Sample[];
    preprocessingSteps?: PreprocessingStep[];
}

const RunIcon: React.FC = () => (
    <svg xmlns="http://www.w3.org/2000/svg" width="16" height="16" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round">
        <polygon points="5 3 19 12 5 21 5 3"></polygon>
    </svg>
);

const OptimizeIcon: React.FC = () => (
    <svg xmlns="http://www.w3.org/2000/svg" width="16" height="16" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round">
        <line x1="18" y1="20" x2="18" y2="10"></line><line x1="12" y1="20" x2="12" y2="4"></line><line x1="6" y1="20" x2="6" y2="14"></line>
    </svg>
);

const ModelGenerator: React.FC<ModelGeneratorProps> = ({ onRunModel, disabled, activeSamples, preprocessingSteps }) => {
    const [nComponents, setNComponents] = useState('5');
    const [isOptimizing, setIsOptimizing] = useState(false);
    const [optimizationData, setOptimizationData] = useState<OptimizationResult[] | null>(null);

    const chartRef = useRef<HTMLCanvasElement>(null);
    const chartInstanceRef = useRef<any>(null);

    const handleRun = () => {
        const lv = parseInt(nComponents);
        if (!isNaN(lv) && lv > 0 && lv <= 20) {
            onRunModel({ type: 'pls', nComponents: lv });
        } else {
            alert('Por favor, introduzca un número válido de variables latentes (1-20).');
        }
    };

    const handleOptimize = async () => {
        if (!activeSamples || !preprocessingSteps || activeSamples.length < 3) {
            alert("Se requieren al menos 3 muestras activas para optimizar.");
            return;
        }

        setIsOptimizing(true);
        setTimeout(() => {
            try {
                const maxLVs = Math.min(15, activeSamples.length - 1);
                const results = runPlsOptimization(activeSamples, preprocessingSteps, maxLVs);
                setOptimizationData(results);
            } catch (e) {
                console.error(e);
                alert("Error durante la optimización.");
            } finally {
                setIsOptimizing(false);
            }
        }, 50);
    };

    useEffect(() => {
        if (optimizationData && chartRef.current) {
            if (chartInstanceRef.current) {
                chartInstanceRef.current.destroy();
            }

            const ctx = chartRef.current.getContext('2d');
            if (ctx) {
                chartInstanceRef.current = new Chart(ctx, {
                    type: 'line',
                    data: {
                        labels: optimizationData.map(d => d.components),
                        datasets: [
                            {
                                label: 'SEC (Calibración)',
                                data: optimizationData.map(d => d.sec),
                                borderColor: '#0ea5e9', // Sky 500
                                backgroundColor: '#0ea5e9',
                                tension: 0.1,
                                pointRadius: 4,
                                pointHoverRadius: 6
                            },
                            {
                                label: 'SECV (Validación)',
                                data: optimizationData.map(d => d.secv),
                                borderColor: '#10b981', // Emerald 500
                                backgroundColor: '#10b981',
                                tension: 0.1,
                                pointRadius: 4,
                                pointHoverRadius: 6
                            }
                        ]
                    },
                    options: {
                        responsive: true,
                        maintainAspectRatio: false,
                        interaction: {
                            mode: 'index',
                            intersect: false,
                        },
                        plugins: {
                            legend: { labels: { color: '#64748b' } },
                            title: { display: true, text: 'Error vs. LVs', color: '#64748b' },
                            tooltip: {
                                backgroundColor: 'rgba(255, 255, 255, 0.95)',
                                titleColor: '#0f172a',
                                bodyColor: '#334155',
                                borderColor: '#e2e8f0',
                                borderWidth: 1,
                                padding: 10,
                                titleFont: { family: 'Inter', size: 13 },
                                callbacks: {
                                    footer: (tooltipItems: any[]) => {
                                        return 'Click para usar este valor.';
                                    }
                                }
                            }
                        },
                        scales: {
                            x: { 
                                title: { display: true, text: 'Variables Latentes (LVs)', color: '#94a3b8' },
                                ticks: { color: '#64748b' },
                                grid: { color: '#e2e8f0' }
                            },
                            y: { 
                                title: { display: true, text: 'RMSE (Error)', color: '#94a3b8' },
                                ticks: { color: '#64748b' },
                                grid: { color: '#e2e8f0' }
                            }
                        },
                        onClick: (e: any, elements: any[]) => {
                            if (elements && elements.length > 0) {
                                const index = elements[0].index;
                                const selectedComps = optimizationData[index].components;
                                setNComponents(selectedComps.toString());
                            }
                        }
                    }
                });
            }
        }

        return () => {
             // Cleanup if needed
        };
    }, [optimizationData]);

    const suggestedLV = optimizationData 
        ? optimizationData.reduce((prev, curr) => curr.secv < prev.secv ? curr : prev).components 
        : null;

    return (
        <Card className="h-full">
            <div className="flex flex-col h-full">
                <div className="flex items-center gap-3 mb-4 border-b border-slate-200 pb-3">
                    <div className="h-7 w-7 bg-brand-50 text-brand-600 border border-brand-100 rounded-lg flex items-center justify-center text-sm font-bold shadow-sm">3</div>
                    <h3 className="text-lg font-bold text-slate-800">Generación de Modelo (PLS)</h3>
                </div>

                <div className="flex-1 flex flex-col space-y-4">
                    <div className="grid grid-cols-2 gap-4 items-end">
                        <div>
                             <label htmlFor="lv-input" className="block text-xs font-bold text-slate-500 mb-1">Variables Latentes (LV)</label>
                            <input
                                type="number"
                                id="lv-input"
                                value={nComponents}
                                onChange={(e) => setNComponents(e.target.value)}
                                min="1"
                                max="20"
                                className="w-full bg-white border border-slate-300 text-slate-800 rounded-md px-3 py-2 text-sm focus:outline-none focus:ring-2 focus:ring-brand-500 focus:border-brand-500 shadow-sm"
                            />
                        </div>
                        <Button variant="secondary" onClick={handleOptimize} disabled={disabled || isOptimizing} className="h-[38px] text-xs">
                            {isOptimizing ? 'Analizando...' : (
                                <>
                                    <OptimizeIcon /> Analizar Componentes
                                </>
                            )}
                        </Button>
                    </div>

                    {optimizationData && (
                        <div className="border border-slate-200 rounded-lg p-3 bg-slate-50 animate-fade-in shadow-inner">
                            <div className="h-48 relative">
                                <canvas ref={chartRef}></canvas>
                            </div>
                            {suggestedLV && (
                                <p className="text-xs text-center mt-2 text-slate-500">
                                    Mínimo error de validación en <span className="font-bold text-brand-600">{suggestedLV} LVs</span>.
                                </p>
                            )}
                        </div>
                    )}

                    <div className="pt-2 mt-auto">
                        <Button onClick={handleRun} disabled={disabled} className="w-full">
                            <RunIcon />
                            Generar Modelo PLS Final
                        </Button>
                    </div>
                </div>
            </div>
        </Card>
    );
};

export default ModelGenerator;

import React, { useState, useCallback } from 'react';
import { Sample, PreprocessingStep, ModelResults } from './types';
import { parseCSV } from './services/csvParser';
import { applyPreprocessingLogic, runPlsAnalysis } from './services/chemometrics';
import Header from './components/Header';
import Loader from './components/Loader';
import DataUploader from './components/DataUploader';
import SampleManager from './components/SampleManager';
import SpectraViewer from './components/SpectraViewer';
import PreprocessingEditor from './components/PreprocessingEditor';
import ModelGenerator, { ModelParams } from './components/ModelGenerator';
import ResultsViewer from './components/ResultsViewer';
import ModelPredictor from './components/ModelPredictor';
import Card from './components/Card';

type AppView = 'calibration' | 'prediction';

const App: React.FC = () => {
    const [currentView, setCurrentView] = useState<AppView>('calibration');
    const [loadingMessage, setLoadingMessage] = useState<string | null>(null);
    const [wavelengths, setWavelengths] = useState<number[]>([]);
    const [samples, setSamples] = useState<Sample[]>([]);
    const [analyticalProperty, setAnalyticalProperty] = useState<string>('Propiedad');
    const [preprocessingSteps, setPreprocessingSteps] = useState<PreprocessingStep[]>([]);
    const [modelResults, setModelResults] = useState<ModelResults | null>(null);
    const [processedSpectra, setProcessedSpectra] = useState<{ id: string | number; values: number[] }[] | null>(null);

    const handleDataLoaded = (data: { wavelengths: number[]; samples: Sample[]; analyticalProperty: string }) => {
        setWavelengths(data.wavelengths);
        setSamples(data.samples);
        setAnalyticalProperty(data.analyticalProperty);
        setModelResults(null);
        setProcessedSpectra(null);
        setPreprocessingSteps([]);
    };

    const handleFileSelected = (file: File) => {
        setLoadingMessage('Cargando datos...');
        parseCSV(file, (results) => {
            handleDataLoaded(results);
            setLoadingMessage(null);
        });
    };

    const handleToggleSample = (index: number) => {
        setSamples(prev => prev.map((s, i) => i === index ? { ...s, active: !s.active } : s));
    };

    const handleToggleAllSamples = (active: boolean) => {
        setSamples(prev => prev.map(s => ({ ...s, active })));
    };

    const handleVisualizePreprocessing = () => {
        const activeSamples = samples.filter(s => s.active);
        if (activeSamples.length === 0) return;
        const processed = activeSamples.map(sample => ({
            ...sample,
            values: applyPreprocessingLogic(sample.values, preprocessingSteps)
        }));
        setProcessedSpectra(processed);
    };

    const handleResetVisualization = useCallback(() => {
        setProcessedSpectra(null);
    }, []);

    const handleRunModel = async (params: ModelParams) => {
        const activeSamples = samples.filter(s => s.active);
        if (activeSamples.length < 3) {
            alert('Se necesitan al menos 3 muestras activas para generar el modelo PLS y validación cruzada.');
            return;
        }
        setLoadingMessage(`Generando modelo ${params.type.toUpperCase()}...`);

        setTimeout(() => {
            try {
                const results = runPlsAnalysis(activeSamples, preprocessingSteps, params.nComponents);
                setModelResults(results);
            } catch (error) {
                console.error(`Error during ${params.type} run:`, error);
                const errorMessage = error instanceof Error ? error.message : "Ocurrió un error desconocido.";
                alert(`Ocurrió un error al generar el modelo: ${errorMessage}`);
            } finally {
                setLoadingMessage(null);
            }
        }, 100);
    };

    const handleDeactivateOutliers = (outlierIds: (string|number)[]) => {
         setSamples(prev => prev.map(s => outlierIds.includes(s.id) ? { ...s, active: false } : s));
         if (modelResults) {
             setTimeout(() => {
                const params: ModelParams = { type: 'pls', nComponents: modelResults.nComponents };
                handleRunModel(params);
             }, 100);
         }
    }

    const activeSamples = samples.filter(s => s.active);
    const spectraToDisplay = processedSpectra ? processedSpectra.map(p => {
        const originalSample = samples.find(s => s.id === p.id);
        return { ...p, color: originalSample?.color || '#000000' };
    }) : activeSamples;

    return (
        <>
            {loadingMessage && <Loader message={loadingMessage} />}
            <div className="min-h-screen flex flex-col bg-slate-50 text-slate-800 font-sans">
                <Header />

                {/* Navigation Tabs */}
                <div className="bg-white border-b border-slate-200 sticky top-16 z-20">
                    <div className="max-w-[1920px] mx-auto px-4 lg:px-6 flex gap-8">
                        <button 
                            onClick={() => setCurrentView('calibration')}
                            className={`py-4 text-sm font-semibold border-b-2 transition-colors flex items-center gap-2 ${currentView === 'calibration' ? 'border-brand-600 text-brand-600' : 'border-transparent text-slate-500 hover:text-slate-800'}`}
                        >
                            <svg xmlns="http://www.w3.org/2000/svg" width="18" height="18" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"><path d="M2 12h5"/><path d="M17 12h5"/><path d="M7 12a5 5 0 0 1 5-5 5 5 0 0 1 5 5 5 5 0 0 1-5 5 5 5 0 0 1-5-5Z"/></svg>
                            1. Entrenamiento & Calibración
                        </button>
                        <button 
                            onClick={() => setCurrentView('prediction')}
                            className={`py-4 text-sm font-semibold border-b-2 transition-colors flex items-center gap-2 ${currentView === 'prediction' ? 'border-brand-600 text-brand-600' : 'border-transparent text-slate-500 hover:text-slate-800'}`}
                        >
                            <svg xmlns="http://www.w3.org/2000/svg" width="18" height="18" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"><path d="M22 11.08V12a10 10 0 1 1-5.93-9.14"/><polyline points="22 4 12 14.01 9 11.01"/></svg>
                            2. Predicción de Nuevas Muestras
                        </button>
                    </div>
                </div>

                <main className="flex-grow p-4 lg:p-6">

                    {/* VISTA DE CALIBRACIÓN */}
                    {currentView === 'calibration' && (
                        <div className="flex flex-col gap-6 animate-fade-in">
                            {/* Main Workspace: Controls & Visualization */}
                            <div className="grid grid-cols-1 lg:grid-cols-7 gap-6">
                                {/* Left Column: Workflow Steps 1, 2 & 3 */}
                                <div className="flex flex-col gap-6 lg:col-span-2">
                                    <DataUploader onFileSelected={handleFileSelected} />
                                    <PreprocessingEditor
                                        steps={preprocessingSteps}
                                        setSteps={setPreprocessingSteps}
                                        onVisualize={handleVisualizePreprocessing}
                                        disabled={activeSamples.length === 0}
                                    />
                                    <ModelGenerator 
                                        onRunModel={handleRunModel} 
                                        disabled={activeSamples.length < 3}
                                        activeSamples={activeSamples}
                                        preprocessingSteps={preprocessingSteps}
                                    />
                                </div>

                                {/* Right Column: Data Interaction */}
                                <div className="flex flex-col gap-6 lg:col-span-5">
                                    <SpectraViewer
                                        wavelengths={wavelengths}
                                        samples={spectraToDisplay}
                                        isProcessed={!!processedSpectra}
                                        onReset={handleResetVisualization}
                                    />
                                    <SampleManager
                                        samples={samples}
                                        onToggle={handleToggleSample}
                                        onToggleAll={handleToggleAllSamples}
                                    />
                                    {/* Final Step: Results (Now inside the main grid) */}
                                    <div>
                                        <div className="flex items-center gap-3 mb-4">
                                             <div className="h-7 w-7 bg-slate-100 text-slate-600 border border-slate-200 rounded-lg flex items-center justify-center text-sm font-bold shadow-sm">4</div>
                                             <h2 className="text-lg font-bold text-slate-800">Análisis de Resultados del Modelo</h2>
                                        </div>
                                        {modelResults ? (
                                            <ResultsViewer 
                                                results={modelResults}
                                                propertyName={analyticalProperty}
                                                preprocessingSteps={preprocessingSteps}
                                                activeSamples={activeSamples.map(s => s.id)}
                                                onDeactivateOutliers={handleDeactivateOutliers}
                                                wavelengths={wavelengths}
                                            />
                                        ) : (
                                            <Card>
                                                <div className="flex flex-col items-center justify-center h-64 text-slate-400 bg-slate-50/50 rounded-lg border-2 border-dashed border-slate-300">
                                                    <svg xmlns="http://www.w3.org/2000/svg" className="h-16 w-16 mb-4 opacity-50" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                                                        <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={1} d="M9 17v-2m3 2v-4m3 4v-6m2 10H7a2 2 0 01-2-2V5a2 2 0 012-2h5.586a1 1 0 01.707.293l5.414 5.414a1 1 0 01.293.707V19a2 2 0 01-2 2z" />
                                                    </svg>
                                                    <p className="font-semibold text-slate-600 text-lg">Resultados del Modelo</p>
                                                    <p className="text-sm text-slate-500 mt-1">Genere un modelo en el paso 3 para ver el análisis estadístico aquí.</p>
                                                </div>
                                            </Card>
                                        )}
                                    </div>
                                </div>
                            </div>
                        </div>
                    )}

                    {/* VISTA DE PREDICCIÓN */}
                    {currentView === 'prediction' && (
                        <div className="max-w-5xl mx-auto animate-fade-in">
                            <div className="mb-6 text-center">
                                <h2 className="text-2xl font-bold text-slate-800">Módulo de Predicción Independiente</h2>
                                <p className="text-slate-500 mt-2">Cargue un modelo previamente entrenado (.json) y un nuevo archivo de espectros (.csv) para calcular propiedades.</p>
                            </div>
                            <ModelPredictor />
                        </div>
                    )}

                </main>
            </div>
        </>
    );
};

export default App;

import React, 'useState', 'useRef', 'useEffect' } from 'react';
import Card from './Card';
import Button from './Button';
import { ModelResults, PreprocessingStep } from '../types';

declare var Chart: any;

interface ResultsViewerProps {
    results: ModelResults;
    propertyName: string;
    preprocessingSteps: PreprocessingStep[];
    activeSamples: (string|number)[];
    onDeactivateOutliers: (outlierIds: (string|number)[]) => void;
    wavelengths: number[];
}

const StatCard = ({ label, value, subtext, colorClass }: { label: string, value: string | number, subtext?: string, colorClass: string }) => (
    <div className="bg-white p-5 rounded-xl border border-slate-200 shadow-soft flex flex-col items-center justify-center hover:translate-y-[-2px] transition-transform duration-200">
        <span className="text-xs font-bold text-slate-400 uppercase tracking-wider mb-2">{label}</span>
        <span className={`text-3xl font-bold font-mono ${colorClass}`}>{value}</span>
        {subtext && <span className="text-xs text-slate-500 mt-2 bg-slate-50 px-2 py-0.5 rounded-full">{subtext}</span>}
    </div>
);

const ResultsViewer: React.FC<ResultsViewerProps> = ({ results, propertyName, preprocessingSteps, activeSamples, onDeactivateOutliers, wavelengths }) => {
    const [activeTab, setActiveTab] = useState('correlation');
    const chartRef = useRef<HTMLCanvasElement>(null);
    const chartInstanceRef = useRef<any>(null);

    const residuals = results.model.residuals;
    const outliers = results.mahalanobis.distances.filter(d => d.isOutlier);
    const [selectedOutliers, setSelectedOutliers] = useState<Set<string|number>>(new Set());
    const [manualSelection, setManualSelection] = useState<Set<string | number>>(new Set());

    useEffect(() => {
        // Reset selections when model results change
        setSelectedOutliers(new Set());
        setManualSelection(new Set());
    }, [results]);

    useEffect(() => {
        if (activeTab === 'correlation' && chartRef.current) {
            const ctx = chartRef.current.getContext('2d');
            if (ctx) {
                const chartInstance = new Chart(ctx, {
                    type: 'scatter',
                    data: { datasets: [] },
                    options: {
                        maintainAspectRatio: false,
                        responsive: true,
                        animation: false,
                        onClick: (evt: any) => {
                            const points = chartInstance.getElementsAtEventForMode(evt, 'point', { intersect: true }, true);
                            if (points.length > 0) {
                                const point = points[0];
                                const dataset = chartInstance.data.datasets[point.datasetIndex];
                                // Aseguramos que data[point.index] es del tipo correcto
                                const dataPoint = (dataset.data[point.index] as any);
                                if (dataPoint && dataPoint.id !== undefined) {
                                    const sampleId = dataPoint.id;
                                    setManualSelection(prev => {
                                        const newSet = new Set(prev);
                                        if (newSet.has(sampleId)) {
                                            newSet.delete(sampleId);
                                        } else {
                                            newSet.add(sampleId);
                                        }
                                        return newSet;
                                    });
                                }
                            }
                        },
                        plugins: {
                            legend: { 
                                position: 'bottom',
                                labels: { usePointStyle: true, padding: 20, font: { family: 'Inter', size: 12 }, color: '#94a3b8' }
                            },
                            title: { display: false },
                            tooltip: {
                                backgroundColor: 'rgba(255, 255, 255, 0.95)',
                                titleColor: '#0f172a',
                                bodyColor: '#334155',
                                borderColor: '#e2e8f0',
                                borderWidth: 1,
                                padding: 10,
                                titleFont: { family: 'Inter', size: 13, weight: 'bold' },
                                callbacks: {
                                    title: (context: any) => {
                                        const dataPoint = context[0].dataset.data[context[0].dataIndex] as any;
                                        return `Muestra: ${dataPoint.id}`;
                                    },
                                    label: (context: any) => {
                                        const x = context.parsed.x;
                                        const y = context.parsed.y;
                                        return `Ref ${x.toFixed(2)} / Pred ${y.toFixed(2)}`;
                                    }
                                }
                            }
                        },
                        scales: {
                            x: { 
                                title: { display: true, text: `Valor Referencia (${propertyName})`, font: { weight: '600' }, color: '#94a3b8' },
                                grid: { color: '#334155', drawBorder: false },
                                ticks: { color: '#94a3b8', font: { family: 'JetBrains Mono' } }
                            },
                            y: { 
                                title: { display: true, text: 'Valor Predicho (NIR)', font: { weight: '600' }, color: '#94a3b8' },
                                grid: { color: '#334155', drawBorder: false },
                                ticks: { color: '#94a3b8', font: { family: 'JetBrains Mono' } }
                            }
                        }
                    }
                });

                chartInstanceRef.current = chartInstance;
            }
        }

        return () => {
            if (chartInstanceRef.current) {
                chartInstanceRef.current.destroy();
                chartInstanceRef.current = null;
            }
        };
    }, [activeTab]);

    useEffect(() => {
        const chartInstance = chartInstanceRef.current;
        if (chartInstance && results) {
            const allDataPoints = results.model.correlation.actual.map((act, i) => ({
                x: act,
                y: results.model.correlation.predicted[i],
                id: results.model.residuals[i].id,
                isOutlier: results.mahalanobis.distances.find(d => d.id === results.model.residuals[i].id)?.isOutlier || false
            }));

            const inliersData = allDataPoints.filter(p => !p.isOutlier);
            const outliersData = allDataPoints.filter(p => p.isOutlier);

            const allValues = [...results.model.correlation.actual, ...results.model.correlation.predicted];
            if (allValues.length > 0) {
                const minVal = Math.min(...allValues);
                const maxVal = Math.max(...allValues);
                const padding = (maxVal - minVal) * 0.1;

                chartInstance.data.datasets = [
                    { 
                        label: 'Muestras Válidas', 
                        data: inliersData, 
                        backgroundColor: '#0ea5e9',
                        pointRadius: (ctx: any) => manualSelection.has(ctx.raw.id) ? 8 : 5,
                        borderWidth: (ctx: any) => manualSelection.has(ctx.raw.id) ? 3 : 1,
                        borderColor: (ctx: any) => manualSelection.has(ctx.raw.id) ? '#f59e0b' : '#0284c7'
                    },
                    { 
                        label: 'Posibles Outliers', 
                        data: outliersData, 
                        backgroundColor: '#ef4444', 
                        pointStyle: 'triangle',
                        pointRadius: (ctx: any) => manualSelection.has(ctx.raw.id) ? 9 : 6,
                        borderWidth: (ctx: any) => manualSelection.has(ctx.raw.id) ? 3 : 1,
                        borderColor: (ctx: any) => manualSelection.has(ctx.raw.id) ? '#f59e0b' : '#b91c1c'
                    },
                    { 
                        type: 'line', 
                        label: 'Línea Ideal (1:1)', 
                        data: [{x: minVal - padding, y: minVal - padding}, {x: maxVal + padding, y: maxVal + padding}], 
                        borderColor: '#64748b', 
                        borderWidth: 2, 
                        borderDash: [6, 6], 
                        pointRadius: 0, 
                        fill: false 
                    }
                ];

                chartInstance.options.scales.x.min = minVal - padding;
                chartInstance.options.scales.x.max = maxVal + padding;
                chartInstance.options.scales.y.min = minVal - padding;
                chartInstance.options.scales.y.max = maxVal + padding;

                chartInstance.update();
            }
        }
    }, [results, manualSelection, activeTab]);

    const handleExportConfig = () => {
        const config = {
            date: new Date().toISOString(),
            modelType: results.modelType,
            nComponents: results.nComponents,
            analyticalProperty: propertyName,
            activeSamples: activeSamples,
            preprocessing: preprocessingSteps,
            metrics: results.model,
            coefficients: results.model.coefficients
        };
        const dataStr = "data:text/json;charset=utf-8," + encodeURIComponent(JSON.stringify(config, null, 2));
        const anchor = document.createElement('a');
        anchor.href = dataStr;
        anchor.download = `model_config_${new Date().toISOString().slice(0,10)}.json`;
        anchor.click();
    };

    const handleDownloadData = () => {
        const headers = ['ID', 'Reference', 'Predicted', 'Residual', ...wavelengths];
        const { residuals, processedSpectra } = results.model;
        const rows = residuals.map((res, index) => 
            [res.id, res.actual, res.predicted, res.residual, ...processedSpectra[index]]
        );
        const csvContent = [headers.join(','), ...rows.map(row => row.join(','))].join('\n');
        const blob = new Blob([csvContent], { type: 'text/csv;charset=utf-8;' });
        const url = URL.createObjectURL(blob);
        const link = document.createElement("a");
        link.href = url;
        link.download = "pls_prediction_results.csv";
        link.click();
    };

    const handleOutlierSelection = (id: string|number, checked: boolean) => {
        setSelectedOutliers(prev => {
            const newSet = new Set(prev);
            if (checked) newSet.add(id);
            else newSet.delete(id);
            return newSet;
        });
    };

    const handleDeactivateClick = () => {
        if (selectedOutliers.size === 0) return alert("Seleccione al menos un outlier.");
        onDeactivateOutliers(Array.from(selectedOutliers));
        setSelectedOutliers(new Set());
    };

    const handleDeactivateManualClick = () => {
        if (manualSelection.size === 0) return;
        onDeactivateOutliers(Array.from(manualSelection));
        setManualSelection(new Set());
    };

    const TabButton = ({ tabId, label, icon }: { tabId: string; label: string; icon?: React.ReactNode }) => (
        <button
            className={`flex items-center gap-2 px-5 py-3 text-sm font-medium transition-all relative ${activeTab === tabId ? 'text-brand-600 bg-brand-50 border-b-2 border-brand-600' : 'text-slate-500 hover:text-slate-800 hover:bg-slate-50'}`}
            onClick={() => setActiveTab(tabId)}
        >
            {icon}
            {label}
        </button>
    );

    return (
        <Card noPadding className="overflow-hidden">
            <div className="bg-white border-b border-slate-200">
                <div className="flex overflow-x-auto no-scrollbar">
                    <TabButton tabId="correlation" label="Diagnóstico Gráfico" icon={<svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M7 12l3-3 3 3 4-4M8 21l4-4 4 4M3 4h18M4 4h16v12a1 1 0 01-1 1H5a1 1 0 01-1-1V4z"></path></svg>} />
                    <TabButton tabId="stats" label="Métricas de Regresión" icon={<svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M9 19v-6a2 2 0 00-2-2H5a2 2 0 00-2 2v6a2 2 0 002 2h2a2 2 0 002-2zm0 0V9a2 2 0 012-2h2a2 2 0 012 2v10m-6 0a2 2 0 002 2h2a2 2 0 002-2m0 0V5a2 2 0 012-2h2a2 2 0 012 2v14a2 2 0 01-2 2h-2a2 2 0 01-2-2z"></path></svg>} />
                    <TabButton tabId="residuals" label="Tabla Residuos" icon={<svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M3 10h18M3 14h18m-9-4v8m-7 0h14a2 2 0 002-2V8a2 2 0 00-2-2H5a2 2 0 00-2 2v8a2 2 0 002 2z"></path></svg>} />
                    <TabButton tabId="full-data" label="Exportar" icon={<svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M4 16v1a3 3 0 003 3h10a3 3 0 003-3v-1m-4-4l-4 4m0 0l-4-4m4 4V4"></path></svg>} />
                </div>
            </div>

            <div className="p-6 bg-slate-50 min-h-[400px]">
                {activeTab === 'correlation' && (
                    <div className="flex flex-col gap-6 animate-fade-in">
                        {/* Top Stats Row */}
                        <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-4">
                            <div className="lg:col-span-2 bg-slate-800 text-white p-6 rounded-xl shadow-xl border border-slate-700 relative overflow-hidden group">
                                <div className="absolute top-0 right-0 p-4 opacity-10 group-hover:opacity-20 transition-opacity">
                                    <svg className="w-16 h-16" fill="currentColor" viewBox="0 0 24 24"><path d="M13 10V3L4 14h7v7l9-11h-7z"/></svg>
                                </div>
                                <h3 className="text-brand-500 text-xs font-bold uppercase tracking-widest mb-1">Modelo PLS</h3>
                                <div className="text-4xl font-bold font-mono tracking-tight">{results.nComponents} <span className="text-lg font-normal text-slate-400 font-sans">LVs</span></div>
                                <div className="mt-6 pt-4 border-t border-slate-700 flex flex-col gap-2">
                                    <div className="flex justify-between text-sm items-center">
                                        <span className="text-slate-300">R² Score</span>
                                        <span className="font-mono text-brand-400 font-bold bg-slate-900 px-2 py-0.5 rounded">{results.model.r2.toFixed(4)}</span>
                                    </div>
                                    <div className="flex justify-between text-sm items-center">
                                        <span className="text-slate-300">Correlación (r)</span>
                                        <span className="font-mono text-white">{results.model.r.toFixed(4)}</span>
                                    </div>
                                </div>
                            </div>
                             <StatCard label="SEC (Calibración)" value={results.model.sec.toFixed(4)} colorClass="text-brand-600" />
                             <StatCard label="SECV (Validación)" value={results.model.secv.toFixed(4)} colorClass="text-emerald-600" subtext="Target Minimization" />
                        </div>

                        {/* Chart */}
                        <div className="bg-slate-900 p-4 rounded-xl border border-slate-800 shadow-inner-dark relative h-[500px]">
                            <canvas ref={chartRef}></canvas>
                        </div>

                        {/* Manual Outlier Selection */}
                        <div className="bg-white rounded-xl border border-slate-200 shadow-card p-6">
                            <h4 className="font-bold text-slate-700 mb-2">Selección Manual de Outliers</h4>
                            <p className="text-sm text-slate-500 mb-4">Haga clic en los puntos del gráfico para seleccionarlos/deseleccionarlos. Una vez seleccionados, puede desactivarlos para recalcular el modelo.</p>
                            {manualSelection.size > 0 && 
                                <div className="text-sm text-slate-700 mb-4 p-3 bg-amber-50 border border-amber-200 rounded-lg animate-fade-in">
                                    <span className="font-bold">{manualSelection.size}</span> muestra(s) seleccionada(s): <span className="font-mono bg-amber-100 px-1 py-0.5 rounded">{Array.from(manualSelection).slice(0, 5).join(', ')}{manualSelection.size > 5 ? '...' : ''}</span>
                                </div>
                            }
                            <Button 
                                onClick={handleDeactivateManualClick} 
                                disabled={manualSelection.size === 0}
                                className="w-full"
                                variant="danger"
                            >
                                Desactivar {manualSelection.size > 0 ? `${manualSelection.size} ` : ''}Muestra(s) Seleccionada(s) y Recalcular
                            </Button>
                        </div>


                        {/* Outlier Management Table */}
                        <div className="bg-white rounded-xl border border-slate-200 shadow-card overflow-hidden flex flex-col">
                            <div className="bg-slate-50 px-6 py-4 border-b border-slate-200 flex justify-between items-center">
                                <h4 className="font-bold text-slate-700">Detección de Outliers (Mahalanobis)</h4>
                                {outliers.length > 0 && <span className="bg-red-100 text-red-700 text-xs font-bold px-2 py-1 rounded-full">{outliers.length} Detectados</span>}
                            </div>

                            <div className="flex-1 p-0 overflow-hidden flex flex-col">
                                {outliers.length > 0 ? (
                                    <>
                                        <div className="flex-1 overflow-y-auto max-h-60 custom-scrollbar">
                                            <table className="w-full text-sm text-left">
                                                <thead className="text-xs text-slate-500 uppercase bg-slate-50 sticky top-0 border-b border-slate-200">
                                                    <tr>
                                                        <th className="px-6 py-3 w-16 text-center">Sel.</th>
                                                        <th className="px-6 py-3">ID Muestra</th>
                                                        <th className="px-6 py-3 text-right">Distancia</th>
                                                        <th className="px-6 py-3 text-right">Estado</th>
                                                    </tr>
                                                </thead>
                                                <tbody className="divide-y divide-slate-100">
                                                    {outliers.map(o => (
                                                        <tr key={o.id} className="hover:bg-slate-50 transition-colors">
                                                            <td className="px-6 py-3 text-center">
                                                                <input 
                                                                    type="checkbox" 
                                                                    className="rounded border-slate-300 text-brand-600 focus:ring-brand-500 cursor-pointer"
                                                                    checked={selectedOutliers.has(o.id)} 
                                                                    onChange={e => handleOutlierSelection(o.id, e.target.checked)} 
                                                                />
                                                            </td>
                                                            <td className="px-6 py-3 font-medium text-slate-700">{o.id}</td>
                                                            <td className="px-6 py-3 text-right font-mono text-red-600 font-bold">{o.distance.toFixed(2)}</td>
                                                            <td className="px-6 py-3 text-right"><span className="text-[10px] uppercase font-bold text-red-600 bg-red-50 px-2 py-1 rounded-full border border-red-100">Crítico</span></td>
                                                        </tr>
                                                    ))}
                                                </tbody>
                                            </table>
                                        </div>
                                        <div className="p-4 border-t border-slate-200 bg-slate-50">
                                            <Button onClick={handleDeactivateClick} variant="danger" size="sm" className="w-full">
                                                Desactivar Outliers Seleccionados y Recalcular
                                            </Button>
                                        </div>
                                    </>
                                ) : (
                                    <div className="p-8 text-center flex flex-col items-center justify-center h-full">
                                        <div className="h-16 w-16 bg-green-50 text-green-500 rounded-full flex items-center justify-center mb-4">
                                            <svg className="w-8 h-8" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M5 13l4 4L19 7"></path></svg>
                                        </div>
                                        <p className="text-slate-800 font-bold text-lg">Todo limpio</p>
                                        <p className="text-sm text-slate-500 mt-1">No se detectaron outliers espectrales significativos.</p>
                                    </div>
                                )}
                            </div>
                        </div>
                    </div>
                )}

                {activeTab === 'stats' && (
                    <div className="animate-fade-in max-w-2xl mx-auto">
                         <div className="bg-white rounded-xl border border-slate-200 shadow-card overflow-hidden">
                            <div className="bg-slate-50 px-6 py-4 border-b border-slate-200">
                                <h4 className="font-bold text-slate-700">Parámetros de Regresión</h4>
                            </div>
                            <div className="p-6 space-y-4">
                                <div className="grid grid-cols-2 gap-4">
                                    <div className="p-4 bg-slate-50 rounded-lg border border-slate-100">
                                        <div className="text-xs font-bold text-slate-400 uppercase mb-2">Pendiente (Slope)</div>
                                        <div className="font-mono text-xl font-semibold text-slate-700">{results.model.slope.toFixed(5)}</div>
                                    </div>
                                    <div className="p-4 bg-slate-50 rounded-lg border border-slate-100">
                                        <div className="text-xs font-bold text-slate-400 uppercase mb-2">Offset (Bias)</div>
                                        <div className="font-mono text-xl font-semibold text-slate-700">{results.model.offset.toFixed(5)}</div>
                                    </div>
                                </div>
                                <div className="text-sm text-slate-600 bg-blue-50 p-4 rounded-lg border border-blue-100">
                                    <p className="mb-2"><strong>Validación de Sesgo:</strong> Compruebe si la pendiente es cercana a 1.0 y el offset cercano a 0.0 para asegurar robustez.</p>
                                    <p><strong>Ratio Desempeño:</strong> {results.model.sec > 0 ? `RPD ≈ ${(results.model.secv / results.model.sec).toFixed(2)}` : 'N/A'}</p>
                                </div>
                            </div>
                         </div>
                    </div>
                )}

                {activeTab === 'residuals' && (
                     <div className="animate-fade-in bg-white rounded-xl border border-slate-200 shadow-card overflow-hidden">
                        <div className="max-h-[500px] overflow-y-auto custom-scrollbar">
                            <table className="w-full text-sm text-left">
                                <thead className="text-xs text-slate-500 uppercase bg-slate-50 sticky top-0 z-10 shadow-sm border-b border-slate-200">
                                    <tr>
                                        <th className="px-6 py-4 font-bold">ID Muestra</th>
                                        <th className="px-6 py-4 text-right font-bold">Valor Real</th>
                                        <th className="px-6 py-4 text-right font-bold">Valor Predicho</th>
                                        <th className="px-6 py-4 text-right font-bold">Error Absoluto</th>
                                        <th className="px-6 py-4 text-right font-bold">% Error Relativo</th>
                                    </tr>
                                </thead>
                                <tbody className="divide-y divide-slate-100">
                                    {residuals.map((r, idx) => {
                                        const relError = (Math.abs(r.residual) / Math.abs(r.actual)) * 100;
                                        const isHighError = Math.abs(r.residual) > results.model.sec * 2;
                                        return (
                                            <tr key={r.id} className={`hover:bg-slate-50 transition-colors ${idx % 2 === 0 ? 'bg-white' : 'bg-slate-50/50'}`}>
                                                <td className="px-6 py-3 font-medium text-slate-700">{r.id}</td>
                                                <td className="px-6 py-3 text-right font-mono text-slate-600">{r.actual.toFixed(4)}</td>
                                                <td className="px-6 py-3 text-right font-mono text-slate-600">{r.predicted.toFixed(4)}</td>
                                                <td className={`px-6 py-3 text-right font-mono font-medium ${isHighError ? 'text-red-600' : 'text-slate-600'}`}>
                                                    {r.residual > 0 ? '+' : ''}{r.residual.toFixed(4)}
                                                </td>
                                                <td className="px-6 py-3 text-right font-mono text-slate-500">
                                                    {relError.toFixed(2)}%
                                                </td>
                                            </tr>
                                        );
                                    })}
                                </tbody>
                            </table>
                        </div>
                     </div>
                )}

                {activeTab === 'full-data' && (
                    <div className="flex flex-col items-center justify-center py-16 gap-6 animate-fade-in bg-white rounded-xl border border-dashed border-slate-300">
                         <div className="text-center max-w-md">
                            <div className="bg-slate-50 h-20 w-20 rounded-full flex items-center justify-center mx-auto mb-6 text-slate-400 shadow-inner">
                                <svg className="w-10 h-10" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M4 16v1a3 3 0 003 3h10a3 3 0 003-3v-1m-4-4l-4 4m0 0l-4-4m4 4V4"></path></svg>
                            </div>
                            <h3 className="text-xl font-bold text-slate-800 mb-2">Exportación de Resultados</h3>
                            <p className="text-slate-500 mb-8 leading-relaxed">Descargue los resultados completos en CSV para reportes externos o el archivo de configuración JSON para reproducir este modelo más tarde.</p>
                         </div>
                         <div className="flex gap-4">
                            <Button onClick={handleDownloadData} size="lg" className="shadow-lg shadow-brand-500/20">
                                Descargar CSV
                            </Button>
                            <Button variant="secondary" onClick={handleExportConfig} size="lg">
                                Exportar Modelo (JSON)
                            </Button>
                         </div>
                    </div>
                )}
            </div>
        </Card>
    );
};

export default ResultsViewer;

