);

const PcaAnalyzer: React.FC<PcaAnalyzerProps> = ({ onRunPca, pcaResults, disabled }) => {
    const chartRef = useRef<HTMLCanvasElement>(null);
    const chartInstanceRef = useRef<any>(null);

    useEffect(() => {
        if (typeof Chart === 'undefined') return;

