    // Forzamos una ligera pendiente distinta de 1 para visibilidad
    const nir = (quimico * 0.98) + ruido + 0.45; 
    return { id: i, quimico: parseFloat(quimico.toFixed(2)), nir: parseFloat(nir.toFixed(2)) };
  });
};

